                  {isMounted
                    ? facility.reservations.toLocaleString("en-US")
                    : facility.reservations.toString()}
                </span>
                <span className="text-success text-[10px]">
                  {facility.trend}
                </span>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

interface StatCardProps {
  title: string;
  value: string;
  change: string;
  changeType: "up" | "down" | "neutral";
  subtitle?: string;
  icon: React.ElementType;
  iconBgStyle: React.CSSProperties;
  chart?: React.ReactNode;
}

function StatCard({
  title,
  value,
  change,
  changeType,
  subtitle,
  icon: Icon,
  iconBgStyle,
  chart,
}: StatCardProps) {
  return (
    <Card className="hover:shadow-elevated group shadow-card relative overflow-hidden border-0 transition-all duration-300">
      <CardContent className="p-5">
        <div className="flex items-start justify-between">
          <div className="flex-1">
            <p className="text-muted-foreground mb-1 text-sm font-medium">
              {title}
            </p>
            <div className="flex items-baseline gap-2">
              <h3 className="text-2xl font-bold tracking-tight">{value}</h3>
              <span
                className={`inline-flex items-center text-xs font-medium ${
                  changeType === "up"
                    ? "text-success"
                    : changeType === "down"
                      ? "text-destructive"
                      : "text-muted-foreground"
                } `}
              >
                {changeType === "up" ? (
                  <TrendingUp className="mr-0.5 size-3" />
                ) : changeType === "down" ? (
                  <TrendingDown className="mr-0.5 size-3" />
                ) : null}
                {change}
              </span>
            </div>
            {subtitle && (
              <p className="text-muted-foreground mt-1 text-xs">{subtitle}</p>
            )}
          </div>
          <div
            className="flex h-11 w-11 items-center justify-center rounded-xl transition-transform duration-300 group-hover:scale-110"
            style={iconBgStyle}
          >
            <Icon className="size-5 text-white" />
          </div>
        </div>
        {chart && <div className="mt-4 h-12">{chart}</div>}
      </CardContent>
    </Card>
  );
}

function MiniSparkline({ data, color }: { data: number[]; color: string }) {
  const sparkData = data.map((value, index) => ({ value, index }));
  return (
    <ResponsiveContainer width="100%" height="100%">
      <AreaChart data={sparkData}>
        <defs>
          <linearGradient id={`spark-${color}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={color} stopOpacity={0.3} />
            <stop offset="100%" stopColor={color} stopOpacity={0} />
          </linearGradient>
        </defs>
        <Area
          type="monotone"
          dataKey="value"
          stroke={color}
          strokeWidth={2}
          fill={`url(#spark-${color})`}
        />
      </AreaChart>
    </ResponsiveContainer>
  );
}

