function formatDate(d: string) {
  return new Date(d).toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  });
}

// ── Main page ────────────────────────────────────────────────────────

export default function EvaluationsPage() {
  const allEvals = useMemo(() => getAllEvaluations(), []);
  const [search, setSearch] = useState("");
  const [tab, setTab] = useState<"all" | "pending" | "passed" | "failed">(
    "all",
  );
  const [activeEval, setActiveEval] = useState<EvalEntry | null>(null);

  const filtered = useMemo(() => {
    let list = allEvals;
    if (tab !== "all") {
      list = list.filter((e) => e.evaluation.status === tab);
    }
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(
        (e) =>
          e.petName.toLowerCase().includes(q) ||
          e.clientName.toLowerCase().includes(q) ||
          e.evaluation.evaluatedBy?.toLowerCase().includes(q),
      );
    }
    return list.sort((a, b) => {
      // Pending first, then by date descending
      if (
        a.evaluation.status === "pending" &&
        b.evaluation.status !== "pending"
      )
        return -1;
      if (
        b.evaluation.status === "pending" &&
        a.evaluation.status !== "pending"
      )
        return 1;
      const da = a.evaluation.evaluatedAt
        ? new Date(a.evaluation.evaluatedAt).getTime()
        : 0;
      const db = b.evaluation.evaluatedAt
        ? new Date(b.evaluation.evaluatedAt).getTime()
        : 0;
      return db - da;
    });
  }, [allEvals, tab, search]);

  const counts = {
    all: allEvals.length,
    pending: allEvals.filter((e) => e.evaluation.status === "pending").length,
    passed: allEvals.filter((e) => e.evaluation.status === "passed").length,
    failed: allEvals.filter((e) => e.evaluation.status === "failed").length,
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="rounded-xl border border-slate-200 bg-slate-50 px-5 py-4">
        <div className="flex items-center gap-3">
          <div className="flex size-11 items-center justify-center rounded-xl bg-slate-800">
            <ClipboardCheck className="size-5 text-white" />
          </div>
          <div>
            <h2 className="text-lg font-bold tracking-tight text-slate-900">
              Evaluations
            </h2>
            <p className="text-sm text-slate-500">
              View and manage all pet evaluations — pending, completed, and
              upcoming
            </p>
          </div>
        </div>
      </div>

      {/* Stats */}
      <div className="grid gap-4 md:grid-cols-4">
        {(
          [
            {
              key: "all",
              label: "Total",
              count: counts.all,
              icon: ClipboardCheck,
              bg: "bg-slate-100",
              ic: "text-slate-600",
            },
            {
              key: "pending",
              label: "Pending",
              count: counts.pending,
              icon: Clock,
              bg: "bg-blue-50",
              ic: "text-blue-600",
            },
            {
              key: "passed",
              label: "Passed",
              count: counts.passed,
              icon: CheckCircle2,
              bg: "bg-emerald-50",
              ic: "text-emerald-600",
            },
            {
              key: "failed",
              label: "Not Approved",
              count: counts.failed,
              icon: XCircle,
              bg: "bg-rose-50",
              ic: "text-rose-600",
            },
          ] as const
        ).map((stat) => (
          <Card
            key={stat.key}
            className="cursor-pointer transition-all hover:-translate-y-0.5 hover:shadow-md"
            onClick={() =>
              setTab(stat.key as "all" | "pending" | "passed" | "failed")
            }
          >
            <CardContent className="pt-5">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-muted-foreground text-[11px] font-semibold tracking-wider uppercase">
                    {stat.label}
                  </p>
                  <p className="mt-1 text-3xl font-bold tabular-nums">
                    {stat.count}
                  </p>
                </div>
                <div
                  className={`flex size-12 items-center justify-center rounded-2xl ${stat.bg}`}
                >
                  <stat.icon className={`size-5 ${stat.ic}`} />
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Filter tabs + search */}
      <div className="flex items-center gap-3">
        <div className="flex gap-1 rounded-lg bg-slate-100 p-1">
          {(
            [
              { key: "all", label: "All" },
              { key: "pending", label: "Pending" },
              { key: "passed", label: "Passed" },
              { key: "failed", label: "Failed" },
            ] as const
          ).map((t) => (
            <button
              key={t.key}
              type="button"
              onClick={() => setTab(t.key)}
              className={`rounded-md px-3 py-1.5 text-xs font-medium transition-colors ${
                tab === t.key
                  ? "bg-white shadow-sm"
                  : "text-muted-foreground hover:text-foreground"
              }`}
            >
              {t.label}
            </button>
          ))}
        </div>
        <div className="relative flex-1">
          <Search className="text-muted-foreground absolute top-1/2 left-3 size-4 -translate-y-1/2" />
          <Input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search by pet, client, or evaluator..."
            className="pl-10"
          />
        </div>
      </div>

      {/* Evaluation list */}
      <Card className="overflow-hidden">
        <CardContent className="p-0">
          {filtered.length === 0 ? (
            <div className="flex flex-col items-center py-12 text-center">
              <ClipboardCheck className="text-muted-foreground/30 size-10" />
              <p className="text-muted-foreground mt-3 text-sm">
                No evaluations found
              </p>
            </div>
          ) : (
            <div className="divide-y">
              {filtered.map((entry) => {
                const s =
                  STATUS_MAP[
                    entry.evaluation.status as keyof typeof STATUS_MAP
                  ] ?? STATUS_MAP.pending;
                const Icon = s.icon;
                const isExpired =
                  entry.evaluation.isExpired &&
                  entry.evaluation.status === "passed";

                return (
                  <div
                    key={entry.evaluation.id}
                    className="group flex items-center justify-between px-5 py-3.5 transition-colors hover:bg-slate-50/50"
                  >
                    <div className="flex items-center gap-3">
                      <div className="relative">
                        {entry.petImage ? (
                          <img
                            src={entry.petImage}
                            alt={entry.petName}
                            className="size-11 rounded-xl object-cover"
                          />
                        ) : (
                          <div
                            className={`flex size-11 items-center justify-center rounded-xl ${s.bgColor}`}
                          >
                            <Icon className={`size-5 ${s.iconColor}`} />
                          </div>
                        )}
                        <div
                          className={`absolute -right-1 -bottom-1 flex size-5 items-center justify-center rounded-full ring-2 ring-white ${s.bgColor}`}
                        >
                          <Icon className={`size-3 ${s.iconColor}`} />
                        </div>
                      </div>
                      <div>
                        <div className="flex items-center gap-2">
                          <p className="text-sm font-semibold">
                            {entry.petName}
                          </p>
                          <Badge className={`text-[10px] ${s.color}`}>
                            {isExpired ? "Expired" : s.label}
                          </Badge>
                          <span className="text-muted-foreground text-xs">
                            {entry.petType} · {entry.petBreed}
                          </span>
                        </div>
                        <div className="text-muted-foreground mt-0.5 flex items-center gap-3 text-xs">
                          <span className="flex items-center gap-1">
                            <User className="size-3" />
                            {entry.clientName}
                          </span>
                          {entry.evaluation.evaluatedAt && (
                            <span className="flex items-center gap-1">
                              <Calendar className="size-3" />
                              {formatDate(entry.evaluation.evaluatedAt)}
                            </span>
                          )}
                          {entry.evaluation.evaluatedBy && (
                            <span className="flex items-center gap-1">
                              Evaluator: {entry.evaluation.evaluatedBy}
                            </span>
                          )}
                        </div>
                        {entry.bundledWith && (
                          <p className="mt-1 text-xs font-medium text-amber-700">
                            Bundled with {entry.bundledWith}
                            {entry.bundledDate &&
                              ` — check-in ${formatDate(entry.bundledDate)}`}
                          </p>
                        )}
                        {entry.evaluation.notes && (
                          <p className="text-muted-foreground mt-1 line-clamp-1 max-w-md text-xs">
                            {entry.evaluation.notes}
                          </p>
                        )}
                      </div>
                    </div>

                    <div className="flex items-center gap-2 opacity-0 transition-opacity group-hover:opacity-100">
                      {entry.evaluation.status === "pending" && (
                        <Button
                          size="sm"
                          className="gap-1.5"
                          onClick={() => setActiveEval(entry)}
                        >
                          <ClipboardCheck className="size-3.5" />
                          Evaluate
                        </Button>
                      )}
                      {(entry.evaluation.status === "passed" ||
                        entry.evaluation.status === "failed") && (
                        <>
                          <Button
                            size="sm"
                            variant="outline"
                            className="gap-1.5"
                            onClick={() => setActiveEval(entry)}
                          >
                            <ClipboardCheck className="size-3.5" />
                            View / Edit
                          </Button>
                        </>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Evaluation form modal */}
      {activeEval && (
        <StaffEvaluationFormModal
          open={!!activeEval}
          onOpenChange={(open) => !open && setActiveEval(null)}
          evaluation={activeEval.evaluation}
          petName={activeEval.petName}
          ownerName={activeEval.clientName}
          evaluatorName={activeEval.evaluation.evaluatedBy}
        />
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { PageAuditTrail } from "@/components/shared/PageAuditTrail";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { CreateFormModal } from "@/components/forms/CreateFormModal";
import {
  getFormsByFacility,
  duplicateForm,
  archiveForm,
  deleteForm,
  type Form,
  type FormType,
} from "@/data/forms";
import { triggerFormEvent } from "@/lib/form-automation-events";
import {
  Plus,
  Lock,
  Pencil,
  Copy,
  ExternalLink,
  Share2,
  Code,
  PenLine,
  Archive,
  Trash2,
  MoreVertical,
  Shield,
} from "lucide-react";
import { toast } from "sonner";

const FORM_CATEGORIES: { value: FormType; label: string }[] = [
  { value: "intake", label: "Intake Forms" },
  { value: "pet", label: "Pet Profile Forms" },
  { value: "owner", label: "Customer Profile Forms" },
  { value: "service", label: "Service Forms" },
  { value: "internal", label: "Internal Forms" },
];

const FACILITY_ID = 11;

export default function IntakeFormsPage() {
  const [category, setCategory] = useState<FormType>("intake");
  const [createModalOpen, setCreateModalOpen] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const router = useRouter();
  const allForms = getFormsByFacility(FACILITY_ID);
  const formsInCategory = allForms.filter((f) => f.type === category);

  const _refresh = refreshKey; // force re-render on state change

  return (
    <div className="flex-1 space-y-4 p-4 pt-6">
      <div className="flex items-center justify-between space-y-2">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Intake Forms</h2>
          <p className="text-muted-foreground">
            View and manage forms by category. Create and edit in Form Builder.
          </p>
        </div>
        <div className="flex gap-2">
          <Button onClick={() => setCreateModalOpen(true)}>
            <Plus className="mr-2 size-4" />
            Create New
          </Button>
          <Button variant="outline" asChild>
            <Link href="/facility/dashboard/forms/templates">
              From template
            </Link>
          </Button>
          <Button variant="outline" asChild>
            <Link href="/facility/dashboard/forms/audit">
              <Shield className="mr-2 size-4" />
              Audit Trail
            </Link>
          </Button>
        </div>
        <CreateFormModal
          open={createModalOpen}
          onOpenChange={setCreateModalOpen}
          facilityId={FACILITY_ID}
          defaultCategory={category}
        />
      </div>

      <Tabs value={category} onValueChange={(v) => setCategory(v as FormType)}>
        <div className="flex flex-wrap items-center gap-2">
          <TabsList className="flex h-auto flex-wrap gap-1">
            {FORM_CATEGORIES.map((cat) => (
              <TabsTrigger key={cat.value} value={cat.value}>
                {cat.value === "internal" && (
                  <Lock className="text-muted-foreground mr-1.5 size-3.5" />
                )}
                {cat.label}
              </TabsTrigger>
            ))}
          </TabsList>
          <Button variant="outline" size="sm" asChild className="shrink-0">
            <Link
              href="/facility/dashboard/forms/builder?new=1"
              className="gap-2"
            >
              <PenLine className="size-4" />
              Form Builder
            </Link>
          </Button>
        </div>
        <TabsContent value={category} className="mt-4">
          {formsInCategory.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12 text-center">
                <p className="text-muted-foreground mb-4">
                  No{" "}
                  {FORM_CATEGORIES.find(
                    (c) => c.value === category,
                  )?.label.toLowerCase()}{" "}
                  yet.
                </p>
                <Button onClick={() => setCreateModalOpen(true)}>
                  <Plus className="mr-2 size-4" />
                  Create form
                </Button>
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
              {formsInCategory.map((form) => (
                <FormCard
                  key={form.id}
                  form={form}
                  facilityId={FACILITY_ID}
                  router={router}
                  onRefresh={() => setRefreshKey((k) => k + 1)}
                />
              ))}
            </div>
          )}
        </TabsContent>
      </Tabs>
    </div>
  );
}

function statusBadge(status?: string) {
  switch (status) {
    case "published":
      return (
        <Badge className="border-0 bg-green-100 text-xs text-green-800 hover:bg-green-100">
          Published
        </Badge>
      );
    case "archived":
      return (
        <Badge variant="outline" className="text-muted-foreground text-xs">
          Archived
        </Badge>
      );
    default:
      return (
        <Badge variant="secondary" className="text-xs">
          Draft
        </Badge>
      );
  }
}

function FormCard({
  form,
  facilityId,
  router,
  onRefresh,
}: {
  form: Form;
  facilityId: number;
  router: ReturnType<typeof useRouter>;
  onRefresh: () => void;
}) {
  const sharePath = `/forms/${form.slug}`;
  const [embedOpen, setEmbedOpen] = useState(false);

  const copyLink = () => {
    const url =
      typeof window !== "undefined"
        ? `${window.location.origin}${sharePath}`
        : sharePath;
    navigator.clipboard.writeText(url);
    triggerFormEvent("form_link_sent", {
      facilityId: form.facilityId,
      formId: form.id,
      formName: form.name,
      sentVia: "copy",
    });
    toast.success("Link copied to clipboard");
  };

  const embedSnippet =
    typeof window !== "undefined"
      ? `<iframe src="${window.location.origin}${sharePath}" width="100%" height="600" frameborder="0" title="${form.name}"></iframe>`
      : `<iframe src="https://yoursite.com${sharePath}" width="100%" height="600" frameborder="0" title="${form.name}"></iframe>`;

  const copyEmbed = () => {
    navigator.clipboard.writeText(embedSnippet);
    toast.success("Embed code copied to clipboard");
  };

  const handleArchive = () => {
    archiveForm(form.id);
    toast.success("Form archived");
    onRefresh();
  };

  const handleDelete = () => {
    if (!confirm(`Delete "${form.name}"? This cannot be undone.`)) return;
    deleteForm(form.id);
    toast.success("Form deleted");
    onRefresh();
  };

  return (
    <>
      <Card className={form.status === "archived" ? "opacity-60" : ""}>
        <CardHeader className="flex flex-row items-start justify-between space-y-0 pb-2">
          <div className="min-w-0 flex-1 space-y-1">
            <CardTitle className="text-base font-medium">{form.name}</CardTitle>
            <div className="flex flex-wrap items-center gap-1.5">
              {statusBadge(form.status)}
              {form.internal && (
                <Badge variant="secondary" className="text-xs">
                  <Lock className="mr-0.5 h-2.5 w-2.5" />
                  Staff only
                </Badge>
              )}
              {form.audience === "both" && (
                <Badge variant="secondary" className="text-xs">
                  Both
                </Badge>
              )}
            </div>
          </div>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="ghost" size="icon" className="size-8 shrink-0">
                <MoreVertical className="size-4" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuItem
                onClick={() =>
                  router.push(`/facility/dashboard/forms/builder?id=${form.id}`)
                }
              >
                <Pencil className="mr-2 size-3.5" />
                Edit
              </DropdownMenuItem>
              <DropdownMenuItem
                onClick={() => {
                  const copy = duplicateForm(form.id, facilityId);
                  if (copy)
                    router.push(
                      `/facility/dashboard/forms/builder?id=${copy.id}`,
                    );
                }}
              >
                <Copy className="mr-2 size-3.5" />
                Duplicate
              </DropdownMenuItem>
              {form.status !== "archived" && (
                <DropdownMenuItem onClick={handleArchive}>
                  <Archive className="mr-2 size-3.5" />
                  Archive
                </DropdownMenuItem>
              )}
              <DropdownMenuItem
                onClick={handleDelete}
                className="text-destructive focus:text-destructive"
              >
                <Trash2 className="mr-2 size-3.5" />
                Delete
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </CardHeader>
        <CardContent className="space-y-3">
          <p className="text-muted-foreground text-xs">
            {form.questions.length} question
            {form.questions.length !== 1 ? "s" : ""}
            {form.serviceType && ` · ${form.serviceType}`}
            {form.appliesTo?.petTypes?.length
              ? ` · ${form.appliesTo.petTypes.join(", ")}`
              : ""}
          </p>
          <div className="flex flex-wrap gap-2">
            <Button
              size="sm"
              variant="outline"
              onClick={() =>
                router.push(`/facility/dashboard/forms/builder?id=${form.id}`)
              }
            >
              <Pencil className="mr-1 size-3.5" />
              Edit
            </Button>
            {!form.internal && (
              <>
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button size="sm" variant="ghost">
                      <Share2 className="mr-1 size-3.5" />
                      Share
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="start">
                    <DropdownMenuItem onClick={copyLink}>
                      <Copy className="mr-2 size-3.5" />
                      Copy link
                    </DropdownMenuItem>
                    <DropdownMenuItem onClick={() => setEmbedOpen(true)}>
                      <Code className="mr-2 size-3.5" />
                      Embed code
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
                <Button size="sm" variant="ghost" asChild>
                  <a href={sharePath} target="_blank" rel="noopener noreferrer">
                    <ExternalLink className="mr-1 size-3.5" />
                    Open link
                  </a>
                </Button>
              </>
            )}
          </div>
        </CardContent>
      </Card>

      {/* Permissions link — managed in Roles & Permissions */}
      <div className="bg-muted/50 flex items-center gap-2 rounded-lg border border-dashed p-3 text-sm">
        <Shield className="text-muted-foreground size-4" />
        <span className="text-muted-foreground">
          Manage form permissions in{" "}
          <Link
            href="/facility/dashboard/settings?section=roles-permissions"
            className="text-primary hover:underline"
          >
            Settings → Roles &amp; Permissions
          </Link>
        </span>
      </div>

      <PageAuditTrail area="forms" />

      <Dialog open={embedOpen} onOpenChange={setEmbedOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>Embed form</DialogTitle>
          </DialogHeader>
          <p className="text-muted-foreground text-sm">
            Paste this code on your website to embed the form.
          </p>
          <pre className="bg-muted max-h-32 overflow-x-auto rounded-sm p-3 text-xs">
            {embedSnippet}
          </pre>
          <Button onClick={copyEmbed} variant="outline" size="sm">
            <Copy className="mr-2 size-3.5" />
            Copy embed code
          </Button>
        </DialogContent>
      </Dialog>
    </>
  );
}

