${itemsHtml}
<div class="row sub"><span>Subtotal</span><span>$${subtotal.toFixed(2)}</span></div>
${discountTotal > 0 ? `<div class="row sub"><span>Discount</span><span>-$${discountTotal.toFixed(2)}</span></div>` : ""}
