                    return stay ? (
                      <div className="text-muted-foreground mt-1 text-xs">
                        {stay.service} • {pet?.name} • Checked in
                      </div>
                    ) : null;
                  })()}
                </div>
              )}

            {/* Show account info if charging to account */}
            {paymentForm.chargeType === "charge_to_account" && (
