                                      <CreditCard className="size-4" />
                                      <span>Credit Card</span>
                                    </div>
                                  </SelectItem>
                                  <SelectItem value="debit">
                                    <div className="flex items-center gap-2">
                                      <CreditCard className="size-4" />
                                      <span>Debit Card</span>
                                    </div>
                                  </SelectItem>
                                </>
