                              if (newPayments.length > 0) {
                                const totalSoFar = newPayments
                                  .slice(0, -1)
                                  .reduce((sum, p) => sum + p.amount, 0);
                                newPayments[newPayments.length - 1].amount =
                                  grandTotal - totalSoFar;
                              }
                              setPaymentForm({
                                ...paymentForm,
                                payments: newPayments,
                              });
                            }}
                          >
                            <X className="size-4" />
                          </Button>
                        )}
                      </div>

                      {/* Pay with iPhone option for credit/debit */}
