                                checked={payment.useYipyyPay || false}
                                onCheckedChange={(checked) => {
                                  const newPayments = [...paymentForm.payments];
                                  newPayments[index] = {
                                    ...newPayments[index],
                                    useYipyyPay: checked,
                                    useCloverTerminal: checked
                                      ? false
                                      : newPayments[index].useCloverTerminal,
                                  };
                                  if (checked) {
                                    const devices =
                                      getYipyyPayDevicesByFacility(facilityId);
                                    if (devices.length > 0) {
                                      newPayments[index].yipyyPayDeviceId =
                                        devices[0].deviceId;
                                    }
                                  } else {
                                    newPayments[index].yipyyPayDeviceId =
                                      undefined;
                                  }
                                  setPaymentForm({
                                    ...paymentForm,
                                    payments: newPayments,
                                  });
                                }}
                              />
                            </div>
                            {payment.useYipyyPay && (
                              <div className="grid gap-2">
                                <Label className="text-xs">
                                  Select iPhone Device
                                </Label>
                                <Select
                                  value={payment.yipyyPayDeviceId || ""}
                                  onValueChange={(value) => {
                                    const newPayments = [
                                      ...paymentForm.payments,
                                    ];
                                    newPayments[index].yipyyPayDeviceId = value;
                                    setPaymentForm({
                                      ...paymentForm,
                                      payments: newPayments,
                                    });
                                  }}
                                >
                                  <SelectTrigger>
                                    <SelectValue placeholder="Select device" />
                                  </SelectTrigger>
                                  <SelectContent>
                                    {getYipyyPayDevicesByFacility(
                                      facilityId,
                                    ).map((device) => (
                                      <SelectItem
                                        key={device.id}
                                        value={device.deviceId}
                                      >
                                        <div className="flex items-center gap-2">
                                          <Smartphone className="size-4" />
                                          <span>{device.deviceName}</span>
                                          {device.isAuthorized ? (
                                            <Badge
                                              variant="default"
                                              className="ml-2"
                                            >
                                              Ready
                                            </Badge>
                                          ) : (
                                            <Badge
                                              variant="secondary"
                                              className="ml-2"
                                            >
                                              Pending
                                            </Badge>
                                          )}
                                        </div>
                                      </SelectItem>
                                    ))}
                                  </SelectContent>
                                </Select>
                              </div>
                            )}
                          </div>
                        )}

                      {/* Clover Terminal option for credit/debit */}
                      {(payment.method === "credit" ||
                        payment.method === "debit") &&
                        !payment.useYipyyPay &&
                        inPersonMethods?.cloverTerminal && (
                          <div className="bg-muted/50 space-y-2 rounded-lg border p-3">
                            <div className="flex items-center justify-between">
                              <Label className="text-xs">
                                Use Clover Terminal
                              </Label>
                              <Switch
                                checked={payment.useCloverTerminal || false}
                                onCheckedChange={(checked) => {
                                  const newPayments = [...paymentForm.payments];
                                  newPayments[index] = {
                                    ...newPayments[index],
                                    useCloverTerminal: checked,
                                  };
                                  if (checked) {
                                    const terminals =
                                      getCloverTerminalsByFacility(facilityId);
                                    if (terminals.length > 0) {
                                      newPayments[index].cloverTerminalId =
                                        terminals[0].terminalId;
                                    }
                                  } else {
                                    newPayments[index].cloverTerminalId =
                                      undefined;
                                  }
                                  setPaymentForm({
                                    ...paymentForm,
                                    payments: newPayments,
                                  });
                                }}
                              />
                            </div>
