              <div className="space-y-6">
                <Label className="text-base font-semibold">Brand Styling</Label>

                {/* Title + Color */}
                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label>Report Title</Label>
                    <Input
                      value={brand.reportTitle}
                      readOnly={!isEditing}
                      onChange={(e) =>
