// ── Helpers ──────────────────────────────────────────────────────────────────

function fmtDate(d: Date) {
  return d.toLocaleDateString("en-US", {
    weekday: "short",
    month: "short",
    day: "numeric",
  });
}

function fmtTime(t: string) {
  const [h, m] = t.split(":").map(Number);
  const ampm = h >= 12 ? "PM" : "AM";
  return `${h % 12 || 12}:${String(m).padStart(2, "0")} ${ampm}`;
}

function fmtTimestamp(ts: string) {
  return new Date(ts).toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
  });
}

const shiftIcons: Record<string, typeof Sunrise> = {
  morning: Sunrise,
  afternoon: Sun,
  evening: Moon,
  night: Moon,
};

const categoryIcons: Record<string, typeof UtensilsCrossed> = {
  feeding: UtensilsCrossed,
  medication: Pill,
  activity: Sparkles,
  care: Sparkles,
  cleanup: Sparkles,
};

const FEEDBACK_OPTIONS = facilityConfig.careTaskFeedback.feeding;
const MED_FEEDBACK = facilityConfig.careTaskFeedback.medication;

// ── Page ─────────────────────────────────────────────────────────────────────

export default function TaskManagementPage() {
  const { role } = useFacilityRole();
  const isManager = role === "owner" || role === "manager";

  const searchParams = useSearchParams();
  const highlightTaskId = searchParams?.get("taskId") ?? null;
  const [highlightFade, setHighlightFade] = useState(!!highlightTaskId);

  // Auto-fade the highlight after 3 seconds
  useEffect(() => {
    if (highlightTaskId) {
      requestAnimationFrame(() => setHighlightFade(true));
      const timer = setTimeout(() => {
        requestAnimationFrame(() => setHighlightFade(false));
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [highlightTaskId]);

  const [dateOffset, setDateOffset] = useState(0);
  const [viewMode, setViewMode] = useState<"time" | "staff" | "pet">("time");
  const [statusFilter, setStatusFilter] = useState("all");
  const [staffFilter, setStaffFilter] = useState<"mine" | "all">(
    isManager ? "all" : "mine",
  );
  const [deptFilter, setDeptFilter] = useState("all");
  const [completeTask, setCompleteTask] = useState<FacilityTask | null>(null);
  const [feedback, setFeedback] = useState("");
  const [notes, setNotes] = useState("");

  // Mock: current logged-in staff (would come from auth in production)
  const currentStaffName = "Jessica M.";

  // Compute dates with tasks for calendar dots
  const datesWithTasks = useMemo(() => {
    const dates = new Set<string>();
    // Check a range of dates around today for tasks
    for (let i = -15; i <= 15; i++) {
      const d = new Date();
      d.setDate(d.getDate() + i);
      const ds = d.toISOString().slice(0, 10);
      const tasks = generateAllTasksForDate(ds);
      if (tasks.length > 0) dates.add(ds);
    }
    return dates;
  }, []);

  const today = useMemo(() => {
    const d = new Date();
    d.setDate(d.getDate() + dateOffset);
    return d;
  }, [dateOffset]);

  const dateStr = today.toISOString().slice(0, 10);

  // Generate tasks from booking care instructions for this date
  const dayTasks = useMemo(() => {
    let tasks = generateAllTasksForDate(dateStr);
    if (staffFilter === "mine") {
      tasks = tasks.filter((t) => t.assignedToName === currentStaffName);
    }
    if (statusFilter !== "all") {
      tasks = tasks.filter((t) => t.status === statusFilter);
    }
    if (deptFilter !== "all") {
      tasks = tasks.filter((t) => {
        if (!t.assignedToId) return false;
        const dept = getStaffDepartment(t.assignedToId);
        return dept?.id === deptFilter;
      });
    }
    return tasks;
  }, [dateStr, statusFilter, staffFilter, deptFilter, currentStaffName]);

  const totalTasks = dayTasks.length;
  const completedTasks = dayTasks.filter(
    (t) => t.status === "completed",
  ).length;
  const overdueTasks = dayTasks.filter((t) => t.isOverdue).length;
  const pendingTasks = totalTasks - completedTasks;

  // Group tasks
  const grouped = useMemo(() => {
    if (viewMode === "time") {
      const groups: Record<string, FacilityTask[]> = {
        morning: [],
        afternoon: [],
        evening: [],
      };
      for (const t of dayTasks)
        groups[t.shiftPeriod]?.push(t) ?? (groups[t.shiftPeriod] = [t]);
      return Object.entries(groups).filter(([, tasks]) => tasks.length > 0);
    }
    if (viewMode === "staff") {
      const groups = new Map<string, FacilityTask[]>();
      for (const t of dayTasks) {
        const key = t.assignedToName ?? "Unassigned";
        if (!groups.has(key)) groups.set(key, []);
        groups.get(key)!.push(t);
      }
      return Array.from(groups.entries());
    }
    // by pet
    const groups = new Map<string, FacilityTask[]>();
    for (const t of dayTasks) {
      if (!groups.has(t.petName)) groups.set(t.petName, []);
      groups.get(t.petName)!.push(t);
    }
    return Array.from(groups.entries());
  }, [dayTasks, viewMode]);

  const handleComplete = () => {
    if (!completeTask) return;
    toast.success(`Task completed: ${completeTask.name}`);
    setCompleteTask(null);
    setFeedback("");
    setNotes("");
  };

  return (
    <div className="space-y-5 p-5 md:p-7">
      {/* Header + Date Navigation */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Task Management</h1>
          <p className="text-muted-foreground mt-0.5 text-sm">
            {fmtDate(today)}
            {totalTasks > 0 && (
              <span className="ml-1.5">
                · {totalTasks} task{totalTasks !== 1 ? "s" : ""}
              </span>
            )}
          </p>
        </div>
        <div className="flex items-center gap-1.5">
          <Button
            variant="outline"
            size="icon"
            className="size-8 rounded-lg"
            onClick={() => setDateOffset((p) => p - 1)}
          >
            <ChevronLeft className="size-4" />
          </Button>
          <Button
            variant={dateOffset === 0 ? "default" : "outline"}
            size="sm"
            className="h-8 rounded-lg px-3 text-xs"
            onClick={() => setDateOffset(0)}
          >
            Today
          </Button>
          <Button
            variant="outline"
            size="icon"
            className="size-8 rounded-lg"
            onClick={() => setDateOffset((p) => p + 1)}
          >
            <ChevronRight className="size-4" />
          </Button>
          <Popover>
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                size="sm"
                className="ml-1 h-8 gap-1.5 rounded-lg text-xs"
              >
                <CalendarDays className="size-3.5" />
                Pick Date
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-auto p-0" align="end">
              <CalendarWidget
                mode="single"
                selected={today}
                onSelect={(date) => {
                  if (date) {
                    const now = new Date();
                    now.setHours(0, 0, 0, 0);
                    const sel = new Date(date);
                    sel.setHours(0, 0, 0, 0);
                    const diff = Math.round(
                      (sel.getTime() - now.getTime()) / (1000 * 60 * 60 * 24),
                    );
                    setDateOffset(diff);
                  }
                }}
              />
              {datesWithTasks.size > 0 && (
                <div className="border-t px-3 py-2">
                  <p className="text-muted-foreground text-[10px]">
                    <span className="bg-primary mr-1 inline-block size-1.5 rounded-full" />
                    {datesWithTasks.size} day
                    {datesWithTasks.size !== 1 ? "s" : ""} with active tasks
                  </p>
                </div>
              )}
            </PopoverContent>
          </Popover>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 gap-3 md:grid-cols-4">
        <ClickableStatCard
          title="Total Tasks"
          value={totalTasks}
          subtitle="All tasks"
          icon={ListChecks}
          onClick={() =>
            setStatusFilter(statusFilter === "all" ? "all" : "all")
          }
          isActive={statusFilter === "all"}
        />
        <ClickableStatCard
          title="Completed"
          value={completedTasks}
          subtitle="Done"
          icon={CheckCircleIcon}
          onClick={() =>
            setStatusFilter(statusFilter === "completed" ? "all" : "completed")
          }
          isActive={statusFilter === "completed"}
          valueClassName="text-emerald-600"
        />
        <ClickableStatCard
          title="Pending"
          value={pendingTasks}
          subtitle="Awaiting action"
          icon={Clock}
          onClick={() =>
            setStatusFilter(statusFilter === "pending" ? "all" : "pending")
          }
          isActive={statusFilter === "pending"}
          valueClassName="text-amber-600"
        />
        <ClickableStatCard
          title="Overdue"
          value={overdueTasks}
          subtitle="Needs attention"
          icon={AlertTriangle}
          onClick={() =>
            setStatusFilter(statusFilter === "overdue" ? "all" : "overdue")
          }
          isActive={statusFilter === "overdue"}
          valueClassName="text-red-600"
        />
      </div>

      {/* Overdue alert banner */}
      {overdueTasks > 0 && (
        <div className="flex items-start gap-3 rounded-xl border border-red-200 bg-red-50 p-4">
          <AlertTriangle className="mt-0.5 size-5 shrink-0 text-red-600" />
          <div className="flex-1">
            <p className="text-sm font-semibold text-red-900">
              {overdueTasks} overdue task{overdueTasks !== 1 ? "s" : ""} need
              attention
            </p>
            <div className="mt-1.5 space-y-1">
              {dayTasks
                .filter((t) => t.isOverdue)
                .map((t) => (
                  <p key={t.id} className="text-xs text-red-700">
                    {t.isCritical && "⚠ CRITICAL: "}
                    {t.name} — assigned to {t.assignedToName ?? "unassigned"},
                    was due at {fmtTime(t.scheduledTime)}
                  </p>
                ))}
            </div>
          </div>
        </div>
      )}

      {/* Controls */}
      <Card className="border-border/50">
        <CardContent className="flex flex-wrap items-center gap-4 px-4 py-3">
          {/* Staff filter */}
          <div className="flex items-center gap-2">
            <span className="text-muted-foreground text-[11px] font-medium">
              Show:
            </span>
            <div className="flex gap-1">
              {(
                [
                  { key: "mine", label: "My Tasks" },
                  { key: "all", label: "All Tasks" },
                ] as const
              ).map((opt) => (
                <button
                  key={opt.key}
                  onClick={() => setStaffFilter(opt.key)}
                  className={cn(
                    "rounded-lg border px-3 py-1.5 text-xs font-medium transition-all",
                    staffFilter === opt.key
                      ? "border-primary bg-primary/10 text-primary"
                      : "border-border text-muted-foreground hover:border-primary/30 hover:text-foreground",
                  )}
                >
                  {opt.label}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-border hidden h-5 w-px sm:block" />

          {/* View mode */}
          <div className="flex items-center gap-2">
            <span className="text-muted-foreground text-[11px] font-medium">
              View:
            </span>
            <div className="flex gap-1">
              {(["time", "staff", "pet"] as const).map((mode) => (
                <button
                  key={mode}
                  onClick={() => setViewMode(mode)}
                  className={cn(
                    "rounded-lg border px-3 py-1.5 text-xs font-medium capitalize transition-all",
                    viewMode === mode
                      ? "border-primary bg-primary/10 text-primary"
                      : "border-border text-muted-foreground hover:border-primary/30 hover:text-foreground",
                  )}
                >
                  By {mode}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-border hidden h-5 w-px sm:block" />

          {/* Status filter */}
          <div className="flex items-center gap-2">
            <span className="text-muted-foreground text-[11px] font-medium">
              Status:
            </span>
            <Select value={statusFilter} onValueChange={setStatusFilter}>
              <SelectTrigger className="h-8 w-[130px] rounded-lg text-xs">
                <SelectValue placeholder="All statuses" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Statuses</SelectItem>
                <SelectItem value="pending">
                  <span className="flex items-center gap-1.5">
                    <span className="size-2 rounded-full bg-amber-500" />
                    Pending
                  </span>
                </SelectItem>
                <SelectItem value="completed">
                  <span className="flex items-center gap-1.5">
                    <span className="size-2 rounded-full bg-emerald-500" />
                    Completed
                  </span>
                </SelectItem>
                <SelectItem value="overdue">
                  <span className="flex items-center gap-1.5">
                    <span className="size-2 rounded-full bg-red-500" />
                    Overdue
                  </span>
                </SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="bg-border hidden h-5 w-px sm:block" />

          {/* Department filter */}
          <div className="flex items-center gap-2">
            <span className="text-muted-foreground text-[11px] font-medium">
              Dept:
            </span>
            <Select value={deptFilter} onValueChange={setDeptFilter}>
              <SelectTrigger className="h-8 w-[160px] rounded-lg text-xs">
                <SelectValue placeholder="All departments" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Departments</SelectItem>
                {departments.map((dept) => {
                  const dotColor: Record<string, string> = {
                    blue: "bg-blue-500",
                    emerald: "bg-emerald-500",
                    purple: "bg-purple-500",
                    amber: "bg-amber-500",
                    orange: "bg-orange-500",
                    red: "bg-red-500",
                    teal: "bg-teal-500",
                    pink: "bg-pink-500",
                    slate: "bg-slate-500",
                  };
                  return (
                    <SelectItem key={dept.id} value={dept.id}>
                      <span className="flex items-center gap-1.5">
                        <span
                          className={cn(
                            "size-2 rounded-full",
                            dotColor[dept.color] ?? "bg-slate-500",
                          )}
                        />
                        {dept.name}
                      </span>
                    </SelectItem>
                  );
                })}
              </SelectContent>
            </Select>
          </div>
        </CardContent>
      </Card>

      {/* Task groups */}
      {grouped.length === 0 && (
        <Card className="border-dashed">
          <CardContent className="flex flex-col items-center py-16">
            <ListChecks className="text-muted-foreground/20 size-12" />
            <p className="text-muted-foreground mt-3 text-sm font-medium">
              No tasks for {fmtDate(today)}
            </p>
            <p className="text-muted-foreground/60 mt-1 text-xs">
              {dateOffset !== 0
                ? "Try navigating to today or another date with active bookings"
                : "Tasks are generated from bookings with care instructions"}
            </p>
            {dateOffset !== 0 && (
              <Button
                variant="outline"
                size="sm"
                className="mt-4 gap-1.5"
                onClick={() => setDateOffset(0)}
              >
                Go to Today
              </Button>
            )}
          </CardContent>
        </Card>
      )}
      <div className="space-y-5">
        {grouped.map(([groupKey, tasks]) => {
          const shiftDef = shifts.find((s) => s.id === groupKey);
          const ShiftIcon = shiftIcons[groupKey] ?? Clock;
          const groupDone = tasks.filter(
            (t) => t.status === "completed",
          ).length;

          // Staff on shift (for time view)
          const onShift =
            viewMode === "time" && shiftDef
              ? getStaffOnShift(dateStr, shiftDef.id)
              : [];

          return (
            <Card key={groupKey} className="border-border/50 overflow-hidden">
              <CardHeader className="bg-muted/20 px-5 pb-3">
                <div className="flex items-center justify-between">
                  <CardTitle className="flex items-center gap-2 text-xs font-semibold tracking-wider uppercase">
                    {viewMode === "time" ? (
                      <ShiftIcon className="size-3.5" />
                    ) : viewMode === "staff" ? (
                      <User className="size-3.5" />
                    ) : (
                      <Sparkles className="size-3.5" />
                    )}
                    {viewMode === "time" && shiftDef
                      ? `${shiftDef.name} (${fmtTime(shiftDef.startTime)} – ${fmtTime(shiftDef.endTime)})`
                      : groupKey}
                  </CardTitle>
                  <div className="flex items-center gap-3">
                    {onShift.length > 0 && (
                      <span className="text-muted-foreground text-[11px]">
                        {onShift.map((s) => s.staffName).join(", ")}
                      </span>
                    )}
                    <span className="text-muted-foreground text-[11px]">
                      {groupDone}/{tasks.length}
                    </span>
                    <div className="bg-muted h-1 w-14 overflow-hidden rounded-full">
                      <div
                        className={cn(
                          "h-full rounded-full transition-all",
                          groupDone === tasks.length
                            ? "bg-emerald-500"
                            : "bg-primary",
                        )}
                        style={{
                          width: `${tasks.length > 0 ? (groupDone / tasks.length) * 100 : 0}%`,
                        }}
                      />
                    </div>
                    {groupDone < tasks.length && (
                      <Button
                        variant="ghost"
                        size="sm"
                        className="h-6 text-[10px]"
                        onClick={() =>
                          toast.success(
                            `${tasks.length - groupDone} tasks marked complete`,
                          )
                        }
                      >
                        Complete All
                      </Button>
                    )}
                  </div>
                </div>
              </CardHeader>
              <CardContent className="divide-y px-5 pt-0">
                {tasks.map((task) => {
                  const CatIcon = categoryIcons[task.category] ?? Sparkles;
                  return (
                    <div
                      key={task.id}
                      id={`task-${task.id}`}
                      className={cn(
                        "flex items-start gap-3 py-3 first:pt-3",
                        task.status === "completed" && "opacity-50",
                        task.isOverdue &&
                          "rounded-lg border border-red-200 bg-red-50/50 px-3",
                        highlightTaskId === task.id &&
                          highlightFade &&
                          "border-primary bg-primary/5 animate-pulse rounded-lg border-2 px-3",
                      )}
                    >
                      {/* Status icon */}
                      {task.status === "completed" ? (
                        <CheckCircle2 className="mt-0.5 size-4 shrink-0 text-emerald-500" />
                      ) : task.isOverdue ? (
                        <AlertTriangle className="mt-0.5 size-4 shrink-0 text-red-500" />
                      ) : (
                        <Circle className="text-muted-foreground/30 mt-0.5 size-4 shrink-0" />
                      )}

                      {/* Task info */}
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center gap-2">
                          <CatIcon className="text-muted-foreground size-3.5" />
                          <span
                            className={cn(
                              "text-sm font-medium",
                              task.status === "completed" && "line-through",
                            )}
                          >
                            {task.name}
                          </span>
                          {task.isCritical && (
                            <Badge
                              variant="outline"
                              className="border-amber-200 bg-amber-50 px-1.5 py-0 text-[9px] text-amber-700"
                            >
                              Critical
                            </Badge>
                          )}
                          {task.isOverdue && (
                            <Badge
                              variant="outline"
                              className="border-red-200 bg-red-50 px-1.5 py-0 text-[9px] text-red-700"
                            >
                              Overdue
                            </Badge>
                          )}
                          {!task.isOverdue &&
                            task.status === "pending" &&
                            (() => {
                              const [h, m] = task.scheduledTime
                                .split(":")
                                .map(Number);
                              const taskMin = h * 60 + m;
                              const now = new Date();
                              const nowMin =
                                now.getHours() * 60 + now.getMinutes();
                              return (
                                taskMin - nowMin > 0 && taskMin - nowMin <= 15
                              );
                            })() && (
                              <Badge
                                variant="outline"
                                className="border-orange-200 bg-orange-50 px-1.5 py-0 text-[9px] text-orange-700"
                              >
                                Due soon
                              </Badge>
                            )}
                          {task.autoAssigned && (
                            <span className="text-muted-foreground/50 text-[9px]">
                              auto
                            </span>
                          )}
                        </div>
                        {task.description && (
                          <p className="text-muted-foreground mt-0.5 text-xs">
                            {task.description}
                          </p>
                        )}
                        <div className="text-muted-foreground mt-1 flex flex-wrap items-center gap-x-3 text-[11px]">
                          <span className="flex items-center gap-1">
                            <Clock className="size-3" />
                            {fmtTime(task.scheduledTime)}
                          </span>
                          <span>{task.petName}</span>
                          {task.assignedToName && (
                            <span className="flex items-center gap-1">
                              <span className="bg-primary/10 text-primary flex size-4 items-center justify-center rounded-full text-[7px] font-bold">
                                {task.assignedToName
                                  .split(" ")
                                  .map((n) => n[0])
                                  .join("")
                                  .slice(0, 2)}
                              </span>
                              {task.assignedToName}
                              {task.assignedToId &&
                                (() => {
                                  const dept = getStaffDepartment(
                                    task.assignedToId,
                                  );
                                  if (!dept) return null;
                                  const dotColor: Record<string, string> = {
                                    blue: "bg-blue-500",
                                    emerald: "bg-emerald-500",
                                    purple: "bg-purple-500",
                                    amber: "bg-amber-500",
                                    orange: "bg-orange-500",
                                  };
                                  return (
                                    <span
                                      className={cn(
                                        "rounded-full px-1.5 py-0 text-[8px] font-medium",
                                        `bg-${dept.color}-50 text-${dept.color}-700 border border-${dept.color}-200`,
                                      )}
                                    >
                                      {dept.name}
                                    </span>
                                  );
                                })()}
                            </span>
                          )}
                          {task.requiredSkill && (
                            <span className="italic">
                              requires: {task.requiredSkill.replace(/_/g, " ")}
                            </span>
                          )}
                        </div>

                        {/* Completion info */}
                        {task.status === "completed" && (
                          <div className="mt-1 flex items-center gap-2 text-[11px]">
                            <span className="rounded-full bg-emerald-50 px-2 py-0.5 font-medium text-emerald-700">
                              {task.feedback}
                            </span>
                            <span className="text-muted-foreground">
                              {task.completedByName} at{" "}
                              {task.completedAt
                                ? fmtTimestamp(task.completedAt)
                                : ""}
                            </span>
                          </div>
                        )}
                        {task.completionNotes && (
                          <p className="mt-1 rounded-sm bg-amber-50 px-2 py-1 text-[10px] text-amber-700">
                            ⚠ {task.completionNotes}
                          </p>
                        )}
                      </div>

                      {/* Actions */}
                      {(task.status === "pending" ||
                        task.status === "overdue") && (
                        <div className="flex shrink-0 items-center gap-1">
                          <Popover>
                            <PopoverTrigger asChild>
                              <Button
                                variant="ghost"
                                size="sm"
                                className="h-7 gap-1 text-[10px]"
                              >
                                <CalendarDays className="size-3" />
                                Reschedule
                              </Button>
                            </PopoverTrigger>
                            <PopoverContent className="w-auto p-0" align="end">
                              <CalendarWidget
                                mode="single"
                                onSelect={(date) => {
                                  if (date) {
                                    toast.success(
                                      `${task.name} rescheduled to ${date.toLocaleDateString("en-US", { month: "short", day: "numeric" })}`,
                                    );
                                  }
                                }}
                              />
                            </PopoverContent>
                          </Popover>
                          <Button
                            variant="outline"
                            size="sm"
                            className="h-7 text-[11px]"
                            onClick={() => setCompleteTask(task)}
                          >
                            Complete
                          </Button>
                        </div>
                      )}
                    </div>
                  );
                })}
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Completion modal */}
      <Dialog
        open={!!completeTask}
        onOpenChange={(open) => {
          if (!open) {
            setCompleteTask(null);
            setFeedback("");
            setNotes("");
          }
        }}
      >
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-base">
              <CheckCircle2 className="size-5 text-emerald-500" />
              Complete Task
            </DialogTitle>
          </DialogHeader>
          {completeTask && (
            <div className="space-y-4 py-2">
              <div className="bg-muted/20 rounded-lg border p-3">
                <p className="text-sm font-semibold">{completeTask.name}</p>
                {completeTask.description && (
                  <p className="text-muted-foreground mt-0.5 text-xs">
                    {completeTask.description}
                  </p>
                )}
                <p className="text-muted-foreground mt-1 text-xs">
                  {completeTask.petName} · {fmtTime(completeTask.scheduledTime)}
                </p>
              </div>

              <div>
                <p className="mb-2 text-sm font-medium">Result</p>
                <Select value={feedback} onValueChange={setFeedback}>
                  <SelectTrigger className="h-9 text-sm">
                    <SelectValue placeholder="Select feedback..." />
                  </SelectTrigger>
                  <SelectContent>
                    {(completeTask.category === "medication"
                      ? MED_FEEDBACK
                      : FEEDBACK_OPTIONS
                    ).map((opt) => (
                      <SelectItem key={opt.value} value={opt.value}>
                        {opt.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <p className="mb-2 text-sm font-medium">Notes (optional)</p>
                <Textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  placeholder="Any observations or handoff notes..."
                  className="min-h-[80px] text-sm"
                  rows={3}
                />
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setCompleteTask(null)}>
              Cancel
            </Button>
            <Button onClick={handleComplete} disabled={!feedback}>
              Mark as Complete
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import Link from "next/link";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  ClipboardList,
  ArrowRight,
  Building,
  Calendar,
  AlertTriangle,
  CheckCircle,
  XCircle,
} from "lucide-react";
import { toast } from "sonner";
import { getAllRequests, updateRequestStatus } from "@/data/module-requests";

export function ModuleRequestsInbox() {
  const [refreshKey, setRefreshKey] = useState(0);
  const requests = useMemo(() => getAllRequests(), [refreshKey]);
  const pending = requests.filter(
    (r) => r.status === "pending" || r.status === "in_progress",
  );

  const formatDate = (iso: string) =>
    new Date(iso).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    });

  const handleDecline = (id: string, name: string) => {
    if (!window.confirm(`Decline request for "${name}"?`)) return;
    updateRequestStatus(id, "declined", {
      declineReason: "Not feasible at this time",
    });
    setRefreshKey((k) => k + 1);
    toast.success(`Request for "${name}" declined`);
  };

  const handleStartBuild = (id: string, name: string) => {
    updateRequestStatus(id, "in_progress");
    setRefreshKey((k) => k + 1);
    toast.success(`Started building "${name}"`);
  };

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2 text-base">
            <ClipboardList className="size-5" />
            Module Requests
            {pending.length > 0 && (
              <Badge variant="secondary">{pending.length} pending</Badge>
            )}
          </CardTitle>
        </div>
      </CardHeader>
      <CardContent>
        {requests.length === 0 ? (
          <p className="text-muted-foreground py-6 text-center text-sm">
            No module requests yet
          </p>
        ) : (
          <div className="space-y-3">
            {requests.map((req) => (
              <div
                key={req.id}
                className="hover:bg-muted/30 rounded-lg border p-4 transition-colors"
              >
                <div className="flex items-start justify-between">
                  <div>
                    <div className="flex items-center gap-2">
                      <h4 className="text-sm font-semibold">
                        {req.serviceName}
                      </h4>
                      <Badge
                        variant={
                          req.status === "pending"
                            ? "secondary"
                            : req.status === "in_progress"
                              ? "default"
                              : req.status === "completed"
                                ? "outline"
                                : "destructive"
                        }
                        className="text-[10px] capitalize"
                      >
                        {req.status.replace("_", " ")}
                      </Badge>
                      {req.priority === "urgent" && (
                        <Badge
                          variant="outline"
                          className="border-red-200 bg-red-50 text-[10px] text-red-700"
                        >
                          <AlertTriangle className="mr-0.5 size-2.5" />
                          Urgent
                        </Badge>
                      )}
                    </div>
                    <div className="text-muted-foreground mt-1 flex items-center gap-3 text-xs">
                      <span className="flex items-center gap-1">
                        <Building className="size-3" />
                        {req.facilityName}
                      </span>
                      <span className="flex items-center gap-1">
                        <Calendar className="size-3" />
                        {formatDate(req.requestedAt)}
                      </span>
                      <span className="capitalize">
                        {req.suggestedCategory === "unsure"
                          ? "Category: Unsure"
                          : req.suggestedCategory.replace("_", " ")}
                      </span>
                    </div>
                    <p className="text-muted-foreground mt-2 line-clamp-2 text-xs">
                      {req.description}
                    </p>
                    {req.notes && (
                      <p className="mt-1 text-xs text-emerald-600 italic">
                        {req.notes}
                      </p>
                    )}
                  </div>
                </div>

                {(req.status === "pending" || req.status === "in_progress") && (
                  <div className="mt-3 flex items-center gap-2">
                    {req.status === "pending" && (
                      <Link href="/dashboard/services/custom-modules/create">
                        <Button size="sm" className="h-7 gap-1 text-xs">
                          <ArrowRight className="size-3" />
                          Build Module
                        </Button>
                      </Link>
                    )}
                    {req.status === "pending" && (
                      <Button
                        variant="outline"
                        size="sm"
                        className="h-7 gap-1 text-xs"
                        onClick={() =>
                          handleStartBuild(req.id, req.serviceName)
                        }
                      >
                        Mark In Progress
                      </Button>
                    )}
                    <Button
                      variant="outline"
                      size="sm"
                      className="text-destructive h-7 gap-1 text-xs"
                      onClick={() => handleDecline(req.id, req.serviceName)}
                    >
                      <XCircle className="size-3" />
                      Decline
                    </Button>
                  </div>
                )}

                {req.status === "completed" && (
                  <div className="mt-2 flex items-center gap-1.5 text-xs text-emerald-600">
                    <CheckCircle className="size-3" />
                    Built and published
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
}

"use client";

import { useState, useRef } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import { Collapsible, CollapsibleContent } from "@/components/ui/collapsible";
import { Dialog, DialogContent, DialogTitle } from "@/components/ui/dialog";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Backpack,
  CheckCircle2,
  Plus,
  Camera,
  Upload,
  AlertTriangle,
  PackageCheck,
  Expand,
  Trash2,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import type { BelongingEntry } from "@/types/booking";

interface BelongingsSectionProps {
  entries: BelongingEntry[];
  isCompleted?: boolean;
  required?: boolean;
}

function fmtTimestamp(ts: string) {
  return new Date(ts).toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

let _belId = 300;

export function BelongingsSection({
  entries,
  isCompleted,
  required,
}: BelongingsSectionProps) {
  const [items, setItems] = useState(entries);
  const [lightboxUrl, setLightboxUrl] = useState<string | null>(null);
  const [addOpen, setAddOpen] = useState(false);
  const [newItem, setNewItem] = useState({
    name: "",
    description: "",
    photoUrl: "",
  });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const totalItems = items.length;
  const returnedCount = items.filter((i) => i.returned).length;
  const unreturnedCount = totalItems - returnedCount;

  const handleReturn = (id: string, checked: boolean) => {
    setItems((prev) =>
      prev.map((e) =>
        e.id === id
          ? {
              ...e,
              returned: checked,
              returnedAt: checked ? new Date().toISOString() : undefined,
              returnedBy: checked ? "You" : undefined,
            }
          : e,
      ),
    );
    if (checked) toast.success("Item marked as returned");
  };

  const handleReturnAll = () => {
    const now = new Date().toISOString();
    setItems((prev) =>
      prev.map((e) =>
        e.returned
          ? e
          : { ...e, returned: true, returnedAt: now, returnedBy: "You" },
      ),
    );
    toast.success(`All ${unreturnedCount} items marked as returned`);
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      setNewItem((prev) => ({ ...prev, photoUrl: reader.result as string }));
    };
    reader.readAsDataURL(file);
  };

  const handleAdd = () => {
    if (!newItem.name.trim()) {
      toast.error("Item name is required");
      return;
    }
    _belId += 1;
    setItems((prev) => [
      ...prev,
      {
        id: `bel-new-${_belId}`,
        name: newItem.name,
        description: newItem.description || undefined,
        photoUrl: newItem.photoUrl || undefined,
        condition: "Good",
        checkedInAt: new Date().toISOString(),
        checkedInBy: "You",
        returned: false,
      },
    ]);
    setNewItem({ name: "", description: "", photoUrl: "" });
    setAddOpen(false);
    toast.success("Belonging added");
  };

  return (
    <>
      <Card className="overflow-hidden">
        <CardHeader className="bg-muted/30 pb-3">
          <div className="flex items-center justify-between">
            <CardTitle className="flex items-center gap-2 text-xs font-semibold tracking-wider uppercase">
              <Backpack className="size-3.5" />
              Belongings
              {required && (
                <Badge
                  variant="destructive"
                  className="text-[10px] normal-case"
                >
                  Required
                </Badge>
              )}
              {totalItems > 0 && (
                <span className="text-muted-foreground font-normal normal-case">
                  — {returnedCount} of {totalItems} returned
                </span>
              )}
            </CardTitle>
            <div className="flex items-center gap-2">
              {unreturnedCount > 1 && (
                <Button
                  variant="outline"
                  size="sm"
                  className="h-7 gap-1 text-[11px]"
                  onClick={handleReturnAll}
                >
                  <PackageCheck className="size-3" />
                  Return All
                </Button>
              )}
              <Button
                variant="outline"
                size="sm"
                className="h-7 gap-1 text-[11px]"
                onClick={() => setAddOpen(!addOpen)}
              >
                <Plus className="size-3" />
                Add Item
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent className="pt-0">
          {/* Unreturned items alert — on completed bookings */}
          {isCompleted && unreturnedCount > 0 && (
            <div className="mt-4 flex items-start gap-2.5 rounded-lg border border-amber-200 bg-amber-50 px-3.5 py-3">
              <AlertTriangle className="mt-0.5 size-4 shrink-0 text-amber-600" />
              <div>
                <p className="text-sm font-semibold text-amber-900">
                  {unreturnedCount} item{unreturnedCount !== 1 ? "s" : ""} not
                  returned
                </p>
                <p className="mt-0.5 text-xs text-amber-700">
                  Please verify all belongings have been returned to the client
                  before closing out this booking.
                </p>
              </div>
            </div>
          )}

          {/* Inline add form */}
          <Collapsible open={addOpen} onOpenChange={setAddOpen}>
            <CollapsibleContent>
              <div className="space-y-3 border-b py-4">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <Label className="text-[11px]">Item Name</Label>
                    <Input
                      value={newItem.name}
                      onChange={(e) =>
                        setNewItem((p) => ({ ...p, name: e.target.value }))
                      }
                      placeholder="e.g. Blue fleece blanket"
                      className="mt-1 h-8 text-xs"
                    />
                  </div>
                  <div>
                    <Label className="text-[11px]">Description</Label>
                    <Input
                      value={newItem.description}
                      onChange={(e) =>
                        setNewItem((p) => ({
                          ...p,
                          description: e.target.value,
                        }))
                      }
                      placeholder="Color, features..."
                      className="mt-1 h-8 text-xs"
                    />
                  </div>
                </div>

                {/* Photo upload */}
                <div>
                  <Label className="text-[11px]">
                    Photo (optional — documents condition at check-in)
                  </Label>
                  <div className="mt-1 flex items-center gap-2">
                    {newItem.photoUrl ? (
                      <div className="relative">
                        <img
                          src={newItem.photoUrl}
                          alt="Preview"
                          className="ring-border size-16 rounded-lg object-cover ring-1"
                        />
                        <button
                          className="bg-destructive absolute -top-1 -right-1 flex size-5 items-center justify-center rounded-full text-[10px] text-white"
                          onClick={() =>
                            setNewItem((p) => ({ ...p, photoUrl: "" }))
                          }
                        >
                          ×
                        </button>
                      </div>
                    ) : (
                      <div className="flex gap-2">
                        <Button
                          variant="outline"
                          size="sm"
                          className="h-8 gap-1.5 text-xs"
                          onClick={() => fileInputRef.current?.click()}
                        >
                          <Upload className="size-3.5" />
                          Upload
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          className="h-8 gap-1.5 text-xs"
                          onClick={() => {
                            // In production: use navigator.mediaDevices.getUserMedia
                            fileInputRef.current?.click();
                          }}
                        >
                          <Camera className="size-3.5" />
                          Camera
                        </Button>
                      </div>
                    )}
                    <input
                      ref={fileInputRef}
                      type="file"
                      accept="image/*"
                      capture="environment"
                      className="hidden"
                      onChange={handlePhotoUpload}
                    />
                  </div>
                </div>

                <div className="flex justify-end gap-2">
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-7 text-[11px]"
                    onClick={() => setAddOpen(false)}
                  >
                    Cancel
                  </Button>
                  <Button
                    size="sm"
                    className="h-7 text-[11px]"
                    onClick={handleAdd}
                  >
                    Add Item
                  </Button>
                </div>
              </div>
            </CollapsibleContent>
          </Collapsible>

          {/* Items list */}
          {items.length === 0 ? (
            <div className="py-6 text-center">
              <Backpack className="text-muted-foreground/20 mx-auto size-8" />
              <p className="text-muted-foreground mt-2 text-xs">
                No belongings checked in — click &quot;Add Item&quot; at
                check-in
              </p>
            </div>
          ) : (
            <div className="divide-y">
              {items.map((item) => (
                <div
                  key={item.id}
                  className={cn(
                    "flex items-start gap-3 py-4 transition-opacity first:pt-4",
                    item.returned && "opacity-50",
                  )}
                >
                  {/* Photo thumbnail with action menu */}
                  <Popover>
                    <PopoverTrigger asChild>
                      <button className="group relative shrink-0 overflow-hidden rounded-lg">
                        {item.photoUrl ? (
                          <>
                            <img
                              src={item.photoUrl}
                              alt={item.name}
                              className="size-16 object-cover transition-transform group-hover:scale-105"
                            />
                            <div className="absolute inset-0 flex items-center justify-center bg-black/0 transition-colors group-hover:bg-black/30">
                              <Camera className="size-4 text-white opacity-0 transition-opacity group-hover:opacity-100" />
                            </div>
                          </>
                        ) : (
                          <div className="bg-muted/50 group-hover:bg-muted flex size-16 items-center justify-center transition-colors">
                            <Camera className="text-muted-foreground/30 group-hover:text-muted-foreground/60 size-5 transition-colors" />
                          </div>
                        )}
                      </button>
                    </PopoverTrigger>
                    <PopoverContent
                      align="start"
                      className="w-auto p-1.5"
                      onOpenAutoFocus={(e) => e.preventDefault()}
                    >
                      <div className="flex flex-col gap-0.5">
                        {item.photoUrl && (
                          <button
                            className="hover:bg-muted flex items-center gap-2 rounded-md px-3 py-1.5 text-xs transition-colors"
                            onClick={() => setLightboxUrl(item.photoUrl!)}
                          >
                            <Expand className="size-3.5" />
                            View Full Photo
                          </button>
                        )}
                        <button
                          className="hover:bg-muted flex items-center gap-2 rounded-md px-3 py-1.5 text-xs transition-colors"
                          onClick={() => {
                            const input = document.createElement("input");
                            input.type = "file";
                            input.accept = "image/*";
                            input.capture = "environment";
                            input.onchange = (e) => {
                              const file = (e.target as HTMLInputElement)
                                .files?.[0];
                              if (!file) return;
                              const reader = new FileReader();
                              reader.onload = () => {
                                setItems((prev) =>
                                  prev.map((b) =>
                                    b.id === item.id
                                      ? {
                                          ...b,
                                          photoUrl: reader.result as string,
                                        }
                                      : b,
                                  ),
                                );
                                toast.success("Photo updated");
                              };
                              reader.readAsDataURL(file);
                            };
                            input.click();
                          }}
                        >
                          <Upload className="size-3.5" />
                          {item.photoUrl ? "Replace Photo" : "Upload Photo"}
                        </button>
                        {item.photoUrl && (
                          <button
                            className="hover:bg-destructive/10 text-destructive flex items-center gap-2 rounded-md px-3 py-1.5 text-xs transition-colors"
                            onClick={() => {
                              setItems((prev) =>
                                prev.map((b) =>
                                  b.id === item.id
                                    ? { ...b, photoUrl: undefined }
                                    : b,
                                ),
                              );
                              toast.success("Photo removed");
                            }}
                          >
                            <Trash2 className="size-3.5" />
                            Remove Photo
                          </button>
                        )}
                      </div>
                    </PopoverContent>
                  </Popover>

                  {/* Details */}
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center gap-2">
                      <span
                        className={cn(
                          "text-sm font-semibold",
                          item.returned && "line-through",
                        )}
                      >
                        {item.name}
                      </span>
                    </div>
                    {item.description && (
                      <p className="text-muted-foreground mt-0.5 text-xs">
                        {item.description}
                      </p>
                    )}
                    {item.checkedInBy && (
                      <p className="text-muted-foreground mt-0.5 text-[10px]">
                        Checked in by {item.checkedInBy}
                        {item.checkedInAt &&
                          ` · ${fmtTimestamp(item.checkedInAt)}`}
                      </p>
                    )}
                    {item.returned && item.returnedBy && (
                      <p className="mt-0.5 flex items-center gap-1 text-[10px] text-emerald-600">
                        <CheckCircle2 className="size-3" />
                        Returned by {item.returnedBy}
                        {item.returnedAt &&
                          ` · ${fmtTimestamp(item.returnedAt)}`}
                      </p>
                    )}
                  </div>

                  {/* Return checkbox */}
                  <div className="flex shrink-0 items-center gap-1.5 pt-1">
                    <Checkbox
                      id={`return-${item.id}`}
                      checked={item.returned}
                      onCheckedChange={(c) => handleReturn(item.id, c === true)}
                    />
                    <label
                      htmlFor={`return-${item.id}`}
                      className="text-muted-foreground cursor-pointer text-[11px]"
                    >
                      Returned
                    </label>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Lightbox */}
      <Dialog open={!!lightboxUrl} onOpenChange={() => setLightboxUrl(null)}>
        <DialogContent
          className="max-w-lg p-2"
          showCloseButton
          aria-describedby={undefined}
        >
          <DialogTitle className="sr-only">Belonging Photo</DialogTitle>
          {lightboxUrl && (
            <img
              src={lightboxUrl}
              alt="Belonging photo"
              className="w-full rounded-lg object-contain"
            />
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Send,
  CreditCard,
  Printer,
  Pencil,
  XCircle,
  RotateCcw,
  Copy,
  ChevronDown,
  Mail,
  Smartphone,
  Link2,
  FileText,
  Tag as TagIcon,
  LogOut,
} from "lucide-react";
import { toast } from "sonner";
import type { Booking } from "@/types/booking";
import { EvaluationCheckoutAlert } from "@/components/evaluations/EvaluationCheckoutAlert";

interface BookingActionBarProps {
  booking: Booking;
  onEdit?: () => void;
  onCancel?: () => void;
  onRefund?: () => void;
  onPayment?: () => void;
  onRecordEvaluation?: () => void;
}

export function BookingActionBar({
  booking,
  onEdit,
  onCancel,
  onRefund,
  onPayment,
  onRecordEvaluation,
}: BookingActionBarProps) {
  const isActive =
    booking.status === "confirmed" || booking.status === "pending";
  const isCompleted = booking.status === "completed";
  const isCancelled = booking.status === "cancelled";
  const isPaid = booking.paymentStatus === "paid";

  const isEvaluationBooking =
    booking.serviceType?.toLowerCase().includes("evaluation") ?? false;

  return (
    <div className="space-y-2">
      {isEvaluationBooking && booking.status === "confirmed" && (
        <EvaluationCheckoutAlert
          petName="this pet"
          hasEvaluationToday
          evaluationRecorded={false}
          onRecordResult={onRecordEvaluation}
        />
      )}
      <div className="flex flex-wrap items-center gap-2">
        {/* Send Invoice */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="outline" size="sm" className="gap-1.5">
              <Send className="size-3.5" />
              Send Invoice
              <ChevronDown className="size-3" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="start">
            <DropdownMenuItem
              onClick={() => toast.success("Invoice sent via email")}
            >
              <Mail className="size-4" />
              Send via Email
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => toast.success("Invoice sent via SMS")}
            >
              <Smartphone className="size-4" />
              Send via SMS
            </DropdownMenuItem>
            <DropdownMenuSeparator />
            <DropdownMenuItem
              onClick={() => {
                navigator.clipboard.writeText(
                  `${window.location.origin}/invoices/${booking.id}`,
                );
                toast.success("Invoice link copied");
              }}
            >
              <Link2 className="size-4" />
              Copy Invoice Link
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>

        {/* Accept Payment */}
        {!isPaid && !isCancelled && (
          <Button
            size="sm"
            className="gap-1.5"
            onClick={() => {
              if (onPayment) onPayment();
              else toast.info("Payment modal would open");
            }}
          >
            <CreditCard className="size-3.5" />
            Accept Payment
          </Button>
        )}

        {/* Print */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="outline" size="sm" className="gap-1.5">
              <Printer className="size-3.5" />
              Print
              <ChevronDown className="size-3" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="start">
            <DropdownMenuItem
              onClick={() => toast.info("Print invoice/receipt")}
            >
              <FileText className="size-4" />
              Invoice / Receipt
            </DropdownMenuItem>
            <DropdownMenuItem
              onClick={() => toast.info("Print boarding sheet")}
            >
              <FileText className="size-4" />
              Boarding Sheet
            </DropdownMenuItem>
            <DropdownMenuItem onClick={() => toast.info("Print kennel label")}>
              <TagIcon className="size-4" />
              Kennel Label
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>

        {/* Edit */}
        {isActive && (
          <Button
            variant="outline"
            size="sm"
            className="gap-1.5"
            onClick={() => {
              if (onEdit) onEdit();
              else toast.info("Edit modal would open");
            }}
          >
            <Pencil className="size-3.5" />
            Edit
          </Button>
        )}

        {/* Early Checkout */}
        {booking.status === "confirmed" && (
          <Button
            variant="outline"
            size="sm"
            className="gap-1.5"
            onClick={() => toast.info("Early checkout flow would start")}
          >
            <LogOut className="size-3.5" />
            Checkout
          </Button>
        )}

        {/* Cancel */}
        {isActive && (
          <Button
            variant="outline"
            size="sm"
            className="text-destructive gap-1.5"
            onClick={() => {
              if (onCancel) onCancel();
              else toast.info("Cancel modal would open");
            }}
          >
            <XCircle className="size-3.5" />
            Cancel
          </Button>
        )}

        {/* Refund */}
        {isPaid && !isCancelled && (
          <Button
            variant="outline"
            size="sm"
            className="gap-1.5"
            onClick={() => {
              if (onRefund) onRefund();
              else toast.info("Refund modal would open");
            }}
          >
            <RotateCcw className="size-3.5" />
            Refund
          </Button>
        )}

        {/* Duplicate */}
        <Button
          variant="ghost"
          size="sm"
          className="gap-1.5"
          onClick={() => toast.info("Duplicate booking created in draft")}
        >
          <Copy className="size-3.5" />
          Duplicate
        </Button>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Separator } from "@/components/ui/separator";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  RotateCcw,
  CreditCard,
  Banknote,
  Wallet,
  Check,
  AlertTriangle,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { facilities } from "@/data/facilities";
import { invoiceHeaderHtml } from "@/lib/invoice-header";

const defaultFacility = facilities.find((f) => f.id === 11);

interface RefundModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  invoiceTotal: number;
  amountPaid: number;
  items: { name: string; price: number }[];
  onConfirm: (refund: {
    amount: number;
    method: string;
    reason: string;
    type: "full" | "partial" | "by_item";
  }) => void;
}

type RefundType = "full" | "partial" | "by_item";
type RefundMethod = "original" | "store_credit" | "cash";

export function RefundModal({
  open,
  onOpenChange,
  invoiceTotal,
  amountPaid,
  items,
  onConfirm,
}: RefundModalProps) {
  const [step, setStep] = useState<"select" | "confirm">("select");
  const [refundType, setRefundType] = useState<RefundType>("full");
  const [partialAmount, setPartialAmount] = useState("");
  const [selectedItems, setSelectedItems] = useState<Set<number>>(new Set());
  const [method, setMethod] = useState<RefundMethod>("original");
  const [reason, setReason] = useState("");

  const refundAmount =
    refundType === "full"
      ? amountPaid
      : refundType === "partial"
        ? parseFloat(partialAmount) || 0
        : items
            .filter((_, i) => selectedItems.has(i))
            .reduce((s, item) => s + item.price, 0);

  const toggleItem = (idx: number) => {
    setSelectedItems((prev) => {
      const next = new Set(prev);
      if (next.has(idx)) next.delete(idx);
      else next.add(idx);
      return next;
    });
  };

  const handleConfirm = () => {
    if (step === "select") {
      setStep("confirm");
      return;
    }
    onConfirm({
      amount: refundAmount,
      method,
      reason,
      type: refundType,
    });

    // Auto-generate refund receipt in new window
    const w = window.open("", "_blank", "width=500,height=600");
    if (w) {
      const methodLabel =
        method === "original"
          ? "Original Payment Method"
          : method === "store_credit"
            ? "Store Credit"
            : "Cash";
      w.document.write(`<!DOCTYPE html><html><head><title>Refund Receipt</title>
<style>body{font-family:-apple-system,sans-serif;padding:40px;color:#111;max-width:420px;margin:0 auto}
h1{font-size:18px;margin:0;color:#dc2626}h2{font-size:12px;color:#666;margin:4px 0 20px}
.row{display:flex;justify-content:space-between;padding:5px 0;font-size:13px;border-bottom:1px solid #eee}
.row.total{border-top:2px solid #dc2626;border-bottom:none;font-weight:700;font-size:15px;padding-top:10px;color:#dc2626}
.row.sub{color:#666}.section{margin-top:14px;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px}
.footer{margin-top:24px;text-align:center;font-size:10px;color:#999}
.badge{background:#fef2f2;color:#dc2626;padding:6px 14px;border-radius:8px;text-align:center;margin-top:14px;font-weight:600;font-size:13px}
.note{background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:10px;margin-top:14px;font-size:11px;color:#64748b}
</style></head><body>
${invoiceHeaderHtml(defaultFacility)}
<h1>Refund Receipt</h1>
<h2>Processed ${new Date().toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" })}</h2>
<div class="section">Refund Details</div>
<div class="row"><span>Type</span><span>${refundType === "by_item" ? "By Item" : refundType === "partial" ? "Partial" : "Full"}</span></div>
<div class="row"><span>Method</span><span>${methodLabel}</span></div>
${reason ? `<div class="row"><span>Reason</span><span>${reason}</span></div>` : ""}
${
  refundType === "by_item"
    ? `<div class="section">Refunded Items</div>${items
        .filter((_, i) => selectedItems.has(i))
        .map(
          (item) =>
            `<div class="row"><span>${item.name}</span><span>$${item.price.toFixed(2)}</span></div>`,
        )
        .join("")}`
    : ""
}
<div class="row total"><span>Refund Amount</span><span>$${refundAmount.toFixed(2)}</span></div>
<div class="badge">REFUND PROCESSED</div>
<div class="note">The original invoice remains unchanged for audit purposes. This refund receipt is linked to the original transaction.</div>
<div class="footer">Refund processed by staff · ${new Date().toLocaleTimeString()}</div>
</body></html>`);
      w.document.close();
    }

    onOpenChange(false);
    setStep("select");
    setRefundType("full");
    setPartialAmount("");
    setSelectedItems(new Set());
    setReason("");
  };

  const handleBack = () => {
    if (step === "confirm") {
      setStep("select");
    } else {
      onOpenChange(false);
    }
  };

  const METHODS = [
    {
      value: "original" as const,
      label: "Original Method",
      desc: "Refund to the card/method used",
      icon: CreditCard,
    },
    {
      value: "store_credit" as const,
      label: "Store Credit",
      desc: "Add to client's credit balance",
      icon: Wallet,
    },
    {
      value: "cash" as const,
      label: "Cash",
      desc: "Hand cash refund to client",
      icon: Banknote,
    },
  ];

  return (
    <Dialog
      open={open}
      onOpenChange={(v) => {
        if (!v) {
          setStep("select");
          setRefundType("full");
        }
        onOpenChange(v);
      }}
    >
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <RotateCcw className="size-5" />
            Issue Refund
          </DialogTitle>
        </DialogHeader>

        {step === "select" ? (
          <div className="animate-in fade-in space-y-5 py-2 duration-200">
            {/* Refund type */}
            <div className="space-y-2">
              <p className="text-muted-foreground text-[11px] font-medium tracking-wider uppercase">
                Refund Type
              </p>
              <div className="space-y-1.5">
                <button
                  onClick={() => setRefundType("full")}
                  className={cn(
                    "flex w-full items-center gap-3 rounded-xl border p-4 text-left transition-all",
                    refundType === "full"
                      ? "border-primary bg-primary/5 ring-primary/20 ring-1"
                      : "hover:border-border hover:bg-muted/30",
                  )}
                >
                  <div
                    className={cn(
                      "flex size-10 shrink-0 items-center justify-center rounded-full",
                      refundType === "full"
                        ? "bg-primary/10 text-primary"
                        : "bg-muted text-muted-foreground",
                    )}
                  >
                    <RotateCcw className="size-5" />
                  </div>
                  <div>
                    <p className="text-sm font-semibold">Full Refund</p>
                    <p className="text-muted-foreground text-xs">
                      Refund entire payment of{" "}
                      <span className="font-[tabular-nums] font-medium">
                        ${amountPaid.toFixed(2)}
                      </span>
                    </p>
                  </div>
                </button>

                <button
                  onClick={() => setRefundType("partial")}
                  className={cn(
                    "flex w-full items-center gap-3 rounded-xl border p-4 text-left transition-all",
                    refundType === "partial"
                      ? "border-primary bg-primary/5 ring-primary/20 ring-1"
                      : "hover:border-border hover:bg-muted/30",
                  )}
                >
                  <div
                    className={cn(
                      "flex size-10 shrink-0 items-center justify-center rounded-full",
                      refundType === "partial"
                        ? "bg-primary/10 text-primary"
                        : "bg-muted text-muted-foreground",
                    )}
                  >
                    <Banknote className="size-5" />
                  </div>
                  <div className="flex-1">
                    <p className="text-sm font-semibold">Partial Refund</p>
                    <p className="text-muted-foreground text-xs">
                      Specify a custom refund amount
                    </p>
                  </div>
                </button>

                <button
                  onClick={() => setRefundType("by_item")}
                  className={cn(
                    "flex w-full items-center gap-3 rounded-xl border p-4 text-left transition-all",
                    refundType === "by_item"
                      ? "border-primary bg-primary/5 ring-primary/20 ring-1"
                      : "hover:border-border hover:bg-muted/30",
                  )}
                >
                  <div
                    className={cn(
                      "flex size-10 shrink-0 items-center justify-center rounded-full",
                      refundType === "by_item"
                        ? "bg-primary/10 text-primary"
                        : "bg-muted text-muted-foreground",
                    )}
                  >
                    <Check className="size-5" />
                  </div>
                  <div>
                    <p className="text-sm font-semibold">Refund by Item</p>
                    <p className="text-muted-foreground text-xs">
                      Select specific items to refund
                    </p>
                  </div>
                </button>
              </div>
            </div>

            {/* Partial amount input */}
            {refundType === "partial" && (
              <div className="animate-in fade-in duration-150">
                <p className="text-muted-foreground mb-1.5 text-xs">
                  Refund Amount (max ${amountPaid.toFixed(2)})
                </p>
                <Input
                  type="number"
                  value={partialAmount}
                  onChange={(e) => setPartialAmount(e.target.value)}
                  placeholder="0.00"
                  min={0}
                  max={amountPaid}
                  step={0.01}
                  className="h-12 text-center font-[tabular-nums] text-xl font-bold"
                  autoFocus
                />
              </div>
            )}

            {/* Item selection */}
            {refundType === "by_item" && (
              <div className="animate-in fade-in space-y-1.5 duration-150">
                <p className="text-muted-foreground text-xs">
                  Select items to refund
                </p>
                {items.map((item, idx) => (
                  <button
                    key={idx}
                    onClick={() => toggleItem(idx)}
                    className={cn(
                      "flex w-full items-center justify-between rounded-lg border px-4 py-3 text-left transition-all",
                      selectedItems.has(idx)
                        ? "border-primary bg-primary/5"
                        : "hover:bg-muted/30",
                    )}
                  >
                    <div className="flex items-center gap-3">
                      <div
                        className={cn(
                          "flex size-5 items-center justify-center rounded-full border-2 transition-all",
                          selectedItems.has(idx)
                            ? "border-primary bg-primary text-primary-foreground"
                            : "border-border",
                        )}
                      >
                        {selectedItems.has(idx) && <Check className="size-3" />}
                      </div>
                      <span className="text-sm">{item.name}</span>
                    </div>
                    <span className="font-[tabular-nums] text-sm font-medium">
                      ${item.price.toFixed(2)}
                    </span>
                  </button>
                ))}
              </div>
            )}

            {/* Refund method */}
            <div>
              <p className="text-muted-foreground mb-2 text-[11px] font-medium tracking-wider uppercase">
                Refund To
              </p>
              <div className="grid grid-cols-3 gap-2">
                {METHODS.map((m) => {
                  const Icon = m.icon;
                  return (
                    <button
                      key={m.value}
                      onClick={() => setMethod(m.value)}
                      className={cn(
                        "flex flex-col items-center gap-1.5 rounded-xl border p-3 transition-all",
                        method === m.value
                          ? "border-primary bg-primary/5 text-primary ring-primary/20 ring-1"
                          : "hover:bg-muted/30",
                      )}
                    >
                      <Icon className="size-5" />
                      <span className="text-[11px] font-medium">{m.label}</span>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Reason */}
            <div>
              <p className="text-muted-foreground mb-1.5 text-xs">
                Reason for refund
              </p>
              <Input
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                placeholder="e.g., Service not rendered, client complaint..."
                className="text-sm"
              />
            </div>
          </div>
        ) : (
          /* Confirmation step */
          <div className="animate-in fade-in slide-in-from-right-2 space-y-5 py-2 duration-200">
            {/* Warning */}
            <div className="flex items-start gap-3 rounded-xl border border-amber-200 bg-amber-50 p-4">
              <AlertTriangle className="mt-0.5 size-5 shrink-0 text-amber-600" />
              <div>
                <p className="text-sm font-semibold text-amber-800">
                  Confirm Refund
                </p>
                <p className="mt-0.5 text-xs text-amber-700">
                  This action cannot be undone. The refund will be processed
                  immediately. The original invoice stays unchanged for audit
                  purposes — a separate refund receipt will be generated.
                </p>
              </div>
            </div>

            {/* Summary */}
            <div className="bg-muted/20 rounded-xl border p-4">
              <div className="space-y-2.5 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Refund Type</span>
                  <span className="font-medium capitalize">
                    {refundType === "by_item"
                      ? "By Item"
                      : refundType === "partial"
                        ? "Partial"
                        : "Full"}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Refund Method</span>
                  <span className="font-medium">
                    {METHODS.find((m) => m.value === method)?.label}
                  </span>
                </div>
                {reason && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">Reason</span>
                    <span className="max-w-[200px] text-right text-sm italic">
                      {reason}
                    </span>
                  </div>
                )}
                <Separator />
                <div className="flex items-baseline justify-between">
                  <span className="font-medium">Refund Amount</span>
                  <span className="font-[tabular-nums] text-2xl font-bold text-red-600">
                    ${refundAmount.toFixed(2)}
                  </span>
                </div>
              </div>
            </div>
          </div>
        )}

        <DialogFooter className="gap-2">
          <Button variant="outline" onClick={handleBack}>
            {step === "confirm" ? "Go Back" : "Cancel"}
          </Button>
          <Button
            onClick={handleConfirm}
            disabled={refundAmount <= 0 || refundAmount > amountPaid}
            className={cn(
              "gap-1.5",
              step === "confirm" && "bg-red-600 text-white hover:bg-red-700",
            )}
          >
            <RotateCcw className="size-4" />
            {step === "confirm"
              ? `Confirm Refund $${refundAmount.toFixed(2)}`
              : `Continue — $${refundAmount.toFixed(2)}`}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import React, { useState, useMemo, useCallback } from "react";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogTitle } from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Plus,
  Check,
  Clock,
  Pill,
  Utensils,
  Scissors,
  ClipboardCheck,
  type LucideIcon,
} from "lucide-react";
import { Switch } from "@/components/ui/switch";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { ScrollArea } from "@/components/ui/scroll-area";
import { ServiceStep, ClientPetStep, DetailsStep, ConfirmStep } from "./steps";
import {
  STEPS,
  DAYCARE_SUB_STEPS,
  BOARDING_SUB_STEPS,
  EVALUATION_SUB_STEPS,
  CUSTOM_SERVICE_SUB_STEPS,
  getServiceAccent,
} from "./constants";
import { useCustomServices } from "@/hooks/use-custom-services";
import { isBuiltinService } from "@/lib/service-registry";
import {
  applyDynamicPricingRules,
  getStoredServiceAddOns,
} from "@/lib/pricing-rules";
import { cn } from "@/lib/utils";
import { useSettings } from "@/hooks/use-settings";
import { evaluationConfig } from "@/data/settings";
import { bookings as historicalBookings } from "@/data/bookings";

import type { Client } from "@/types/client";
import type { FeedingScheduleItem, MedicationItem } from "@/types/booking";
import type {
  NewBooking,
  Booking,
  DaycareDateTime,
  Task,
  ExtraService,
} from "@/types/booking";
import type { Pet, Evaluation } from "@/types/pet";

// Types

export interface NewBookingModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  clients: Client[];
  facilityId: number;
  facilityName: string;
  onCreateBooking: (booking: NewBooking) => void;
  preSelectedClientId?: number;
  preSelectedPetId?: number;
  preSelectedService?: string;
  booking?: Booking;
}

export function BookingModal({
  open,
  onOpenChange,
  clients,
  facilityId,
  onCreateBooking,
  preSelectedClientId,
  preSelectedPetId,
  preSelectedService,
  booking,
}: NewBookingModalProps) {
  const {
    daycare,
    boarding,
    grooming,
    training,
    bookingFlow,
    serviceNotifDefaults,
    tipConfig,
  } = useSettings();
  const configs = useMemo(
    () => ({ daycare, boarding, grooming, training }),
    [daycare, boarding, grooming, training],
  );
  const { getModuleBySlug } = useCustomServices();

  // Estimate mode detection
  const [isEstimateMode, setIsEstimateMode] = useState(false);
  const [estimateCreated, setEstimateCreated] = useState(false);
  const [estimateSent, setEstimateSent] = useState(false);

  // Guest estimate fields
  const [isGuestEstimate, setIsGuestEstimate] = useState(false);
  const [guestName, setGuestName] = useState("");
  const [guestEmail, setGuestEmail] = useState("");
  const [guestPhone, setGuestPhone] = useState("");
  const [guestPetName, setGuestPetName] = useState("");
  const [prevOpen, setPrevOpen] = useState(open);
  if (open !== prevOpen) {
    setPrevOpen(open);
    if (open) {
      const mode = localStorage.getItem("booking-modal-mode");
      setIsEstimateMode(mode === "estimate");
      localStorage.removeItem("booking-modal-mode");
      setEstimateCreated(false);
      setEstimateSent(false);
    } else {
      setIsEstimateMode(false);
      setEstimateCreated(false);
      setEstimateSent(false);
    }
  }

  // Staff options for assignment
  const staffOptions = [
    { value: "Mike Chen", label: "Mike Chen" },
    { value: "Emily Davis", label: "Emily Davis" },
    { value: "David Wilson", label: "David Wilson" },
    { value: "Lisa Rodriguez", label: "Lisa Rodriguez" },
    { value: "Tom Anderson", label: "Tom Anderson" },
    { value: "Manager One", label: "Manager One" },
    { value: "Admin User", label: "Admin User" },
  ];

  // Task assignments state
  const [taskAssignments, setTaskAssignments] = useState<
    Record<string, string>
  >({});

  // Step management
  const displayedSteps = STEPS.filter(
    (step) =>
      !(step.id === "client-pet" && preSelectedClientId && preSelectedPetId),
  );
  const [currentStep, setCurrentStep] = useState(
    preSelectedService
      ? displayedSteps.findIndex(
          (s) =>
            s.id ===
            (preSelectedClientId && preSelectedPetId
              ? "details"
              : "client-pet"),
        )
      : 0,
  );
  const [currentSubStep, setCurrentSubStep] = useState(0);
  const [highestStepReached, setHighestStepReached] = useState(
    preSelectedService
      ? displayedSteps.findIndex(
          (s) =>
            s.id ===
            (preSelectedClientId && preSelectedPetId
              ? "details"
              : "client-pet"),
        )
      : 0,
  );
  const [showCancelConfirm, setShowCancelConfirm] = useState(false);

  // Client selection state
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedClientId, setSelectedClientId] = useState<number | null>(
    preSelectedClientId ?? null,
  );
  const [selectedPetIds, setSelectedPetIds] = useState<number[]>(
    preSelectedPetId ? [preSelectedPetId] : [],
  );

  // Service selection state
  const [selectedService, setSelectedService] = useState<string>(
    preSelectedService ?? "",
  );
  const accent = getServiceAccent(selectedService);
  const handleServiceChange = (service: string) => {
    setSelectedService(service);
    if (service === "evaluation") {
      setServiceType("evaluation");
    } else if (service === "daycare") {
      setServiceType("full_day");
    } else {
      setServiceType("");
    }
    setCurrentSubStep(0);
    // Apply per-service notification defaults from settings
    const defaults = getNotifDefaults(service);
    setNotificationEmail(defaults.email);
    setNotificationSMS(defaults.sms);
  };

  // Service-specific state
  const [serviceType, setServiceType] = useState<string>(
    preSelectedService === "evaluation"
      ? evaluationConfig.duration
      : preSelectedService === "daycare"
        ? "full_day"
        : "",
  );
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [checkInTime, setCheckInTime] = useState("08:00");
  const [checkOutTime, setCheckOutTime] = useState("17:00");

  // Daycare specific - multi-date selection
  const [daycareSelectedDates, setDaycareSelectedDates] = useState<Date[]>([]);
  const [daycareDateTimes, setDaycareDateTimes] = useState<DaycareDateTime[]>(
    [],
  );

  // Boarding specific - date range selection
  const [boardingRangeStart, setBoardingRangeStart] = useState<Date | null>(
    null,
  );
  const [boardingRangeEnd, setBoardingRangeEnd] = useState<Date | null>(null);
  const [boardingDateTimes, setBoardingDateTimes] = useState<DaycareDateTime[]>(
    [],
  );

  // Boarding specific
  const [kennel, setKennel] = useState("");
  const [roomAssignments, setRoomAssignments] = useState<
    Array<{ petId: number; roomId: string }>
  >([]);
  const [feedingSchedule, setFeedingSchedule] = useState<FeedingScheduleItem[]>(
    [],
  );
  const [walkSchedule, setWalkSchedule] = useState("");
  const [medications, setMedications] = useState<MedicationItem[]>([]);
  const [feedingMedicationTab, setFeedingMedicationTab] = useState<
    "feeding" | "medication"
  >("feeding");
  const [extraServices, setExtraServices] = useState<ExtraService[]>([]);

  // Derive notification defaults for a given service from settings
  const getNotifDefaults = useCallback(
    (serviceId: string) => {
      const def = serviceNotifDefaults.find((d) => d.serviceId === serviceId);
      return { email: def?.email ?? true, sms: def?.sms ?? false };
    },
    [serviceNotifDefaults],
  );

  const initDefaults = getNotifDefaults(preSelectedService ?? "");
  const [notificationEmail, setNotificationEmail] = useState(
    initDefaults.email,
  );
  const [notificationSMS, setNotificationSMS] = useState(initDefaults.sms);
  const [tipAmount, setTipAmount] = useState(0);
  const [includesEvaluation, setIncludesEvaluation] = useState(false);

  // Get current sub-steps based on selected service (estimate mode skips feeding/medication)
  const currentSubSteps = useMemo(() => {
    if (selectedService === "daycare") {
      return isEstimateMode
        ? DAYCARE_SUB_STEPS.filter((s) => s.id <= 2)
        : DAYCARE_SUB_STEPS;
    }
    if (selectedService === "boarding") {
      return isEstimateMode
        ? BOARDING_SUB_STEPS.filter((s) => s.id <= 2)
        : BOARDING_SUB_STEPS;
    }
    if (selectedService === "evaluation") return EVALUATION_SUB_STEPS;
    if (selectedService) {
      return CUSTOM_SERVICE_SUB_STEPS;
    }
    return [];
  }, [selectedService, isEstimateMode]);

  // Check if current sub-step is complete
  const isSubStepComplete = useCallback(
    (stepIndex: number) => {
      if (selectedService === "daycare") {
        switch (stepIndex) {
          case 0:
            return daycareSelectedDates.length > 0;
          case 1:
            return roomAssignments.length === selectedPetIds.length;
          case 2:
            return true;
          case 3:
            return true;
          case 4:
            return true;
          default:
            return false;
        }
      }
      if (selectedService === "boarding") {
        switch (stepIndex) {
          case 0:
            return boardingRangeStart !== null && boardingRangeEnd !== null;
          case 1:
            return roomAssignments.length === selectedPetIds.length;
          case 2:
            return true;
          case 3:
            return true;
          case 4:
            return true;
          default:
            return false;
        }
      }
      if (selectedService === "evaluation") {
        switch (stepIndex) {
          case 0:
            return !!startDate && !!checkInTime && !!checkOutTime;
          case 1: // Add-ons — always complete (optional)
            return true;
          default:
            return false;
        }
      }
      // Grooming, training, custom services — schedule sub-step
      if (stepIndex === 0) {
        return !!startDate && !!checkInTime && !!checkOutTime;
      }
      return true;
    },
    [
      selectedService,
      daycareSelectedDates,
      roomAssignments,
      selectedPetIds,
      boardingRangeStart,
      boardingRangeEnd,
      startDate,
      checkInTime,
      checkOutTime,
    ],
  );

  // Filtered clients based on search
  const filteredClients = useMemo(() => {
    if (!searchQuery.trim()) return clients;
    const query = searchQuery.toLowerCase();
    return clients.filter(
      (client) =>
        client.name.toLowerCase().includes(query) ||
        client.email.toLowerCase().includes(query) ||
        client.phone?.includes(query),
    );
  }, [clients, searchQuery]);

  const selectedClient = useMemo(() => {
    return clients.find((c) => c.id === selectedClientId);
  }, [clients, selectedClientId]);

  const petHasValidEvaluation = useCallback((pet: Pet) => {
    const evals: Evaluation[] = pet.evaluations ?? [];
    return evals.some((e) => e.status === "passed" && e.isExpired !== true);
  }, []);

  const petHasExpiredEvaluation = useCallback((pet: Pet) => {
    const evals: Evaluation[] = pet.evaluations ?? [];
    return evals.some(
      (e) =>
        (e.status === "passed" && e.isExpired === true) ||
        e.status === "outdated",
    );
  }, []);

  const petHasFailedEvaluation = useCallback((pet: Pet) => {
    const evals: Evaluation[] = pet.evaluations ?? [];
    return evals.some((e) => e.status === "failed");
  }, []);

  const selectedPets = useMemo(() => {
    return (
      selectedClient?.pets.filter((p) => selectedPetIds.includes(p.id)) || []
    );
  }, [selectedClient, selectedPetIds]);

  const selectedClientBookings = useMemo(() => {
    if (selectedClientId == null) return [];
    return historicalBookings.filter(
      (existingBooking) => existingBooking.clientId === selectedClientId,
    );
  }, [selectedClientId]);

  const isNewCustomer = useMemo(() => {
    if (selectedClientId == null) return false;
    return selectedClientBookings.length === 0;
  }, [selectedClientId, selectedClientBookings]);

  const newPetIdsForCustomer = useMemo(() => {
    if (selectedPetIds.length === 0) return [];

    if (selectedClientBookings.length === 0) {
      return selectedPetIds;
    }

    return selectedPetIds.filter(
      (petId) =>
        !selectedClientBookings.some((existingBooking) =>
          Array.isArray(existingBooking.petId)
            ? existingBooking.petId.includes(petId)
            : existingBooking.petId === petId,
        ),
    );
  }, [selectedPetIds, selectedClientBookings]);

  const canAccessLockedServices = useMemo(() => {
    if (
      !bookingFlow.evaluationRequired ||
      !bookingFlow.hideServicesUntilEvaluationCompleted
    ) {
      return true;
    }
    if (selectedPets.length === 0) return false;
    return selectedPets.every((pet) => petHasValidEvaluation(pet));
  }, [bookingFlow, selectedPets, petHasValidEvaluation]);

  // Derive effective service: reset if hidden, force evaluation if locked
  const effectiveService = useMemo(() => {
    if (!selectedService || selectedService === "evaluation")
      return selectedService;
    if (bookingFlow.hiddenServices.includes(selectedService)) return "";
    if (
      bookingFlow.evaluationRequired &&
      bookingFlow.hideServicesUntilEvaluationCompleted &&
      !canAccessLockedServices
    ) {
      return "evaluation";
    }
    return selectedService;
  }, [bookingFlow, selectedService, canAccessLockedServices]);

  if (effectiveService !== selectedService) {
    setSelectedService(effectiveService);
  }

  const requiresEvaluationForService = useCallback(
    (serviceId: string) => {
      if (serviceId === "evaluation") return false;
      if (bookingFlow.evaluationRequired) return true;
      if (bookingFlow.servicesRequiringEvaluation.includes(serviceId))
        return true;
      const config =
        configs[serviceId as "daycare" | "boarding" | "grooming" | "training"];
      return config?.settings.evaluation.enabled ?? false;
    },
    [bookingFlow, configs],
  );

  const isEvaluationOptionalForService = useCallback(
    (serviceId: string) => {
      if (bookingFlow.evaluationRequired) return false;
      if (bookingFlow.servicesRequiringEvaluation.includes(serviceId))
        return false;
      const config =
        configs[serviceId as "daycare" | "boarding" | "grooming" | "training"];
      return config?.settings.evaluation.optional ?? false;
    },
    [bookingFlow, configs],
  );

  const storedAddOns = useMemo(
    () => getStoredServiceAddOns().filter((addOn) => addOn.isActive),
    [open],
  );

  const boardingNights = useMemo(() => {
    if (!boardingRangeStart || !boardingRangeEnd) return 0;
    return Math.max(
      1,
      Math.ceil(
        (boardingRangeEnd.getTime() - boardingRangeStart.getTime()) /
          (1000 * 60 * 60 * 24),
      ),
    );
  }, [boardingRangeStart, boardingRangeEnd]);

  // Calculate total price with dynamic pricing rules
  const calculatePrice = useMemo(() => {
    let basePrice = 0;

    if (selectedService === "daycare") {
      const pricePerDay =
        serviceType === "half_day" ? daycare.basePrice / 2 : daycare.basePrice;
      basePrice = pricePerDay * daycareSelectedDates.length;
    } else if (selectedService === "boarding") {
      basePrice = boarding.basePrice * Math.max(boardingNights, 1);
    } else if (selectedService === "grooming") {
      basePrice = grooming.basePrice * Math.max(selectedPetIds.length, 1);
    } else if (selectedService === "training") {
      basePrice = training.basePrice * Math.max(selectedPetIds.length, 1);
    } else if (selectedService === "evaluation") {
      basePrice = evaluationConfig.price;
    } else if (selectedService && !isBuiltinService(selectedService)) {
      const customModule = getModuleBySlug(selectedService);
      if (customModule) {
        basePrice = customModule.pricing.basePrice;
      }
    }

    const groomingDurationMinutes =
      selectedService === "grooming"
        ? (() => {
            const checkIn = new Date(`2000-01-01T${checkInTime}`);
            const checkOut = new Date(`2000-01-01T${checkOutTime}`);
            const diff = Math.round(
              (checkOut.getTime() - checkIn.getTime()) / (1000 * 60),
            );
            return Number.isFinite(diff) && diff > 0 ? diff : undefined;
          })()
        : undefined;

    const formatDateOnly = (date: Date): string => {
      const year = date.getFullYear();
      const month = `${date.getMonth() + 1}`.padStart(2, "0");
      const day = `${date.getDate()}`.padStart(2, "0");
      return `${year}-${month}-${day}`;
    };

    const daycareServiceDates =
      daycareDateTimes.length > 0
        ? daycareDateTimes.map((entry) => entry.date)
        : daycareSelectedDates.map((date) => formatDateOnly(date));

    const pricingComputation = applyDynamicPricingRules({
      serviceId: selectedService,
      basePrice,
      existingExtraServices: extraServices,
      selectedPetIds,
      isNewCustomer,
      newPetIds: newPetIdsForCustomer,
      customer: selectedClient
        ? {
            status: selectedClient.status,
            membershipPlan: selectedClient.membership?.plan,
            membershipStatus: selectedClient.membership?.status,
            storeCreditBalance: selectedClient.storeCredit?.balance,
            hasPackageCredits: (selectedClient.packages ?? []).some(
              (pkg) => pkg.remainingCredits > 0,
            ),
          }
        : undefined,
      pets: selectedPets,
      addOnsCatalog: storedAddOns,
      roomAssignments,
      boardingNights,
      sessionUnits:
        selectedService === "daycare"
          ? daycareSelectedDates.length
          : selectedService === "boarding"
            ? boardingNights
            : 1,
      serviceStartDate:
        selectedService === "daycare"
          ? daycareServiceDates[0]
          : selectedService === "boarding" && boardingRangeStart
            ? boardingRangeStart.toISOString().slice(0, 10)
            : startDate || undefined,
      serviceEndDate:
        selectedService === "daycare"
          ? daycareServiceDates[daycareServiceDates.length - 1]
          : selectedService === "boarding" && boardingRangeEnd
            ? boardingRangeEnd.toISOString().slice(0, 10)
            : endDate || startDate || undefined,
      serviceDates:
        selectedService === "daycare" && daycareServiceDates.length > 0
          ? daycareServiceDates
          : undefined,
      groomingDurationMinutes,
      appointmentTime: selectedService === "grooming" ? checkInTime : undefined,
      scheduledCheckInTime: checkInTime,
      scheduledCheckOutTime: checkOutTime,
      actualCheckInTime: checkInTime,
      actualCheckOutTime: checkOutTime,
    });

    return {
      basePrice,
      addOnsTotal: pricingComputation.addOnsTotal,
      adjustments: pricingComputation.adjustments,
      discount: pricingComputation.discountTotal,
      total: pricingComputation.total,
      effectiveExtraServices: pricingComputation.extraServices,
    };
  }, [
    selectedService,
    serviceType,
    boardingNights,
    boardingRangeStart,
    boardingRangeEnd,
    startDate,
    endDate,
    daycareSelectedDates,
    daycareDateTimes,
    selectedPetIds,
    isNewCustomer,
    newPetIdsForCustomer,
    selectedClient,
    selectedPets,
    extraServices,
    roomAssignments,
    checkInTime,
    checkOutTime,
    boarding.basePrice,
    daycare.basePrice,
    grooming.basePrice,
    training.basePrice,
    getModuleBySlug,
    storedAddOns,
  ]);

  // Check if service requires evaluation
  const serviceRequiresEvaluation = useMemo(() => {
    return requiresEvaluationForService(selectedService);
  }, [requiresEvaluationForService, selectedService]);

  // Check if evaluation is optional
  const isEvaluationOptional = useMemo(() => {
    return isEvaluationOptionalForService(selectedService);
  }, [isEvaluationOptionalForService, selectedService]);

  // Validation for each step
  const canProceed = useMemo(() => {
    const currentStepId = displayedSteps[currentStep]?.id;
    switch (currentStepId) {
      case "service":
        return selectedService !== "";
      case "client-pet":
        // Guest estimates skip client/pet requirement
        if (isEstimateMode && isGuestEstimate) return true;
        if (selectedClientId === null || selectedPetIds.length === 0)
          return false;
        // If any selected pet has an expired or failed evaluation, lock services (except booking a new evaluation)
        if (selectedService !== "evaluation") {
          const hasExpired = selectedPets.some((pet) =>
            petHasExpiredEvaluation(pet),
          );
          const hasFailed = selectedPets.some((pet) =>
            petHasFailedEvaluation(pet),
          );
          if (hasExpired || hasFailed) return false;
        }
        if (serviceRequiresEvaluation && !isEvaluationOptional) {
          const petsWithoutEvaluation = selectedPets.filter(
            (pet) => !petHasValidEvaluation(pet),
          );
          return petsWithoutEvaluation.length === 0;
        }
        return true;
      case "details": {
        if (
          selectedService !== "evaluation" &&
          (selectedService === "daycare" || selectedService === "boarding")
        ) {
          const hasExpired = selectedPets.some((pet) =>
            petHasExpiredEvaluation(pet),
          );
          const hasFailed = selectedPets.some((pet) =>
            petHasFailedEvaluation(pet),
          );
          if (hasExpired || hasFailed) return false;
        }
        return isSubStepComplete(currentSubStep);
      }
      case "confirm":
        if (selectedService !== "evaluation") {
          const hasExpired = selectedPets.some((pet) =>
            petHasExpiredEvaluation(pet),
          );
          const hasFailed = selectedPets.some((pet) =>
            petHasFailedEvaluation(pet),
          );
          if (hasExpired || hasFailed) return false;
        }
        return true;
      default:
        return false;
    }
  }, [
    currentStep,
    displayedSteps,
    currentSubStep,
    selectedClientId,
    selectedPetIds,
    selectedService,
    startDate,
    isSubStepComplete,
    serviceRequiresEvaluation,
    isEvaluationOptional,
    selectedPets,
    petHasExpiredEvaluation,
    petHasFailedEvaluation,
    petHasValidEvaluation,
  ]);

  const handleNext = () => {
    const currentStepId = displayedSteps[currentStep]?.id;
    // Handle sub-steps for daycare/boarding on details step
    if (
      currentStepId === "details" &&
      (selectedService === "daycare" ||
        selectedService === "boarding" ||
        selectedService === "evaluation")
    ) {
      if (currentSubStep < currentSubSteps.length - 1) {
        setCurrentSubStep(currentSubStep + 1);
        return;
      }
    }
    if (currentStep < displayedSteps.length - 1) {
      const nextStep = currentStep + 1;
      setCurrentStep(nextStep);
      setCurrentSubStep(0);
      setHighestStepReached((prev) => Math.max(prev, nextStep));
    }
  };

  const handlePrevious = () => {
    const currentStepId = displayedSteps[currentStep]?.id;
    const prevStepId = displayedSteps[currentStep - 1]?.id;
    // Handle sub-steps for daycare/boarding on details step
    if (
      currentStepId === "details" &&
      (selectedService === "daycare" ||
        selectedService === "boarding" ||
        selectedService === "evaluation")
    ) {
      if (currentSubStep > 0) {
        setCurrentSubStep(currentSubStep - 1);
        return;
      }
    }
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
      // Reset to last sub-step if going back to details with daycare/boarding
      if (
        prevStepId === "details" &&
        (selectedService === "daycare" ||
          selectedService === "boarding" ||
          selectedService === "evaluation")
      ) {
        setCurrentSubStep(currentSubSteps.length - 1);
      } else {
        setCurrentSubStep(0);
      }
    }
  };

  const handleComplete = () => {
    const clientId = selectedClientId;
    const petId: number | number[] =
      selectedPetIds.length === 1 ? selectedPetIds[0] : selectedPetIds;

    if (!clientId || !petId) return;

    // Check if service requires evaluation
    const requiresEvaluation = requiresEvaluationForService(selectedService);

    if (requiresEvaluation) {
      const petsNeedingEvaluation = selectedPets.filter((pet) => {
        const hasValidEval =
          pet.evaluations?.some(
            (e) => e.status === "passed" && e.isExpired !== true,
          ) ?? false;
        return !hasValidEval;
      });

      if (petsNeedingEvaluation.length > 0) {
        // Create evaluation bookings for pets that need them
        petsNeedingEvaluation.forEach((pet) => {
          const evaluationBooking: NewBooking = {
            clientId,
            petId: pet.id,
            facilityId,
            service: "evaluation",
            serviceType: evaluationConfig.duration,
            startDate: new Date().toISOString().split("T")[0], // Schedule for today or next available
            endDate: new Date().toISOString().split("T")[0],
            checkInTime: "09:00",
            checkOutTime:
              evaluationConfig.duration === "half-day" ? "12:00" : "17:00",
            status: "pending",
            basePrice: evaluationConfig.price,
            discount: 0,
            totalCost: evaluationConfig.price,
            paymentStatus: "pending",
            notificationEmail: true,
            notificationSMS: false,
          };
          onCreateBooking(evaluationBooking);
        });
        // Show confirmation message
        alert(
          `Evaluation bookings have been created for: ${petsNeedingEvaluation.map((p) => p.name).join(", ")}. The main booking will be created after evaluations are completed.`,
        );
        // Still create the main booking - evaluations can be completed later
      }
    }

    const booking: NewBooking = {
      clientId,
      petId,
      facilityId,
      service: selectedService,
      serviceType:
        selectedService === "evaluation" ? "evaluation" : serviceType,
      startDate:
        selectedService === "daycare" && daycareSelectedDates.length > 0
          ? daycareSelectedDates[0].toISOString().split("T")[0]
          : selectedService === "boarding" && boardingRangeStart
            ? boardingRangeStart.toISOString().split("T")[0]
            : startDate,
      endDate:
        selectedService === "evaluation"
          ? startDate
          : selectedService === "boarding" && boardingRangeEnd
            ? boardingRangeEnd.toISOString().split("T")[0]
            : endDate || startDate,
      checkInTime:
        selectedService === "boarding" && boardingDateTimes.length > 0
          ? boardingDateTimes[0].checkInTime
          : checkInTime,
      checkOutTime:
        selectedService === "boarding" && boardingDateTimes.length > 0
          ? boardingDateTimes[boardingDateTimes.length - 1].checkOutTime
          : checkOutTime,
      status: "pending",
      basePrice: calculatePrice.basePrice,
      discount: calculatePrice.discount,
      totalCost: calculatePrice.total,
      paymentStatus: "pending",
      daycareSelectedDates:
        daycareSelectedDates.length > 0
          ? daycareSelectedDates.map((d) => d.toISOString().split("T")[0])
          : undefined,
      daycareDateTimes:
        daycareDateTimes.length > 0 ? daycareDateTimes : undefined,

      kennel: kennel || undefined,
      feedingSchedule: feedingSchedule || undefined,
      walkSchedule: walkSchedule || undefined,
      medications: medications || undefined,
      extraServices:
        calculatePrice.effectiveExtraServices.length > 0
          ? calculatePrice.effectiveExtraServices
          : undefined,
      notificationEmail: notificationEmail,
      notificationSMS: notificationSMS,
      tipAmount: tipAmount > 0 ? tipAmount : undefined,
      includesEvaluation: includesEvaluation || undefined,
      evaluationStatus: includesEvaluation ? "pending" : undefined,
    };

    if (isEstimateMode) {
      // In estimate mode, show success state instead of creating a booking
      setEstimateCreated(true);
      return;
    }

    onCreateBooking(booking);
    resetForm();
    onOpenChange(false);
  };

  const resetForm = () => {
    setCurrentStep(0);
    setCurrentSubStep(0);
    setHighestStepReached(0);
    setSearchQuery("");
    setSelectedClientId(null);
    setSelectedPetIds([]);
    setDaycareSelectedDates([]);
    setDaycareDateTimes([]);
    setBoardingRangeStart(null);
    setBoardingRangeEnd(null);
    setBoardingDateTimes([]);

    setSelectedService("");
    setServiceType("");
    setStartDate("");
    setEndDate("");
    setCheckInTime("08:00");
    setCheckOutTime("17:00");

    setKennel("");
    setRoomAssignments([]);
    setFeedingSchedule([]);
    setWalkSchedule("");
    setMedications([]);
    setExtraServices([]);
    setNotificationEmail(true);
    setNotificationSMS(false);
    setTipAmount(0);
    setIncludesEvaluation(false);
  };

  const isViewMode = !!booking;

  const getTaskIcon = (type: string): LucideIcon => {
    switch (type) {
      case "feeding":
        return Utensils;
      case "medication":
        return Pill;
      case "service":
        return Scissors;
      case "walking":
        return Clock;
      default:
        return Clock;
    }
  };

  const tasks = useMemo((): Task[] => {
    if (!booking) return [];

    const taskList: Task[] = [];
    const now = new Date();
    const bookingStart = new Date(booking.startDate);
    const isFutureBooking = bookingStart > now;

    // Feeding tasks
    if (booking.feedingSchedule) {
      booking.feedingSchedule.forEach((feed) => {
        const petId = Array.isArray(booking.petId)
          ? booking.petId[0]
          : booking.petId;
        taskList.push({
          id: `feed-${feed.id}`,
          bookingId: booking.id,
          petId,
          type: "feeding",
          title: `Feed ${feed.occasions?.[0]?.label || "Feeding"}`,
          time: feed.occasions?.[0]?.time || "",
          details: feed.prepInstructions?.join(", ") || "",
          assignedStaff: taskAssignments[`feed-${feed.id}`] || undefined,
          completionStatus: "pending",
          assignable: isFutureBooking && !taskAssignments[`feed-${feed.id}`],
        });
      });
    }

    // Medication tasks
    if (booking.medications) {
      booking.medications.forEach((med) => {
        med.times.forEach((time: string) => {
          const petId = Array.isArray(booking.petId)
            ? booking.petId[0]
            : booking.petId;
          taskList.push({
            id: `med-${med.id}-${time}`,
            bookingId: booking.id,
            petId,
            type: "medication",
            title: `Give ${med.name}`,
            time,
            details: med.adminInstructions?.join(", ") || "",
            assignedStaff:
              taskAssignments[`med-${med.id}-${time}`] || undefined,
            completionStatus: "pending",
            assignable:
              isFutureBooking && !taskAssignments[`med-${med.id}-${time}`],
          });
        });
      });
    }

    // Extra services
    if (booking.extraServices) {
      booking.extraServices.forEach((service, index) => {
        // Handle both string[] (grooming) and ExtraService[] (daycare/boarding) types
        if (typeof service === "string") {
          // For string type (grooming), use the string as service name
          const petId = Array.isArray(booking.petId)
            ? booking.petId[0]
            : booking.petId;
          taskList.push({
            id: `service-${service}-${petId}-${index}`,
            bookingId: booking.id,
            petId: petId,
            type: "service",
            title: `Perform ${service}`,
            time: null,
            details: "Extra service",
            assignedStaff:
              taskAssignments[`service-${service}-${petId}-${index}`] ||
              undefined,
            completionStatus: "pending",
            assignable:
              isFutureBooking &&
              !taskAssignments[`service-${service}-${petId}-${index}`],
          });
        } else {
          // For ExtraService object type (daycare/boarding)
          taskList.push({
            id: `service-${service.serviceId}-${service.petId}`,
            bookingId: booking.id,
            petId: service.petId,
            type: "service",
            title: `Perform ${service.serviceId} service`,
            time: null,
            details: `Quantity: ${service.quantity}`,
            assignedStaff:
              taskAssignments[
                `service-${service.serviceId}-${service.petId}`
              ] || undefined,
            completionStatus: "pending",
            assignable:
              isFutureBooking &&
              !taskAssignments[`service-${service.serviceId}-${service.petId}`],
          });
        }
      });
    }

    // Walk schedule for boarding
    if (booking.service === "boarding" && booking.walkSchedule) {
      const petId = Array.isArray(booking.petId)
        ? booking.petId[0]
        : booking.petId;
      taskList.push({
        id: "walk-schedule",
        bookingId: booking.id,
        petId,
        type: "walking",
        title: "Walk Schedule",
        time: null,
        details: booking.walkSchedule,
        assignedStaff: taskAssignments["walk-schedule"] || undefined,
        completionStatus: "pending",
        assignable: isFutureBooking && !taskAssignments["walk-schedule"],
      });
    }

    return taskList;
  }, [booking, taskAssignments]);

  if (isViewMode && booking) {
    const client = clients.find((c) => c.id === booking.clientId);
    const pet = client?.pets.find(
      (p) =>
        p.id ===
        (Array.isArray(booking.petId) ? booking.petId[0] : booking.petId),
    );

    const latestEvaluation = (() => {
      const evals = pet?.evaluations ?? [];
      if (evals.length === 0) return null;
      return [...evals].sort((a, b) => {
        const da = a?.evaluatedAt ? new Date(a.evaluatedAt).getTime() : 0;
        const db = b?.evaluatedAt ? new Date(b.evaluatedAt).getTime() : 0;
        return db - da;
      })[0];
    })();

    const evalExpired =
      latestEvaluation?.isExpired === true ||
      latestEvaluation?.status === "outdated";
    const evalOutcome =
      latestEvaluation?.status === "passed"
        ? "PASS"
        : latestEvaluation?.status === "failed"
          ? "FAIL"
          : latestEvaluation?.status
            ? String(latestEvaluation.status).toUpperCase()
            : "MISSING";

    const requiresEvalForBooking =
      requiresEvaluationForService(booking.service) &&
      !isEvaluationOptionalForService(booking.service);

    const evalCompleted =
      latestEvaluation?.status === "passed" ||
      latestEvaluation?.status === "failed";

    return (
      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="flex h-[85vh] w-[90vw] min-w-4xl flex-col overflow-hidden p-0">
          <DialogTitle className="sr-only">Booking Details</DialogTitle>
          <div className="border-b p-6">
            <div className="flex items-center justify-between">
              <div>
                <h2 className="text-2xl font-bold">Booking #{booking.id}</h2>
                <p className="text-muted-foreground">
                  {client?.name} - {pet?.name} - {booking.service}
                </p>
              </div>
              <Badge variant="outline" className="capitalize">
                {booking.status}
              </Badge>
            </div>
          </div>

          <Tabs defaultValue="details" className="flex min-h-0 flex-1 flex-col">
            <TabsList className="mx-6 mt-4 grid w-full grid-cols-2">
              <TabsTrigger value="details">Details</TabsTrigger>
              <TabsTrigger value="tasks">Tasks ({tasks.length})</TabsTrigger>
            </TabsList>

            <TabsContent value="details" className="flex-1 overflow-y-auto p-6">
              <div className="space-y-6">
                {/* Basic Information */}
                <Card>
                  <CardHeader>
                    <CardTitle>Basic Information</CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="text-sm font-medium">Service</label>
                        <p className="capitalize">{booking.service}</p>
                      </div>
                      <div>
                        <label className="text-sm font-medium">
                          Service Type
                        </label>
                        <p>{booking.serviceType || "N/A"}</p>
                      </div>
                      <div>
                        <label className="text-sm font-medium">Status</label>
                        <Badge variant="outline" className="capitalize">
                          {booking.status}
                        </Badge>
                      </div>
                      <div>
                        <label className="text-sm font-medium">
                          Payment Status
                        </label>
                        <Badge variant="outline" className="capitalize">
                          {booking.paymentStatus}
                        </Badge>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                {/* Dates & Times */}
                <Card>
                  <CardHeader>
                    <CardTitle>Dates & Times</CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <div>
                        <label className="text-sm font-medium">
                          Start Date
                        </label>
                        <p>{booking.startDate}</p>
                      </div>
                      <div>
                        <label className="text-sm font-medium">End Date</label>
                        <p>{booking.endDate}</p>
                      </div>
                      <div>
                        <label className="text-sm font-medium">Check In</label>
                        <p>{booking.checkInTime || "N/A"}</p>
                      </div>
                      <div>
                        <label className="text-sm font-medium">Check Out</label>
                        <p>{booking.checkOutTime || "N/A"}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                {/* Pricing */}
                <Card>
                  <CardHeader>
                    <CardTitle>Pricing</CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div className="grid grid-cols-3 gap-4">
                      <div>
                        <label className="text-sm font-medium">
                          Base Price
                        </label>
                        <p>${booking.basePrice}</p>
                      </div>
                      <div>
                        <label className="text-sm font-medium">Discount</label>
                        <p>${booking.discount}</p>
                      </div>
                      <div>
                        <label className="text-sm font-medium">
                          Total Cost
                        </label>
                        <p className="font-semibold">${booking.totalCost}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                {/* Evaluation (staff) */}
                {(requiresEvalForBooking ||
                  booking.service === "evaluation") && (
                  <Card>
                    <CardHeader>
                      <CardTitle>Evaluation</CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-3">
                      {!latestEvaluation ? (
                        <div className="flex items-center justify-between">
                          <span className="text-muted-foreground text-sm">
                            No evaluation result
                          </span>
                          <Badge variant="destructive">Missing</Badge>
                        </div>
                      ) : (
                        <>
                          <div className="flex items-center justify-between">
                            <div className="text-muted-foreground text-sm">
                              Latest outcome
                            </div>
                            <div className="flex items-center gap-2">
                              <Badge
                                variant={
                                  evalOutcome === "PASS"
                                    ? "secondary"
                                    : evalOutcome === "FAIL"
                                      ? "destructive"
                                      : "outline"
                                }
                              >
                                {evalOutcome}
                              </Badge>
                              {(latestEvaluation.status === "passed" ||
                                latestEvaluation.status === "outdated") && (
                                <Badge
                                  variant={
                                    evalExpired ? "destructive" : "secondary"
                                  }
                                >
                                  {evalExpired ? "Expired" : "Valid"}
                                </Badge>
                              )}
                            </div>
                          </div>

                          {(latestEvaluation.evaluatedAt ||
                            latestEvaluation.evaluatedBy) && (
                            <div className="grid grid-cols-2 gap-4 text-sm">
                              <div>
                                <div className="text-muted-foreground">
                                  Evaluated at
                                </div>
                                <div>{latestEvaluation.evaluatedAt || "—"}</div>
                              </div>
                              <div>
                                <div className="text-muted-foreground">
                                  Evaluator
                                </div>
                                <div>{latestEvaluation.evaluatedBy || "—"}</div>
                              </div>
                            </div>
                          )}

                          {/* Staff-only notes / failure reason */}
                          {latestEvaluation.notes && (
                            <div className="text-sm">
                              <div className="text-muted-foreground">
                                Notes (staff)
                              </div>
                              <div>{latestEvaluation.notes}</div>
                            </div>
                          )}
                        </>
                      )}

                      {/* Staff reminders */}
                      {requiresEvalForBooking &&
                        booking.status === "completed" &&
                        !evalCompleted && (
                          <Alert variant="destructive">
                            <AlertTitle>Evaluation result missing</AlertTitle>
                            <AlertDescription>
                              Evaluation is required but has not been completed
                              before checkout.
                            </AlertDescription>
                          </Alert>
                        )}
                      {requiresEvalForBooking &&
                        (evalOutcome === "FAIL" ||
                          evalExpired ||
                          evalOutcome === "MISSING") && (
                          <Alert variant="destructive">
                            <AlertTitle>Services locked</AlertTitle>
                            <AlertDescription>
                              Customer must book a new evaluation to unlock
                              services.
                            </AlertDescription>
                          </Alert>
                        )}
                    </CardContent>
                  </Card>
                )}

                {/* Service-specific details */}
                {booking.service === "boarding" && (
                  <Card>
                    <CardHeader>
                      <CardTitle>Boarding Details</CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                      {booking.kennel && (
                        <div>
                          <label className="text-sm font-medium">Kennel</label>
                          <p>{booking.kennel}</p>
                        </div>
                      )}
                      {booking.walkSchedule && (
                        <div>
                          <label className="text-sm font-medium">
                            Walk Schedule
                          </label>
                          <p>{booking.walkSchedule}</p>
                        </div>
                      )}
                    </CardContent>
                  </Card>
                )}

                {booking.service === "daycare" &&
                  booking.daycareSelectedDates && (
                    <Card>
                      <CardHeader>
                        <CardTitle>Daycare Details</CardTitle>
                      </CardHeader>
                      <CardContent>
                        <div>
                          <label className="text-sm font-medium">
                            Selected Dates
                          </label>
                          <div className="mt-1 flex flex-wrap gap-2">
                            {booking.daycareSelectedDates.map((date) => (
                              <Badge key={date} variant="secondary">
                                {date}
                              </Badge>
                            ))}
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  )}

                {booking.specialRequests && (
                  <Card>
                    <CardHeader>
                      <CardTitle>Special Requests</CardTitle>
                    </CardHeader>
                    <CardContent>
                      <p>{booking.specialRequests}</p>
                    </CardContent>
                  </Card>
                )}
              </div>
            </TabsContent>

            <TabsContent value="tasks" className="flex-1 overflow-y-auto p-6">
              <div className="space-y-4">
                {tasks.length === 0 ? (
                  <Card>
                    <CardContent className="flex flex-col items-center justify-center py-16">
                      <Check className="text-muted-foreground/50 mb-4 h-16 w-16" />
                      <h3 className="mb-2 text-lg font-semibold">No Tasks</h3>
                      <p className="text-muted-foreground text-center">
                        This booking does not have any scheduled tasks.
                      </p>
                    </CardContent>
                  </Card>
                ) : (
                  <div className="space-y-3">
                    {tasks.map((task) => (
                      <Card key={task.id}>
                        <CardContent className="p-4">
                          <div className="flex items-start gap-3">
                            <div className="bg-muted rounded-lg p-2">
                              {React.createElement(getTaskIcon(task.type), {
                                className: "size-4",
                              })}
                            </div>
                            <div className="flex-1">
                              <div className="mb-2 flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                  <h4 className="font-medium">{task.title}</h4>
                                  <Badge
                                    variant="outline"
                                    className="text-xs capitalize"
                                  >
                                    {task.type}
                                  </Badge>
                                  <Badge
                                    variant={
                                      task.completionStatus === "completed"
                                        ? "default"
                                        : task.completionStatus ===
                                            "in_progress"
                                          ? "secondary"
                                          : "outline"
                                    }
                                    className="text-xs"
                                  >
                                    {task.completionStatus.replace("_", " ")}
                                  </Badge>
                                </div>
                                {task.assignedStaff && (
                                  <Badge variant="outline" className="text-xs">
                                    Assigned: {task.assignedStaff}
                                  </Badge>
                                )}
                              </div>
                              {task.time && (
                                <p className="text-muted-foreground mb-1 text-sm">
                                  Time: {task.time}
                                </p>
                              )}
                              <p className="mb-2 text-sm">{task.details}</p>
                              {task.assignable && (
                                <div className="flex items-center gap-2">
                                  <label className="text-sm font-medium">
                                    Assign to:
                                  </label>
                                  <Select
                                    value={task.assignedStaff || ""}
                                    onValueChange={(value) =>
                                      setTaskAssignments((prev) => ({
                                        ...prev,
                                        [task.id]: value,
                                      }))
                                    }
                                  >
                                    <SelectTrigger className="w-48">
                                      <SelectValue placeholder="Select staff" />
                                    </SelectTrigger>
                                    <SelectContent>
                                      {staffOptions.map((staff) => (
                                        <SelectItem
                                          key={staff.value}
                                          value={staff.value}
                                        >
                                          {staff.label}
                                        </SelectItem>
                                      ))}
                                    </SelectContent>
                                  </Select>
                                </div>
                              )}
                            </div>
                          </div>
                        </CardContent>
                      </Card>
                    ))}
                  </div>
                )}
              </div>
            </TabsContent>
          </Tabs>
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <Dialog
      open={open}
      onOpenChange={(nextOpen) => {
        // Prevent closing via overlay/escape if user has progress — show confirm instead
        if (!nextOpen && (currentStep > 0 || selectedService)) {
          setShowCancelConfirm(true);
        } else {
          onOpenChange(nextOpen);
        }
      }}
    >
      <DialogContent className="flex h-[90vh] w-[95vw] min-w-7xl flex-col overflow-hidden p-0 [&>button]:hidden">
        <DialogTitle className="sr-only">
          {isEstimateMode ? "New Estimate" : "New Booking"}
        </DialogTitle>
        <div className="flex min-h-0 flex-1">
          {/* Side Navigation Tabs */}
          <div className="bg-muted/30 flex w-80 flex-col border-r">
            {/* Title in Sidebar */}
            <div className="bg-background border-b p-4">
              <h2 className="flex items-center gap-2 text-lg font-semibold">
                <Plus className="size-5" />
                {(() => {
                  const preSelectedClient = clients.find(
                    (c) => c.id === preSelectedClientId,
                  );
                  const preSelectedPet = preSelectedClient?.pets.find(
                    (p) => p.id === preSelectedPetId,
                  );
                  if (preSelectedPet) {
                    return `Book ${preSelectedPet.name}`;
                  } else if (preSelectedClient) {
                    return `Book for ${preSelectedClient.name}`;
                  } else if (selectedService === "daycare") {
                    return daycare.clientFacingName;
                  } else if (selectedService === "boarding") {
                    return boarding.clientFacingName;
                  } else {
                    return isEstimateMode ? "New Estimate" : "New Booking";
                  }
                })()}
              </h2>
              <p className="text-muted-foreground mt-1 text-sm">
                {(() => {
                  const preSelectedClient = clients.find(
                    (c) => c.id === preSelectedClientId,
                  );
                  const preSelectedPet = preSelectedClient?.pets.find(
                    (p) => p.id === preSelectedPetId,
                  );
                  if (preSelectedPet) {
                    return `Create a new booking for ${preSelectedPet.name}`;
                  } else if (preSelectedClient) {
                    return `Create a new booking for ${preSelectedClient.name}`;
                  } else if (selectedService === "daycare") {
                    return daycare.slogan;
                  } else if (selectedService === "boarding") {
                    return boarding.slogan;
                  } else {
                    return "Create a new booking for your facility";
                  }
                })()}
              </p>
            </div>
            {/* #2 — Progress indicator */}
            <div className="border-b px-4 py-2.5">
              <div className="flex items-center justify-between">
                <span className="text-muted-foreground text-[10px] font-semibold tracking-wide uppercase">
                  Step {currentStep + 1} of {displayedSteps.length}
                </span>
                <span className="text-muted-foreground text-[10px]">
                  {Math.round(
                    ((currentStep + (canProceed ? 1 : 0)) /
                      displayedSteps.length) *
                      100,
                  )}
                  %
                </span>
              </div>
              <div className="bg-muted mt-1.5 h-1 w-full overflow-hidden rounded-full">
                <div
                  className={cn(
                    "h-full rounded-full transition-all duration-300",
                    selectedService ? accent.progressBar : "bg-primary",
                  )}
                  style={{
                    width: `${((currentStep + (canProceed ? 1 : 0)) / displayedSteps.length) * 100}%`,
                  }}
                />
              </div>
            </div>

            <ScrollArea className="flex-1">
              <div className="space-y-2 p-4">
                {displayedSteps.map((step, idx) => {
                  const isActive = currentStep === idx;
                  let isCompleted = currentStep > idx;
                  if (
                    step.id === "details" &&
                    currentStep === idx &&
                    canProceed
                  ) {
                    isCompleted = true;
                  }
                  const showSubSteps =
                    step.id === "details" &&
                    isActive &&
                    currentSubSteps.length > 0;

                  // #1 — clickable any visited step (not just completed)
                  const canClickStep = !isActive && idx <= highestStepReached;

                  // #6 — simplified Details description (just date, sub-steps handle rest)
                  const detailsDesc = (() => {
                    if (step.id !== "details" || !isCompleted) return null;
                    if (
                      selectedService === "daycare" &&
                      daycareSelectedDates.length > 0
                    )
                      return `${daycareSelectedDates.length} day${daycareSelectedDates.length !== 1 ? "s" : ""} scheduled`;
                    if (
                      selectedService === "boarding" &&
                      boardingRangeStart &&
                      boardingRangeEnd
                    )
                      return `${boardingRangeStart.toLocaleDateString("en-US", { month: "short", day: "numeric" })} → ${boardingRangeEnd.toLocaleDateString("en-US", { month: "short", day: "numeric" })}`;
                    if (startDate)
                      return new Date(
                        startDate + "T12:00:00",
                      ).toLocaleDateString("en-US", {
                        weekday: "short",
                        month: "short",
                        day: "numeric",
                      });
                    return null;
                  })();

                  // #5 — pet names with truncation
                  const petSummary = (() => {
                    if (selectedPets.length === 0) return "";
                    if (selectedPets.length <= 2)
                      return selectedPets.map((p) => p.name).join(", ");
                    return `${selectedPets[0].name}, ${selectedPets[1].name} +${selectedPets.length - 2} more`;
                  })();

                  const stepDesc = (() => {
                    if (step.id === "service" && selectedService)
                      return (
                        configs[selectedService as keyof typeof configs]
                          ?.clientFacingName ??
                        getModuleBySlug(selectedService)?.name ??
                        selectedService.charAt(0).toUpperCase() +
                          selectedService.slice(1)
                      );
                    if (step.id === "client-pet" && selectedClient)
                      return `${selectedClient.name}${petSummary ? ` · ${petSummary}` : ""}`;
                    if (step.id === "details" && detailsDesc)
                      return detailsDesc;
                    // #3 — Confirm shows action text, not price (price is in footer)
                    if (step.id === "confirm")
                      return isEstimateMode
                        ? "Review & send"
                        : "Review & create";
                    return step.description;
                  })();

                  return (
                    <div key={step.id}>
                      {/* #1 — clickable step card */}
                      <div
                        role={canClickStep ? "button" : undefined}
                        tabIndex={canClickStep ? 0 : undefined}
                        onClick={() => {
                          if (canClickStep) {
                            setCurrentStep(idx);
                            setCurrentSubStep(0);
                          }
                        }}
                        onKeyDown={(e) => {
                          if (
                            canClickStep &&
                            (e.key === "Enter" || e.key === " ")
                          ) {
                            e.preventDefault();
                            setCurrentStep(idx);
                            setCurrentSubStep(0);
                          }
                        }}
                        className={cn(
                          "w-full rounded-lg border p-3 text-left transition-all",
                          isActive
                            ? selectedService
                              ? `${accent.border} ${accent.stepBg} text-white shadow-sm`
                              : "border-primary bg-primary text-primary-foreground shadow-sm"
                            : isCompleted
                              ? "border-border bg-background"
                              : "border-muted-foreground/30 bg-muted/50 border-dashed opacity-60",
                          canClickStep &&
                            (selectedService
                              ? `cursor-pointer ${accent.btnHover}`
                              : "hover:border-primary/50 hover:bg-primary/5 cursor-pointer"),
                        )}
                      >
                        <div className="flex items-start gap-3">
                          <div
                            className={cn(
                              "mt-0.5 flex size-5 shrink-0 items-center justify-center rounded-full text-xs font-semibold",
                              isActive
                                ? "bg-white/90 text-slate-800"
                                : isCompleted
                                  ? selectedService
                                    ? `${accent.stepBg} text-white`
                                    : "bg-primary text-primary-foreground"
                                  : "bg-muted-foreground/20 text-muted-foreground",
                            )}
                          >
                            {isCompleted ? (
                              <Check className="size-3" />
                            ) : (
                              idx + 1
                            )}
                          </div>
                          <div className="min-w-0 flex-1">
                            <p
                              className={cn(
                                "mb-0.5 text-sm font-medium",
                                !isActive &&
                                  !isCompleted &&
                                  "text-muted-foreground",
                              )}
                            >
                              {step.title}
                            </p>
                            <p
                              className={cn(
                                "truncate text-xs",
                                isActive
                                  ? "text-primary-foreground/80"
                                  : "text-muted-foreground",
                              )}
                            >
                              {stepDesc}
                            </p>
                          </div>
                        </div>
                      </div>

                      {/* Sub-steps */}
                      {showSubSteps && (
                        <div
                          className={cn(
                            "mt-2 ml-6 space-y-1 border-l-2 pl-4",
                            selectedService
                              ? accent.subStepBorder
                              : "border-primary/30",
                          )}
                        >
                          {currentSubSteps.map((subStep, subIdx) => {
                            const isSubActive = currentSubStep === subIdx;
                            const isSubCompleted = isSubStepComplete(subIdx);
                            const isVisitedAndCompleted =
                              subIdx < currentSubStep && isSubCompleted;

                            // #4 — only show summary when there's actual data
                            const subSummary = (() => {
                              if (!isVisitedAndCompleted) return null;
                              if (subStep.id === 0) {
                                if (
                                  selectedService === "daycare" &&
                                  daycareSelectedDates.length > 0
                                )
                                  return `${daycareSelectedDates.length} day${daycareSelectedDates.length !== 1 ? "s" : ""}`;
                                if (
                                  selectedService === "boarding" &&
                                  boardingRangeStart &&
                                  boardingRangeEnd
                                )
                                  return `${boardingRangeStart.toLocaleDateString("en-US", { month: "short", day: "numeric" })} → ${boardingRangeEnd.toLocaleDateString("en-US", { month: "short", day: "numeric" })}`;
                                if (startDate)
                                  return new Date(
                                    startDate + "T12:00:00",
                                  ).toLocaleDateString("en-US", {
                                    month: "short",
                                    day: "numeric",
                                  });
                              }
                              if (
                                subStep.id === 1 &&
                                roomAssignments.length > 0
                              )
                                return `${roomAssignments.length} pet${roomAssignments.length !== 1 ? "s" : ""} assigned`;
                              if (subStep.id === 2 && extraServices.length > 0)
                                return `${extraServices.reduce((s, e) => s + e.quantity, 0)} add-on${extraServices.reduce((s, e) => s + e.quantity, 0) !== 1 ? "s" : ""}`;
                              if (subStep.id === 3) {
                                const parts = [
                                  feedingSchedule.length > 0 &&
                                    `${feedingSchedule.reduce((s, f) => s + f.occasions.length, 0)} meals`,
                                  medications.length > 0 &&
                                    `${medications.length} med${medications.length !== 1 ? "s" : ""}`,
                                ].filter(Boolean);
                                return parts.length > 0
                                  ? parts.join(" · ")
                                  : null;
                              }
                              return null;
                            })();

                            return (
                              <div
                                key={subStep.id}
                                className={cn(
                                  "w-full rounded-md px-3 py-2 text-left text-sm transition-all",
                                  isSubActive
                                    ? selectedService
                                      ? `${accent.subStepBg} ${accent.subStepText} font-medium`
                                      : "bg-primary/20 text-primary font-medium"
                                    : isVisitedAndCompleted
                                      ? "text-foreground"
                                      : "text-muted-foreground",
                                )}
                              >
                                <div className="flex items-center gap-2">
                                  <div
                                    className={cn(
                                      "flex size-4 shrink-0 items-center justify-center rounded-full text-[10px] font-semibold",
                                      isSubActive || isVisitedAndCompleted
                                        ? selectedService
                                          ? `${accent.stepBg} text-white`
                                          : "bg-primary text-primary-foreground"
                                        : "bg-muted-foreground/20 text-muted-foreground",
                                    )}
                                  >
                                    {isVisitedAndCompleted ? (
                                      <Check className="size-2.5" />
                                    ) : (
                                      subIdx + 1
                                    )}
                                  </div>
                                  <div className="min-w-0 flex-1">
                                    <span>{subStep.title}</span>
                                    {subSummary && (
                                      <p className="text-muted-foreground mt-0.5 truncate text-[10px]">
                                        {subSummary}
                                      </p>
                                    )}
                                  </div>
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </ScrollArea>

            {/* Price Summary at Bottom */}
            <div className="bg-background border-t p-6">
              <div className="space-y-2">
                <div className="flex justify-between text-sm font-semibold">
                  <span>
                    {isEstimateMode ? "Estimated Total" : "Total Price"}
                  </span>
                  <span>
                    $
                    {(
                      calculatePrice.total + (isEstimateMode ? 0 : tipAmount)
                    ).toFixed(2)}
                  </span>
                </div>
                {tipAmount > 0 && (
                  <div className="text-muted-foreground flex justify-between text-xs">
                    <span>Incl. tip</span>
                    <span>+${tipAmount.toFixed(2)}</span>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Main Content Area */}
          <div className="flex min-w-0 flex-1 flex-col overflow-scroll">
            <ScrollArea className="flex-1">
              <div className="bg-background border-b p-4">
                <h2 className="text-lg font-semibold">
                  {displayedSteps[currentStep]?.title}
                </h2>
                {displayedSteps[currentStep]?.id === "details" &&
                  (selectedService === "daycare" ||
                    selectedService === "boarding" ||
                    selectedService === "evaluation") && (
                    <p className="text-muted-foreground mt-1 text-sm">
                      {currentSubSteps[currentSubStep]?.title}
                    </p>
                  )}
              </div>
              <div className="p-6">
                {displayedSteps[currentStep]?.id === "service" && (
                  <ServiceStep
                    selectedService={selectedService}
                    setSelectedService={handleServiceChange}
                    setServiceType={setServiceType}
                    setCurrentSubStep={setCurrentSubStep}
                    configs={configs}
                    bookingFlow={bookingFlow}
                    selectedPets={selectedPets}
                  />
                )}
                {displayedSteps[currentStep]?.id === "client-pet" && (
                  <ClientPetStep
                    searchQuery={searchQuery}
                    setSearchQuery={setSearchQuery}
                    filteredClients={filteredClients}
                    selectedClientId={selectedClientId}
                    setSelectedClientId={setSelectedClientId}
                    selectedPetIds={selectedPetIds}
                    setSelectedPetIds={setSelectedPetIds}
                    selectedClient={selectedClient}
                    preSelectedClientId={preSelectedClientId}
                    selectedService={selectedService}
                    configs={configs}
                    isEstimateMode={isEstimateMode}
                    isGuestEstimate={isGuestEstimate}
                    setIsGuestEstimate={setIsGuestEstimate}
                    guestName={guestName}
                    setGuestName={setGuestName}
                    guestEmail={guestEmail}
                    setGuestEmail={setGuestEmail}
                    guestPhone={guestPhone}
                    setGuestPhone={setGuestPhone}
                    guestPetName={guestPetName}
                    setGuestPetName={setGuestPetName}
                  />
                )}
                {displayedSteps[currentStep]?.id === "details" && (
                  <DetailsStep
                    selectedService={selectedService}
                    currentSubStep={currentSubStep}
                    isSubStepComplete={isSubStepComplete}
                    daycareSelectedDates={daycareSelectedDates}
                    setDaycareSelectedDates={setDaycareSelectedDates}
                    daycareDateTimes={daycareDateTimes}
                    setDaycareDateTimes={setDaycareDateTimes}
                    roomAssignments={roomAssignments}
                    setRoomAssignments={setRoomAssignments}
                    boardingRangeStart={boardingRangeStart}
                    setBoardingRangeStart={setBoardingRangeStart}
                    boardingRangeEnd={boardingRangeEnd}
                    setBoardingRangeEnd={setBoardingRangeEnd}
                    boardingDateTimes={boardingDateTimes}
                    setBoardingDateTimes={setBoardingDateTimes}
                    startDate={startDate}
                    setStartDate={setStartDate}
                    endDate={endDate}
                    setEndDate={setEndDate}
                    checkInTime={checkInTime}
                    setCheckInTime={setCheckInTime}
                    checkOutTime={checkOutTime}
                    setCheckOutTime={setCheckOutTime}
                    serviceType={serviceType}
                    setServiceType={setServiceType}
                    feedingSchedule={feedingSchedule}
                    setFeedingSchedule={setFeedingSchedule}
                    medications={medications}
                    setMedications={setMedications}
                    feedingMedicationTab={feedingMedicationTab}
                    setFeedingMedicationTab={setFeedingMedicationTab}
                    extraServices={extraServices}
                    setExtraServices={setExtraServices}
                    selectedPets={selectedPets}
                  />
                )}

                {/* Include Evaluation toggle — shown on confirm step for non-evaluation services */}
                {displayedSteps[currentStep]?.id === "confirm" &&
                  selectedService !== "evaluation" &&
                  !(isEstimateMode && estimateCreated) && (
                    <div className="mx-1 mb-4 flex items-center justify-between rounded-xl border border-amber-200 bg-amber-50 px-4 py-3">
                      <div className="flex items-center gap-2.5">
                        <div className="flex size-8 items-center justify-center rounded-lg bg-amber-100">
                          <ClipboardCheck className="size-4 text-amber-700" />
                        </div>
                        <div>
                          <p className="text-sm font-semibold text-amber-900">
                            Include Evaluation
                          </p>
                          <p className="text-[11px] text-amber-700">
                            Schedule a pet evaluation on the first day of this
                            booking
                          </p>
                        </div>
                      </div>
                      <Switch
                        checked={includesEvaluation}
                        onCheckedChange={setIncludesEvaluation}
                      />
                    </div>
                  )}

                {/* Estimate success state */}
                {displayedSteps[currentStep]?.id === "confirm" &&
                  isEstimateMode &&
                  estimateCreated && (
                    <div className="flex flex-col items-center px-6 py-12 text-center">
                      {estimateSent ? (
                        <>
                          <div className="flex size-16 items-center justify-center rounded-full bg-emerald-100">
                            <Check className="size-7 text-emerald-600" />
                          </div>
                          <h3 className="mt-4 text-lg font-bold text-slate-800">
                            Estimate Sent!
                          </h3>
                          <p className="text-muted-foreground mt-1 max-w-sm text-sm">
                            The estimate has been sent to{" "}
                            <span className="font-medium text-slate-700">
                              {selectedClient?.name}
                            </span>
                            . It will appear in their customer file under
                            Estimates.
                          </p>
                          <div className="mt-4 rounded-xl border border-emerald-200 bg-emerald-50 px-5 py-3">
                            <p className="text-xl font-bold text-emerald-800 tabular-nums">
                              ${calculatePrice.total.toFixed(2)}
                            </p>
                            <p className="text-xs text-emerald-600">
                              Estimated total
                            </p>
                          </div>
                          <Button
                            className="mt-6"
                            onClick={() => {
                              resetForm();
                              onOpenChange(false);
                            }}
                          >
                            Done
                          </Button>
                        </>
                      ) : (
                        <>
                          <div className="flex size-16 items-center justify-center rounded-full bg-blue-100">
                            <Check className="size-7 text-blue-600" />
                          </div>
                          <h3 className="mt-4 text-lg font-bold text-slate-800">
                            Estimate Created
                          </h3>
                          <p className="text-muted-foreground mt-1 max-w-sm text-sm">
                            Estimate for{" "}
                            <span className="font-medium text-slate-700">
                              {selectedClient?.name}
                            </span>{" "}
                            — {selectedPets.map((p) => p.name).join(", ")}
                          </p>
                          <div className="mt-4 rounded-xl border bg-slate-50 px-5 py-3">
                            <p className="text-xl font-bold tabular-nums">
                              ${calculatePrice.total.toFixed(2)}
                            </p>
                            <p className="text-muted-foreground text-xs">
                              {selectedService} · {serviceType || "Standard"}
                            </p>
                          </div>
                          <div className="mt-6 flex gap-3">
                            <Button
                              variant="outline"
                              onClick={() => {
                                resetForm();
                                onOpenChange(false);
                              }}
                            >
                              Save as Draft
                            </Button>
                            <Button
                              className="gap-1.5"
                              onClick={() => setEstimateSent(true)}
                            >
                              <svg
                                className="size-4"
                                fill="none"
                                viewBox="0 0 24 24"
                                stroke="currentColor"
                                strokeWidth={2}
                              >
                                <path
                                  strokeLinecap="round"
                                  strokeLinejoin="round"
                                  d="M6 12L3.269 3.126A59.768 59.768 0 0121.485 12 59.77 59.77 0 013.27 20.876L5.999 12zm0 0h7.5"
                                />
                              </svg>
                              Send to Customer
                            </Button>
                          </div>
                        </>
                      )}
                    </div>
                  )}

                {displayedSteps[currentStep]?.id === "confirm" &&
                  !(isEstimateMode && estimateCreated) && (
                    <ConfirmStep
                      selectedClient={selectedClient}
                      selectedPets={selectedPets}
                      selectedService={selectedService}
                      serviceType={serviceType}
                      startDate={startDate}
                      endDate={endDate}
                      checkInTime={checkInTime}
                      checkOutTime={checkOutTime}
                      daycareSelectedDates={daycareSelectedDates}
                      boardingRangeStart={boardingRangeStart}
                      boardingRangeEnd={boardingRangeEnd}
                      boardingDateTimes={boardingDateTimes}
                      roomAssignments={roomAssignments}
                      feedingSchedule={feedingSchedule}
                      medications={medications}
                      extraServices={calculatePrice.effectiveExtraServices}
                      calculatePrice={calculatePrice}
                      notificationEmail={notificationEmail}
                      setNotificationEmail={setNotificationEmail}
                      notificationSMS={notificationSMS}
                      setNotificationSMS={setNotificationSMS}
                      tipConfig={tipConfig}
                      tipAmount={tipAmount}
                      onTipChange={setTipAmount}
                      onEditStep={(stepIdx, subStep) => {
                        setCurrentStep(stepIdx);
                        setCurrentSubStep(subStep ?? 0);
                      }}
                    />
                  )}
              </div>
            </ScrollArea>

            {/* Navigation Buttons */}
            {!(isEstimateMode && estimateCreated) && (
              <div className="bg-background flex justify-between border-t p-4">
                <Button
                  type="button"
                  variant="outline"
                  onClick={handlePrevious}
                  disabled={currentStep === 0}
                >
                  Previous
                </Button>
                <div className="flex gap-2">
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => {
                      // If user has made progress, confirm before discarding
                      if (currentStep > 0 || selectedService) {
                        setShowCancelConfirm(true);
                      } else {
                        onOpenChange(false);
                      }
                    }}
                  >
                    Cancel
                  </Button>
                  {currentStep < displayedSteps.length - 1 ? (
                    <Button
                      type="button"
                      onClick={handleNext}
                      disabled={!canProceed}
                      className={
                        selectedService && canProceed
                          ? `${accent.btnBg} text-white`
                          : ""
                      }
                    >
                      Next
                    </Button>
                  ) : (
                    <Button
                      type="button"
                      onClick={handleComplete}
                      disabled={!canProceed}
                      className={
                        selectedService && canProceed
                          ? `${accent.btnBg} text-white`
                          : ""
                      }
                    >
                      {isEstimateMode ? "Create Estimate" : "Create Booking"}
                    </Button>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </DialogContent>

      {/* Cancel confirmation */}
      <AlertDialog open={showCancelConfirm} onOpenChange={setShowCancelConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>
              Discard this {isEstimateMode ? "estimate" : "booking"}?
            </AlertDialogTitle>
            <AlertDialogDescription>
              All information you&apos;ve entered will be lost. This action
              cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Continue editing</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={() => {
                resetForm();
                onOpenChange(false);
              }}
            >
              Discard {isEstimateMode ? "estimate" : "booking"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </Dialog>
  );
}

