"use client";

import { useState, useMemo } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Dialog, DialogContent, DialogTitle } from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  User,
  Sparkles,
  Check,
  ChevronRight,
  Search,
  FileText,
  Send,
  Calendar,
  Clock,
  Plus,
  Trash2,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import { clients } from "@/data/clients";
import { GuestContactForm } from "./GuestContactForm";
import { SERVICE_CATEGORIES } from "@/components/bookings/modals/constants";
import type { EstimateLineItem } from "@/types/booking";

interface EstimateWizardProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  facilityId: number;
}

const STEPS = [
  { id: "client", title: "Client" },
  { id: "service", title: "Service" },
  { id: "details", title: "Details" },
  { id: "review", title: "Review & Send" },
];

export function EstimateWizard({
  open,
  onOpenChange,
  facilityId,
}: EstimateWizardProps) {
  const [step, setStep] = useState(0);

  // Client selection
  const [isGuest, setIsGuest] = useState(false);
  const [selectedClientId, setSelectedClientId] = useState<number | null>(null);
  const [clientSearch, setClientSearch] = useState("");

  // Guest contact
  const [guestName, setGuestName] = useState("");
  const [guestEmail, setGuestEmail] = useState("");
  const [guestPhone, setGuestPhone] = useState("");
  const [guestPetName, setGuestPetName] = useState("");
  const [guestPetBreed, setGuestPetBreed] = useState("");
  const [publicNote, setPublicNote] = useState("");
  const [createAccount, setCreateAccount] = useState(true);

  // Service
  const [selectedService, setSelectedService] = useState("");

  // Details
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [checkInTime, setCheckInTime] = useState("14:00");
  const [checkOutTime, setCheckOutTime] = useState("11:00");
  const [roomType, setRoomType] = useState("Standard");

  // Line items
  const [lineItems, setLineItems] = useState<EstimateLineItem[]>([]);
  const [discount, setDiscount] = useState(0);
  const [internalNote, setInternalNote] = useState("");

  // Completion
  const [created, setCreated] = useState(false);
  const [sent, setSent] = useState(false);

  const facilityClients = useMemo(
    () =>
      clients.filter(
        (c) =>
          c.facility === "Example Pet Care Facility" && c.status !== "prospect",
      ),
    [],
  );

  const filteredClients = useMemo(() => {
    if (!clientSearch.trim()) return facilityClients.slice(0, 10);
    const q = clientSearch.toLowerCase();
    return facilityClients
      .filter(
        (c) =>
          c.name.toLowerCase().includes(q) || c.email.toLowerCase().includes(q),
      )
      .slice(0, 10);
  }, [clientSearch, facilityClients]);

  const selectedClient = facilityClients.find((c) => c.id === selectedClientId);

  // Auto-generate line items from service details
  const autoLineItems = useMemo((): EstimateLineItem[] => {
    if (!selectedService || !startDate) return [];
    const svc = SERVICE_CATEGORIES.find((s) => s.id === selectedService);
    const price = svc?.basePrice ?? 45;
    const items: EstimateLineItem[] = [];

    if (selectedService === "boarding" && startDate && endDate) {
      const nights = Math.max(
        1,
        Math.round(
          (new Date(endDate).getTime() - new Date(startDate).getTime()) /
            86400000,
        ),
      );
      items.push({
        label: `${roomType} Room`,
        description: `${nights} night${nights !== 1 ? "s" : ""} @ $${price}/night`,
        amount: price,
        quantity: nights,
        total: price * nights,
      });
    } else {
      items.push({
        label: svc?.name ?? selectedService,
        description: `${svc?.name ?? selectedService} service`,
        amount: price,
        quantity: 1,
        total: price,
      });
    }
    return items;
  }, [selectedService, startDate, endDate, roomType]);

  // Merge auto + custom line items
  const allLineItems = lineItems.length > 0 ? lineItems : autoLineItems;
  const subtotal = allLineItems.reduce((s, li) => s + li.total, 0);
  const taxRate = 0.05;
  const taxAmount = (subtotal - discount) * taxRate;
  const total = subtotal - discount + taxAmount;

  const canProceed = () => {
    switch (step) {
      case 0:
        return isGuest || !!selectedClientId;
      case 1:
        return !!selectedService;
      case 2:
        return !!startDate;
      case 3:
        if (isGuest) return !!guestName.trim() && !!guestEmail.trim();
        return true;
      default:
        return false;
    }
  };

  const handleNext = () => {
    if (step === 2 && lineItems.length === 0) {
      setLineItems(autoLineItems);
    }
    if (step < STEPS.length - 1) setStep(step + 1);
  };

  const handleCreate = () => {
    setCreated(true);
    toast.success("Estimate created");
  };

  const handleSend = () => {
    setSent(true);
    toast.success(
      `Estimate sent to ${isGuest ? guestEmail : selectedClient?.email}`,
    );
  };

  const handleClose = () => {
    setStep(0);
    setIsGuest(false);
    setSelectedClientId(null);
    setSelectedService("");
    setStartDate("");
    setEndDate("");
    setLineItems([]);
    setDiscount(0);
    setCreated(false);
    setSent(false);
    setGuestName("");
    setGuestEmail("");
    setGuestPhone("");
    setGuestPetName("");
    setGuestPetBreed("");
    setPublicNote("");
    setInternalNote("");
    onOpenChange(false);
  };

  const addCustomLineItem = () => {
    setLineItems([
      ...allLineItems,
      { label: "Custom Item", amount: 0, quantity: 1, total: 0 },
    ]);
  };

  const updateLineItem = (idx: number, patch: Partial<EstimateLineItem>) => {
    const updated = [...allLineItems];
    const item = { ...updated[idx], ...patch };
    item.total = item.amount * item.quantity;
    updated[idx] = item;
    setLineItems(updated);
  };

  const removeLineItem = (idx: number) => {
    setLineItems(allLineItems.filter((_, i) => i !== idx));
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="flex max-h-[85vh] max-w-2xl flex-col gap-0 overflow-hidden p-0">
        <DialogTitle className="sr-only">Create Estimate</DialogTitle>

        {/* Header */}
        <div className="shrink-0 border-b px-6 pt-5 pb-4">
          <div className="flex items-center gap-3">
            <div className="flex size-10 items-center justify-center rounded-xl bg-blue-50">
              <FileText className="size-5 text-blue-500" />
            </div>
            <div>
              <h2 className="text-lg font-bold">
                {created ? "Estimate Ready" : "New Estimate"}
              </h2>
              <p className="text-muted-foreground text-sm">
                {created
                  ? "Review and send to customer"
                  : `Step ${step + 1} of ${STEPS.length}`}
              </p>
            </div>
          </div>

          {/* Step indicator */}
          {!created && (
            <div className="mt-4 flex gap-1">
              {STEPS.map((s, i) => (
                <div
                  key={s.id}
                  className={cn(
                    "h-1 flex-1 rounded-full transition-all",
                    i <= step ? "bg-blue-500" : "bg-slate-200",
                  )}
                />
              ))}
            </div>
          )}
        </div>

        {/* Body */}
        <ScrollArea className="min-h-0 flex-1">
          <div className="p-6">
            {/* Success screens */}
            {created && !sent && (
              <div className="flex flex-col items-center gap-4 py-8 text-center">
                <div className="flex size-16 items-center justify-center rounded-full bg-blue-100">
                  <Check className="size-7 text-blue-600" />
                </div>
                <h3 className="text-lg font-bold">Estimate Created</h3>
                <p className="text-muted-foreground max-w-sm text-sm">
                  for{" "}
                  <span className="font-medium text-slate-700">
                    {isGuest ? guestName : selectedClient?.name}
                  </span>
                  {guestPetName && ` — ${guestPetName}`}
                </p>
                <div className="rounded-xl border bg-slate-50 px-6 py-3">
                  <p className="text-xl font-bold tabular-nums">
                    ${total.toFixed(2)}
                  </p>
                  <p className="text-muted-foreground text-xs">
                    Estimated total
                  </p>
                </div>
                <div className="flex gap-3 pt-2">
                  <Button variant="outline" onClick={handleClose}>
                    Save as Draft
                  </Button>
                  <Button className="gap-1.5" onClick={handleSend}>
                    <Send className="size-4" />
                    Send to Customer
                  </Button>
                </div>
              </div>
            )}

            {created && sent && (
              <div className="flex flex-col items-center gap-4 py-8 text-center">
                <div className="flex size-16 items-center justify-center rounded-full bg-emerald-100">
                  <Check className="size-7 text-emerald-600" />
                </div>
                <h3 className="text-lg font-bold">Estimate Sent!</h3>
                <p className="text-muted-foreground max-w-sm text-sm">
                  Sent to{" "}
                  <span className="font-medium text-slate-700">
                    {isGuest ? guestEmail : selectedClient?.email}
                  </span>
                </p>
                {isGuest && createAccount && (
                  <Badge className="bg-blue-50 text-blue-700">
                    Customer account created
                  </Badge>
                )}
                <Button className="mt-2" onClick={handleClose}>
                  Done
                </Button>
              </div>
            )}

            {/* Step 0: Client */}
            {!created && step === 0 && (
              <div className="space-y-4">
                <h3 className="font-semibold">Who is this estimate for?</h3>
                <div className="grid grid-cols-2 gap-3">
                  <button
                    type="button"
                    onClick={() => {
                      setIsGuest(false);
                      setSelectedClientId(null);
                    }}
                    className={cn(
                      "flex flex-col items-center gap-2 rounded-xl border-2 p-5 transition-all",
                      !isGuest
                        ? "border-blue-400 bg-blue-50/50 shadow-sm"
                        : "border-slate-200 hover:border-blue-200",
                    )}
                  >
                    <User className="size-6 text-blue-500" />
                    <span className="text-sm font-semibold">
                      Existing Client
                    </span>
                    <span className="text-muted-foreground text-[11px]">
                      Search your client database
                    </span>
                  </button>
                  <button
                    type="button"
                    onClick={() => {
                      setIsGuest(true);
                      setSelectedClientId(null);
                    }}
                    className={cn(
                      "flex flex-col items-center gap-2 rounded-xl border-2 p-5 transition-all",
                      isGuest
                        ? "border-violet-400 bg-violet-50/50 shadow-sm"
                        : "border-slate-200 hover:border-violet-200",
                    )}
                  >
                    <Sparkles className="size-6 text-violet-500" />
                    <span className="text-sm font-semibold">New Inquiry</span>
                    <span className="text-muted-foreground text-[11px]">
                      No account yet — add info later
                    </span>
                  </button>
                </div>

                {/* Client search */}
                {!isGuest && (
                  <div className="space-y-2">
                    <div className="relative">
                      <Search className="text-muted-foreground absolute top-1/2 left-3 size-4 -translate-y-1/2" />
                      <Input
                        value={clientSearch}
                        onChange={(e) => setClientSearch(e.target.value)}
                        placeholder="Search clients..."
                        className="pl-10"
                      />
                    </div>
                    <div className="max-h-48 overflow-y-auto rounded-lg border">
                      {filteredClients.map((c) => (
                        <button
                          key={c.id}
                          type="button"
                          onClick={() => setSelectedClientId(c.id)}
                          className={cn(
                            "flex w-full items-center gap-3 border-b px-4 py-2.5 text-left transition-colors last:border-0",
                            selectedClientId === c.id
                              ? "bg-blue-50"
                              : "hover:bg-slate-50",
                          )}
                        >
                          <div className="flex size-8 shrink-0 items-center justify-center rounded-full bg-slate-100 text-xs font-bold text-slate-500">
                            {c.name.charAt(0)}
                          </div>
                          <div className="min-w-0 flex-1">
                            <p className="truncate text-sm font-medium">
                              {c.name}
                            </p>
                            <p className="text-muted-foreground truncate text-xs">
                              {c.email}
                            </p>
                          </div>
                          {selectedClientId === c.id && (
                            <Check className="size-4 text-blue-500" />
                          )}
                        </button>
                      ))}
                    </div>
                  </div>
                )}

                {/* Guest quick pet info */}
                {isGuest && (
                  <div className="rounded-xl border bg-violet-50/30 p-4">
                    <p className="mb-3 text-sm font-medium">
                      Quick pet info (optional)
                    </p>
                    <div className="grid gap-3 md:grid-cols-2">
                      <Input
                        value={guestPetName}
                        onChange={(e) => setGuestPetName(e.target.value)}
                        placeholder="Pet name (e.g., Max)"
                        className="bg-white"
                      />
                      <Input
                        value={guestPetBreed}
                        onChange={(e) => setGuestPetBreed(e.target.value)}
                        placeholder="Breed (e.g., Labrador)"
                        className="bg-white"
                      />
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Step 1: Service */}
            {!created && step === 1 && (
              <div className="space-y-4">
                <h3 className="font-semibold">Select a service</h3>
                <div className="grid grid-cols-2 gap-3">
                  {SERVICE_CATEGORIES.filter(
                    (s) => s.id !== "retail" && s.id !== "store",
                  ).map((svc) => {
                    const Icon = svc.icon;
                    const selected = selectedService === svc.id;
                    return (
                      <button
                        key={svc.id}
                        type="button"
                        onClick={() => setSelectedService(svc.id)}
                        className={cn(
                          "flex items-center gap-3 rounded-xl border-2 p-4 text-left transition-all",
                          selected
                            ? "border-blue-400 bg-blue-50/50 shadow-sm"
                            : "border-slate-200 hover:border-blue-200 hover:shadow-sm",
                        )}
                      >
                        <div
                          className={cn(
                            "flex size-10 shrink-0 items-center justify-center rounded-lg",
                            selected ? "bg-blue-100" : "bg-slate-100",
                          )}
                        >
                          <Icon
                            className={cn(
                              "size-5",
                              selected ? "text-blue-600" : "text-slate-400",
                            )}
                          />
                        </div>
                        <div>
                          <p className="text-sm font-semibold">{svc.name}</p>
                          <p className="text-muted-foreground text-[11px]">
                            from ${svc.basePrice}
                          </p>
                        </div>
                      </button>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Step 2: Details */}
            {!created && step === 2 && (
              <div className="space-y-5">
                <h3 className="font-semibold">Service Details</h3>

                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label className="flex items-center gap-1.5">
                      <Calendar className="size-3.5" />
                      {selectedService === "boarding"
                        ? "Check-in Date"
                        : "Date"}
                    </Label>
                    <Input
                      type="date"
                      value={startDate}
                      onChange={(e) => setStartDate(e.target.value)}
                    />
                  </div>
                  {selectedService === "boarding" && (
                    <div className="space-y-2">
                      <Label className="flex items-center gap-1.5">
                        <Calendar className="size-3.5" />
                        Check-out Date
                      </Label>
                      <Input
                        type="date"
                        value={endDate}
                        onChange={(e) => setEndDate(e.target.value)}
                      />
                    </div>
                  )}
                </div>

                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label className="flex items-center gap-1.5">
                      <Clock className="size-3.5" />
                      Check-in Time
                    </Label>
                    <Input
                      type="time"
                      value={checkInTime}
                      onChange={(e) => setCheckInTime(e.target.value)}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label className="flex items-center gap-1.5">
                      <Clock className="size-3.5" />
                      Check-out Time
                    </Label>
                    <Input
                      type="time"
                      value={checkOutTime}
                      onChange={(e) => setCheckOutTime(e.target.value)}
                    />
                  </div>
                </div>

                {selectedService === "boarding" && (
                  <div className="space-y-2">
                    <Label>Room Type</Label>
                    <Select value={roomType} onValueChange={setRoomType}>
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="Standard">
                          Standard Room — $35/night
                        </SelectItem>
                        <SelectItem value="Deluxe">
                          Deluxe Room — $50/night
                        </SelectItem>
                        <SelectItem value="Luxury Suite">
                          Luxury Suite — $65/night
                        </SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                )}

                {/* Preview line items */}
                {autoLineItems.length > 0 && (
                  <div className="rounded-xl border bg-slate-50/50 p-4">
                    <p className="mb-2 text-xs font-semibold text-slate-500 uppercase">
                      Estimated pricing
                    </p>
                    {autoLineItems.map((li, i) => (
                      <div
                        key={i}
                        className="flex items-center justify-between text-sm"
                      >
                        <span>{li.label}</span>
                        <span className="font-semibold tabular-nums">
                          ${li.total.toFixed(2)}
                        </span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Step 3: Review & Send */}
            {!created && step === 3 && (
              <div className="space-y-5">
                {/* Line items editor */}
                <div>
                  <div className="mb-3 flex items-center justify-between">
                    <h3 className="font-semibold">Line Items</h3>
                    <Button
                      variant="ghost"
                      size="sm"
                      className="gap-1.5 text-xs"
                      onClick={addCustomLineItem}
                    >
                      <Plus className="size-3" />
                      Add Item
                    </Button>
                  </div>
                  <div className="space-y-2">
                    {allLineItems.map((li, i) => (
                      <div
                        key={i}
                        className="flex items-center gap-2 rounded-lg border px-3 py-2"
                      >
                        <Input
                          value={li.label}
                          onChange={(e) =>
                            updateLineItem(i, { label: e.target.value })
                          }
                          className="h-8 min-w-0 flex-1 text-sm"
                        />
                        <Input
                          type="number"
                          value={li.quantity}
                          onChange={(e) =>
                            updateLineItem(i, {
                              quantity: Number(e.target.value),
                            })
                          }
                          className="h-8 w-16 text-center text-sm"
                        />
                        <span className="text-muted-foreground text-xs">x</span>
                        <Input
                          type="number"
                          value={li.amount}
                          onChange={(e) =>
                            updateLineItem(i, {
                              amount: Number(e.target.value),
                            })
                          }
                          className="h-8 w-20 text-sm"
                          step="0.01"
                        />
                        <span className="w-20 text-right text-sm font-semibold tabular-nums">
                          ${li.total.toFixed(2)}
                        </span>
                        <button
                          type="button"
                          onClick={() => removeLineItem(i)}
                          className="text-slate-300 hover:text-red-500"
                        >
                          <Trash2 className="size-3.5" />
                        </button>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Pricing summary */}
                <div className="space-y-2 rounded-xl border bg-slate-50 p-4">
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">Subtotal</span>
                    <span className="font-medium tabular-nums">
                      ${subtotal.toFixed(2)}
                    </span>
                  </div>
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-muted-foreground">Discount</span>
                    <Input
                      type="number"
                      value={discount}
                      onChange={(e) => setDiscount(Number(e.target.value))}
                      className="h-7 w-24 text-right text-sm"
                      step="0.01"
                    />
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">
                      Tax ({(taxRate * 100).toFixed(0)}%)
                    </span>
                    <span className="tabular-nums">
                      ${taxAmount.toFixed(2)}
                    </span>
                  </div>
                  <div className="flex justify-between border-t pt-2 text-base font-bold">
                    <span>Total</span>
                    <span className="tabular-nums">${total.toFixed(2)}</span>
                  </div>
                </div>

                {/* Internal note */}
                <div className="space-y-2">
                  <Label>Internal Note (staff only)</Label>
                  <Textarea
                    value={internalNote}
                    onChange={(e) => setInternalNote(e.target.value)}
                    placeholder="Notes visible only to staff..."
                    rows={2}
                    className="min-h-[60px] text-sm"
                  />
                </div>

                {/* Guest contact form */}
                {isGuest && (
                  <GuestContactForm
                    name={guestName}
                    setName={setGuestName}
                    email={guestEmail}
                    setEmail={setGuestEmail}
                    phone={guestPhone}
                    setPhone={setGuestPhone}
                    petName={guestPetName}
                    setPetName={setGuestPetName}
                    petBreed={guestPetBreed}
                    setPetBreed={setGuestPetBreed}
                    publicNote={publicNote}
                    setPublicNote={setPublicNote}
                    createAccount={createAccount}
                    setCreateAccount={setCreateAccount}
                  />
                )}

                {/* Existing client recipient */}
                {!isGuest && selectedClient && (
                  <div className="rounded-xl border bg-blue-50/50 p-4">
                    <p className="mb-2 text-xs font-semibold text-slate-500 uppercase">
                      Send to
                    </p>
                    <p className="text-sm font-semibold">
                      {selectedClient.name}
                    </p>
                    <p className="text-muted-foreground text-xs">
                      {selectedClient.email} · {selectedClient.phone}
                    </p>
                  </div>
                )}
              </div>
            )}
          </div>
        </ScrollArea>

        {/* Footer */}
        {!created && (
          <div className="flex justify-between border-t px-6 py-4">
            <Button
              variant="outline"
              onClick={() => (step === 0 ? handleClose() : setStep(step - 1))}
            >
              {step === 0 ? "Cancel" : "Back"}
            </Button>
            <div className="flex gap-2">
              {step === STEPS.length - 1 ? (
                <Button
                  onClick={handleCreate}
                  disabled={!canProceed()}
                  className="gap-1.5 bg-blue-500 hover:bg-blue-600"
                >
                  <FileText className="size-4" />
                  {isGuest && createAccount
                    ? "Create Account & Estimate"
                    : "Create Estimate"}
                </Button>
              ) : (
                <Button
                  onClick={handleNext}
                  disabled={!canProceed()}
                  className="gap-1.5"
                >
                  Next
                  <ChevronRight className="size-4" />
                </Button>
              )}
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState } from "react";
import type { ServiceAddOn, AddOnPricingType } from "@/types/facility";
import { defaultServiceAddOns } from "@/data/service-addons";
import { SERVICE_CATEGORIES } from "@/components/bookings/modals/constants";
import { useCustomServices } from "@/hooks/use-custom-services";
import { getAllServiceCategories } from "@/lib/service-registry";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import {
  Plus,
  Package,
  Calendar,
  ListChecks,
  MoreVertical,
  Pencil,
  Trash2,
} from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Checkbox } from "@/components/ui/checkbox";
import { ScrollArea } from "@/components/ui/scroll-area";

// ============================================================================
// Constants
// ============================================================================

const STORAGE_KEY = "settings-service-addons";

const PRICING_TYPE_LABELS: Record<AddOnPricingType, string> = {
  flat: "Flat",
  per_day: "Per Day",
  per_session: "Per Session",
  per_hour: "Per Hour",
};

const PRICING_TYPE_PRICE_LABELS: Record<AddOnPricingType, string> = {
  flat: "Price ($)",
  per_day: "Price per Day ($)",
  per_session: "Price per Session ($)",
  per_hour: "Price per Hour ($)",
};

const SIZE_LABELS = {
  small: "Small",
  medium: "Medium",
  large: "Large",
  giant: "Giant",
} as const;

type SizeKey = keyof typeof SIZE_LABELS;

// ============================================================================
// Storage helpers
// ============================================================================

function loadAddOns(): ServiceAddOn[] {
  if (typeof window === "undefined") return defaultServiceAddOns;
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) return JSON.parse(stored) as ServiceAddOn[];
  } catch {
    // ignore
  }
  return defaultServiceAddOns;
}

function persistAddOns(addOns: ServiceAddOn[]) {
  if (typeof window === "undefined") return;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(addOns));
}

// ============================================================================
// Empty form state
// ============================================================================

function createEmptyAddOn(): Omit<
  ServiceAddOn,
  "id" | "createdAt" | "updatedAt" | "sortOrder"
> {
  return {
    name: "",
    description: "",
    image: "",
    category: "",
    colorCode: "",
    pricingType: "flat",
    price: 0,
    unitLabel: "",
    maxQuantity: undefined,
    duration: undefined,
    taxRate: undefined,
    applicableServices: [],
    requiresStaff: false,
    requiresScheduling: false,
    generatesTask: false,
    taskCategory: "",
    isDefault: false,
    petTypeFilter: undefined,
    sizePricing: undefined,
    isActive: true,
  };
}

// ============================================================================
// Price display helper
// ============================================================================

function formatPriceLabel(addon: ServiceAddOn): string {
  switch (addon.pricingType) {
    case "flat":
      return `$${addon.price}`;
    case "per_day":
      return `$${addon.price}/day`;
    case "per_session":
      return `$${addon.price}/${addon.unitLabel || "session"}`;
    case "per_hour":
      return `$${addon.price}/${addon.unitLabel || "hr"}`;
  }
}

// ============================================================================
// Component
// ============================================================================

export function AddOnsSettings() {
  const { modules } = useCustomServices();
  const allCategories = getAllServiceCategories(SERVICE_CATEGORIES, modules);

  const [addOns, setAddOns] = useState<ServiceAddOn[]>(loadAddOns);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [form, setForm] = useState(createEmptyAddOn());
  const [sizePricingEnabled, setSizePricingEnabled] = useState(false);
  const [sizePricingRows, setSizePricingRows] = useState<
    Array<{
      size: SizeKey;
      priceModifier: number;
      modifierType: "flat" | "percentage";
    }>
  >([
    { size: "small", priceModifier: 0, modifierType: "flat" },
    { size: "medium", priceModifier: 0, modifierType: "flat" },
    { size: "large", priceModifier: 0, modifierType: "flat" },
    { size: "giant", priceModifier: 0, modifierType: "flat" },
  ]);

  // --------------------------------------------------
  // Helpers
  // --------------------------------------------------

  function updateAndPersist(next: ServiceAddOn[]) {
    setAddOns(next);
    persistAddOns(next);
  }

  function openCreate() {
    setEditingId(null);
    setForm(createEmptyAddOn());
    setSizePricingEnabled(false);
    setSizePricingRows([
      { size: "small", priceModifier: 0, modifierType: "flat" },
      { size: "medium", priceModifier: 0, modifierType: "flat" },
      { size: "large", priceModifier: 0, modifierType: "flat" },
      { size: "giant", priceModifier: 0, modifierType: "flat" },
    ]);
    setDialogOpen(true);
  }

  function openEdit(addon: ServiceAddOn) {
    setEditingId(addon.id);
    setForm({
      name: addon.name,
      description: addon.description,
      image: addon.image || "",
      category: addon.category || "",
      colorCode: addon.colorCode || "",
      pricingType: addon.pricingType,
      price: addon.price,
      unitLabel: addon.unitLabel || "",
      maxQuantity: addon.maxQuantity,
      duration: addon.duration,
      taxRate: addon.taxRate,
      applicableServices: [...addon.applicableServices],
      requiresStaff: addon.requiresStaff ?? false,
      requiresScheduling: addon.requiresScheduling,
      generatesTask: addon.generatesTask,
      taskCategory: addon.taskCategory || "",
      isDefault: addon.isDefault ?? false,
      petTypeFilter: addon.petTypeFilter,
      sizePricing: addon.sizePricing,
      isActive: addon.isActive,
    });
    const hasSizePricing = !!addon.sizePricing && addon.sizePricing.length > 0;
    setSizePricingEnabled(hasSizePricing);
    if (hasSizePricing && addon.sizePricing) {
      setSizePricingRows(addon.sizePricing.map((sp) => ({ ...sp })));
    } else {
      setSizePricingRows([
        { size: "small", priceModifier: 0, modifierType: "flat" },
        { size: "medium", priceModifier: 0, modifierType: "flat" },
        { size: "large", priceModifier: 0, modifierType: "flat" },
        { size: "giant", priceModifier: 0, modifierType: "flat" },
      ]);
    }
    setDialogOpen(true);
  }

  function handleSave() {
    if (!form.name.trim()) {
      toast.error("Name is required");
      return;
    }
    if (!form.description.trim()) {
      toast.error("Description is required");
      return;
    }

    const now = new Date().toISOString();

    const sharedFields = {
      ...form,
      image: form.image || undefined,
      category: form.category || undefined,
      colorCode: form.colorCode || undefined,
      unitLabel: form.unitLabel || undefined,
      duration: form.duration || undefined,
      taxRate: form.taxRate || undefined,
      taskCategory: form.generatesTask
        ? form.taskCategory || undefined
        : undefined,
      sizePricing: sizePricingEnabled ? sizePricingRows : undefined,
      petTypeFilter:
        form.petTypeFilter &&
        (form.petTypeFilter.types?.length ||
          form.petTypeFilter.breeds?.length ||
          form.petTypeFilter.weightMin ||
          form.petTypeFilter.weightMax ||
          form.petTypeFilter.coatTypes?.length)
          ? form.petTypeFilter
          : undefined,
    };

    if (editingId) {
      const next = addOns.map((a) =>
        a.id === editingId ? { ...a, ...sharedFields, updatedAt: now } : a,
      );
      updateAndPersist(next);
      toast.success(`"${form.name}" updated`);
    } else {
      const newAddOn: ServiceAddOn = {
        id: `addon-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
        ...sharedFields,
        taskCategory: form.generatesTask
          ? form.taskCategory || undefined
          : undefined,
        sizePricing: sizePricingEnabled ? sizePricingRows : undefined,
        sortOrder: addOns.length + 1,
        createdAt: now,
        updatedAt: now,
      };
      updateAndPersist([...addOns, newAddOn]);
      toast.success(`"${form.name}" created`);
    }

    setDialogOpen(false);
  }

  function handleDelete(addon: ServiceAddOn) {
    const next = addOns.filter((a) => a.id !== addon.id);
    updateAndPersist(next);
    toast.success(`"${addon.name}" deleted`);
  }

  function handleToggleActive(addon: ServiceAddOn) {
    const next = addOns.map((a) =>
      a.id === addon.id
        ? { ...a, isActive: !a.isActive, updatedAt: new Date().toISOString() }
        : a,
    );
    updateAndPersist(next);
    toast.success(
      `"${addon.name}" ${addon.isActive ? "deactivated" : "activated"}`,
    );
  }

  function toggleService(serviceId: string) {
    setForm((prev) => {
      const services = prev.applicableServices.includes(serviceId)
        ? prev.applicableServices.filter((s) => s !== serviceId)
        : [...prev.applicableServices, serviceId];
      return { ...prev, applicableServices: services };
    });
  }

  // --------------------------------------------------
  // Sorted list
  // --------------------------------------------------

  const sortedAddOns = [...addOns].sort((a, b) => a.sortOrder - b.sortOrder);

  // Group by category for list display
  const existingCategories = [
    ...new Set(addOns.map((a) => a.category).filter(Boolean)),
  ] as string[];
  const grouped = sortedAddOns.reduce<Record<string, ServiceAddOn[]>>(
    (acc, addon) => {
      const cat = addon.category || "Uncategorized";
      if (!acc[cat]) acc[cat] = [];
      acc[cat].push(addon);
      return acc;
    },
    {},
  );
  const categoryOrder = [
    ...existingCategories,
    ...(grouped["Uncategorized"] ? ["Uncategorized"] : []),
  ].filter((c, i, arr) => arr.indexOf(c) === i);

  // --------------------------------------------------
  // Render
  // --------------------------------------------------

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold">Service Add-Ons</h2>
          <p className="text-muted-foreground text-sm">
            Configure optional add-on services that customers can select when
            booking daycare, boarding, and other services.
          </p>
        </div>
        <Button onClick={openCreate} size="sm" className="gap-1.5">
          <Plus className="size-4" />
          Create Add-On
        </Button>
      </div>

      {/* Add-on cards list grouped by category */}
      <div className="space-y-6">
        {categoryOrder.map((cat) => (
          <div key={cat} className="space-y-3">
            <div className="flex items-center gap-2">
              <h3 className="text-sm font-semibold text-slate-700">{cat}</h3>
              <Badge variant="secondary" className="text-[10px]">
                {grouped[cat]?.length ?? 0}
              </Badge>
            </div>
            {(grouped[cat] ?? []).map((addon) => (
              <div
                key={addon.id}
                className={cn(
                  "flex items-center gap-4 rounded-2xl border p-4 transition-all duration-200 hover:-translate-y-0.5 hover:shadow-lg",
                  !addon.isActive && "opacity-60",
                )}
              >
                {/* Thumbnail */}
                <div className="bg-muted flex size-12 shrink-0 items-center justify-center overflow-hidden rounded-xl">
                  {addon.image ? (
                    <img
                      src={addon.image}
                      alt={addon.name}
                      className="size-full object-cover"
                    />
                  ) : (
                    <Package className="text-muted-foreground size-5" />
                  )}
                </div>

                {/* Content */}
                <div className="min-w-0 flex-1">
                  <div className="flex items-center gap-2">
                    {addon.colorCode && (
                      <div
                        className="size-2.5 shrink-0 rounded-full"
                        style={{ backgroundColor: addon.colorCode }}
                      />
                    )}
                    <span className="truncate font-medium">{addon.name}</span>
                    <Badge variant="secondary" className="shrink-0 text-[10px]">
                      {PRICING_TYPE_LABELS[addon.pricingType]}
                    </Badge>
                    <Badge variant="outline" className="shrink-0 text-[10px]">
                      {formatPriceLabel(addon)}
                    </Badge>
                    {addon.requiresScheduling && (
                      <Badge
                        variant="outline"
                        className="text-muted-foreground shrink-0 gap-1 text-[10px]"
                      >
                        <Calendar className="size-3" />
                        Scheduling
                      </Badge>
                    )}
                    {addon.generatesTask && (
                      <Badge
                        variant="outline"
                        className="text-muted-foreground shrink-0 gap-1 text-[10px]"
                      >
                        <ListChecks className="size-3" />
                        Auto-Task
                      </Badge>
                    )}
                    {addon.isDefault && (
                      <Badge className="shrink-0 bg-blue-100 text-[10px] text-blue-700">
                        Default
                      </Badge>
                    )}
                    {addon.duration && (
                      <Badge variant="outline" className="shrink-0 text-[10px]">
                        {addon.duration}min
                      </Badge>
                    )}
                  </div>
                  <p className="text-muted-foreground mt-0.5 line-clamp-1 text-sm">
                    {addon.description}
                  </p>
                  <p className="text-muted-foreground/70 mt-1 text-xs">
                    {addon.applicableServices
                      .map(
                        (s) =>
                          allCategories.find((c) => c.id === s)?.name ||
                          s.charAt(0).toUpperCase() + s.slice(1),
                      )
                      .join(", ")}
                  </p>
                </div>

                {/* Controls */}
                <div className="flex shrink-0 items-center gap-3">
                  <Switch
                    checked={addon.isActive}
                    onCheckedChange={() => handleToggleActive(addon)}
                  />
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button variant="ghost" size="sm" className="size-8 p-0">
                        <MoreVertical className="size-4" />
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end">
                      <DropdownMenuItem onClick={() => openEdit(addon)}>
                        <Pencil className="mr-2 size-4" />
                        Edit
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        onClick={() => handleDelete(addon)}
                        className="text-destructive"
                      >
                        <Trash2 className="mr-2 size-4" />
                        Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>
              </div>
            ))}
          </div>
        ))}

        {sortedAddOns.length === 0 && (
          <div className="bg-muted/30 flex flex-col items-center justify-center rounded-2xl border border-dashed p-12 text-center">
            <Package className="text-muted-foreground/40 size-10" />
            <p className="text-muted-foreground mt-3 text-sm">
              No add-ons configured yet. Create your first add-on to get
              started.
            </p>
          </div>
        )}
      </div>

      {/* Create / Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <DialogTitle>
              {editingId ? "Edit Add-On" : "Create Add-On"}
            </DialogTitle>
          </DialogHeader>

          <ScrollArea className="max-h-[65vh] pr-4">
            <div className="space-y-5 py-1">
              {/* Name */}
              <div className="space-y-2">
                <Label htmlFor="addon-name">
                  Name <span className="text-destructive">*</span>
                </Label>
                <Input
                  id="addon-name"
                  value={form.name}
                  onChange={(e) =>
                    setForm((prev) => ({ ...prev, name: e.target.value }))
                  }
                  placeholder="e.g. Extended Walk"
                />
              </div>

              {/* Description */}
              <div className="space-y-2">
                <Label htmlFor="addon-desc">
                  Description <span className="text-destructive">*</span>
                </Label>
                <Textarea
                  id="addon-desc"
                  value={form.description}
                  onChange={(e) =>
                    setForm((prev) => ({
                      ...prev,
                      description: e.target.value,
                    }))
                  }
                  placeholder="Describe this add-on..."
                  rows={3}
                />
              </div>

              {/* Image URL */}
              <div className="space-y-2">
                <Label htmlFor="addon-image">Image URL (optional)</Label>
                <Input
                  id="addon-image"
                  value={form.image || ""}
                  onChange={(e) =>
                    setForm((prev) => ({ ...prev, image: e.target.value }))
                  }
                  placeholder="https://..."
                />
              </div>

              {/* Category + Color */}
              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-2">
                  <Label>Category</Label>
                  <Input
                    value={form.category || ""}
                    onChange={(e) =>
                      setForm((prev) => ({ ...prev, category: e.target.value }))
                    }
                    placeholder="e.g. Grooming & Hygiene"
                    list="addon-categories"
                  />
                  <datalist id="addon-categories">
                    {existingCategories.map((c) => (
                      <option key={c} value={c} />
                    ))}
                  </datalist>
                </div>
                <div className="space-y-2">
                  <Label>Color Code</Label>
                  <div className="flex items-center gap-2">
                    <input
                      type="color"
                      value={form.colorCode || "#6366f1"}
                      onChange={(e) =>
                        setForm((prev) => ({
                          ...prev,
                          colorCode: e.target.value,
                        }))
                      }
                      className="size-9 cursor-pointer rounded-lg border p-0.5"
                    />
                    <Input
                      value={form.colorCode || ""}
                      onChange={(e) =>
                        setForm((prev) => ({
                          ...prev,
                          colorCode: e.target.value,
                        }))
                      }
                      placeholder="#6366f1"
                      className="flex-1"
                    />
                  </div>
                </div>
              </div>

              {/* Duration + Tax */}
              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-2">
                  <Label>Duration (minutes)</Label>
                  <Input
                    type="number"
                    min={0}
                    value={form.duration ?? ""}
                    onChange={(e) =>
                      setForm((prev) => ({
                        ...prev,
                        duration: e.target.value
                          ? parseInt(e.target.value, 10)
                          : undefined,
                      }))
                    }
                    placeholder="e.g. 30"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Tax Rate % (override)</Label>
                  <Input
                    type="number"
                    min={0}
                    step={0.01}
                    value={form.taxRate ?? ""}
                    onChange={(e) =>
                      setForm((prev) => ({
                        ...prev,
                        taxRate: e.target.value
                          ? parseFloat(e.target.value)
                          : undefined,
                      }))
                    }
                    placeholder="Uses facility default"
                  />
                </div>
              </div>

              {/* Requires Staff + Default */}
              <div className="space-y-3">
                <div className="flex items-center justify-between rounded-lg border p-3">
                  <div>
                    <p className="text-sm font-medium">Requires Staff</p>
                    <p className="text-muted-foreground text-xs">
                      Staff member must be assigned when this add-on is booked
                    </p>
                  </div>
                  <Switch
                    checked={form.requiresStaff ?? false}
                    onCheckedChange={(c) =>
                      setForm((prev) => ({ ...prev, requiresStaff: c }))
                    }
                  />
                </div>
                <div className="flex items-center justify-between rounded-lg border border-blue-200 bg-blue-50 p-3">
                  <div>
                    <p className="text-sm font-medium text-blue-800">
                      Default Add-On
                    </p>
                    <p className="text-xs text-blue-600">
                      Auto-applied to new bookings for applicable services
                    </p>
                  </div>
                  <Switch
                    checked={form.isDefault ?? false}
                    onCheckedChange={(c) =>
                      setForm((prev) => ({ ...prev, isDefault: c }))
                    }
                  />
                </div>
              </div>

              {/* Pet Eligibility */}
              <div className="space-y-2">
                <Label>Pet Eligibility (optional)</Label>
