      description: "Status has been reset",
      action: {
        label: "Undo",
        onClick: () => {
          setAppointmentsData((prev) =>
            prev.map((apt) =>
              apt.id === appointment.id
                ? { ...apt, status: previousStatus }
                : apt,
            ),
          );
