              </div>

              <div className="mt-3 flex flex-wrap items-center gap-2">
                <span className="text-muted-foreground text-[11px] font-medium uppercase tracking-wider">
                  Available for
                </span>
                {allServices.slice(0, 8).map((service) => (
                  <Badge
