      {/* Tag value */}
      {needsTag && (
        <Input
          value={rule.tagValue ?? ""}
          onChange={(e) => onChange({ ...rule, tagValue: e.target.value })}
          placeholder="Tag to apply (e.g. behavior-alert)"
          className="h-8 text-xs"
        />
      )}
    </div>
  );
}

function QuestionEditor({
  question,
  allQuestions,
  currentQuestionId: _currentQuestionId,
