function WizardQuestionInput({
  question,
  value,
  onChange,
}: {
  question: FormQuestion;
  value: unknown;
  onChange: (v: unknown) => void;
}) {
  const htmlId = `wq-${question.id}`;
  const opts = question.options ?? [];
  const help = question.helpText;

  switch (question.type) {
    // ---- yes_no ----
    case "yes_no": {
      const yesNoOpts = opts.length
        ? opts
        : [
            { value: "yes", label: "Yes" },
            { value: "no", label: "No" },
          ];
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <div className="flex gap-3">
            {yesNoOpts.map((o) => (
              <button
                key={o.value}
                type="button"
                className={`min-h-12 flex-1 touch-manipulation rounded-lg border-2 text-base font-medium transition-colors ${
                  value === o.value
                    ? "border-primary bg-primary/10 text-primary"
                    : `border-input hover:border-muted-foreground/30`
                } `}
                onClick={() => onChange(o.value)}
              >
                {o.label}
              </button>
            ))}
          </div>
        </div>
      );
    }

    // ---- radio ----
    case "radio":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <div className="space-y-2">
            {opts.map((o) => (
              <label
                key={o.value}
                className="hover:bg-muted/50 flex cursor-pointer touch-manipulation items-center gap-3 rounded-lg border p-3 transition-colors"
              >
                <input
                  type="radio"
                  name={htmlId}
                  className="size-5 shrink-0"
                  value={o.value}
                  checked={value === o.value}
                  onChange={() => onChange(o.value)}
                />
                <span className="text-base">{o.label}</span>
              </label>
            ))}
          </div>
        </div>
      );

    // ---- textarea ----
    case "textarea":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <textarea
            id={htmlId}
            className="border-input flex min-h-[80px] w-full rounded-md border bg-transparent px-3 py-2 text-base"
            value={(value as string) ?? question.defaultValue ?? ""}
            onChange={(e) => onChange(e.target.value)}
            placeholder={question.placeholder}
            required={question.required}
          />
        </div>
      );

    // ---- select (dropdown) ----
    case "select":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <select
            id={htmlId}
            className="border-input flex min-h-12 w-full rounded-md border bg-transparent px-3 py-2 text-base"
            value={(value as string) ?? question.defaultValue ?? ""}
            onChange={(e) => onChange(e.target.value)}
            required={question.required}
          >
            <option value="">Select...</option>
            {opts.map((o) => (
              <option key={o.value} value={o.value}>
                {o.label}
              </option>
            ))}
          </select>
        </div>
      );

    // ---- multiselect ----
    case "multiselect": {
      const selected = new Set((value as string[]) ?? []);
      const toggle = (v: string) => {
        const next = new Set(selected);
        if (next.has(v)) next.delete(v);
        else next.add(v);
        onChange(Array.from(next));
      };
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <div className="flex flex-wrap gap-2">
            {opts.map((o) => (
              <label
                key={o.value}
                className="flex min-h-12 cursor-pointer touch-manipulation items-center gap-2 text-base"
              >
                <input
                  type="checkbox"
                  className="size-5"
                  checked={selected.has(o.value)}
                  onChange={() => toggle(o.value)}
                />
                {o.label}
              </label>
            ))}
          </div>
        </div>
      );
    }

    // ---- checkbox (single boolean) ----
    case "checkbox":
      return (
        <div className="flex min-h-12 touch-manipulation items-center gap-2">
          <input
            id={htmlId}
            type="checkbox"
            className="size-5 shrink-0"
            checked={Boolean(value)}
            onChange={(e) => onChange(e.target.checked)}
          />
          <Label htmlFor={htmlId}>
            {question.label}
            {question.required && (
              <span className="ml-0.5 text-red-500">*</span>
            )}
          </Label>
          {help && (
            <span className="text-muted-foreground text-xs">{help}</span>
          )}
        </div>
      );

    // ---- date ----
    case "date":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <Input
            id={htmlId}
            type="date"
            className="min-h-12 text-base"
            value={(value as string) ?? question.defaultValue ?? ""}
            onChange={(e) => onChange(e.target.value)}
            required={question.required}
          />
        </div>
      );

    // ---- number ----
    case "number":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <Input
            id={htmlId}
            type="number"
            className="min-h-12 text-base"
            value={(value as number) ?? question.defaultValue ?? ""}
            onChange={(e) =>
              onChange(e.target.value ? Number(e.target.value) : undefined)
            }
            placeholder={question.placeholder}
            required={question.required}
          />
        </div>
      );

    // ---- file ----
    case "file":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <div className="border-input rounded-lg border-2 border-dashed p-6 text-center">
            <input
              id={htmlId}
              type="file"
              className="hidden"
              accept={
                question.validation?.allowedFileTypes?.join(",") ?? undefined
              }
              onChange={(e) => {
                const file = e.target.files?.[0];
                if (file) onChange(file.name);
              }}
            />
            <label
              htmlFor={htmlId}
              className="cursor-pointer touch-manipulation"
            >
              <div className="text-muted-foreground text-sm">
                {value ? (
                  <span className="text-foreground font-medium">
                    {String(value)}
                  </span>
                ) : (
                  <>Click to upload a file</>
                )}
              </div>
              <p className="text-muted-foreground mt-1 text-xs">
                {question.validation?.allowedFileTypes
                  ? `Allowed: ${question.validation.allowedFileTypes.join(", ")}`
                  : "PDF, JPG, PNG, DOC accepted"}
              </p>
            </label>
          </div>
        </div>
      );

    // ---- signature ----
    case "signature":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          {value ? (
            <div className="space-y-2 rounded-lg border p-4">
              <img
                src={
                  typeof value === "object" &&
                  (value as Record<string, unknown>).signatureData
                    ? String((value as Record<string, unknown>).signatureData)
                    : String(value)
                }
                alt="Signature"
                className="h-20 w-full object-contain"
              />
              <p className="text-xs text-emerald-600">✓ Signature captured</p>
            </div>
          ) : (
            <SignaturePadComponent
              label={question.label}
              agreementText={help}
              compact
              onSign={(result) =>
                onChange({
                  signatureData: result.signatureData,
                  signatureMetadata: {
                    signedAt: result.signedAt,
                    ipAddress: result.ipAddress,
                    userAgent: result.userAgent,
                    deviceId: result.deviceId,
                    timezone: result.timezone,
                    agreementText: result.agreementText,
                  },
                })
              }
            />
          )}
        </div>
      );

    // ---- phone ----
    case "phone":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <Input
            id={htmlId}
            type="tel"
            className="min-h-12 touch-manipulation text-base"
            value={(value as string) ?? question.defaultValue ?? ""}
            onChange={(e) => onChange(e.target.value)}
            placeholder={question.placeholder ?? "(555) 123-4567"}
            required={question.required}
          />
        </div>
      );

    // ---- email ----
    case "email":
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <Input
            id={htmlId}
            type="email"
            className="min-h-12 touch-manipulation text-base"
            value={(value as string) ?? question.defaultValue ?? ""}
            onChange={(e) => onChange(e.target.value)}
            placeholder={question.placeholder ?? "name@example.com"}
            required={question.required}
          />
        </div>
      );

    // ---- address ----
    case "address": {
      const addr =
        (value as {
          street?: string;
          city?: string;
          state?: string;
          zip?: string;
        }) ?? {};
      const update = (field: string, v: string) =>
        onChange({ ...addr, [field]: v });
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <div className="space-y-2">
            <Input
              placeholder="Street address"
              value={addr.street ?? ""}
              onChange={(e) => update("street", e.target.value)}
              className="min-h-12 text-base"
              required={question.required}
            />
            <div className="grid grid-cols-3 gap-2">
              <Input
                placeholder="City"
                value={addr.city ?? ""}
                onChange={(e) => update("city", e.target.value)}
                className="col-span-1 min-h-12 text-base"
              />
              <Input
                placeholder="State"
                value={addr.state ?? ""}
                onChange={(e) => update("state", e.target.value)}
                className="min-h-12 text-base"
              />
              <Input
                placeholder="ZIP"
                value={addr.zip ?? ""}
                onChange={(e) => update("zip", e.target.value)}
                className="min-h-12 text-base"
              />
            </div>
          </div>
        </div>
      );
    }

    // ---- text (default) ----
    case "text":
    default:
      return (
        <div className="space-y-2">
          <WizardQuestionLabel
            label={question.label}
            required={question.required}
            helpText={help}
          />
          <Input
            id={htmlId}
            type="text"
            value={(value as string) ?? question.defaultValue ?? ""}
            onChange={(e) => onChange(e.target.value)}
            placeholder={question.placeholder}
            required={question.required}
            className="min-h-12 touch-manipulation text-base"
          />
        </div>
      );
  }
}

