                            </Label>
                          </div>
                        </CardContent>
                      </Card>
                    ))}
                  </RadioGroup>
                  {depositPaymentMethod &&
                    depositPaymentMethod !== "venue" &&
                    depositPaymentMethod !== "hold" && (
                      <div className="bg-muted mt-2 rounded-md p-3">
                        <div className="flex items-center justify-between">
