            </div>
          ))}
        </div>

        {/* ── Pets ── */}
        <Section title="Pets" icon={PawPrint}>
          <div className="space-y-1">
            {client.pets.map((pet) => (
              <Link
                key={pet.id}
                href={`/facility/dashboard/clients/${client.id}/pets/${pet.id}`}
                className="flex items-center gap-2 rounded-lg p-1.5 hover:bg-slate-50"
              >
                {pet.imageUrl ? (
                  <img
                    src={pet.imageUrl}
                    alt=""
                    className="size-8 rounded-full object-cover"
                  />
                ) : (
                  <div className="flex size-8 items-center justify-center rounded-full bg-slate-100">
                    <PawPrint className="size-3.5 text-slate-400" />
                  </div>
                )}
                <div>
                  <p className="text-xs font-semibold text-slate-700">
                    {pet.name}
                  </p>
                  <p className="text-[11px] text-slate-400">
                    {pet.breed} · {pet.type}
                  </p>
                </div>
              </Link>
            ))}
          </div>
        </Section>

        {/* ── Next Appointment ── */}
        <Section title="Next Appointment" icon={Calendar}>
          {upcoming[0] ? (
            <div className="rounded-xl bg-slate-50 p-2.5">
              <div className="flex items-center justify-between">
                <Badge className="bg-blue-100 text-[10px] text-blue-700 capitalize">
                  {upcoming[0].service}
                </Badge>
                <span className="text-xs font-bold text-slate-700 tabular-nums">
                  ${upcoming[0].totalCost}
                </span>
              </div>
              <p className="mt-1.5 text-xs text-slate-500">
                {formatDate(upcoming[0].startDate)}
                {upcoming[0].checkInTime && ` · ${upcoming[0].checkInTime}`}
              </p>
            </div>
          ) : (
            <p className="text-xs text-slate-400 italic">
              No upcoming bookings
            </p>
          )}
        </Section>

        {/* ── Quick Send Links ── */}
        <Section title="Quick Send" icon={Send} defaultOpen>
          <div className="space-y-1">
            {QUICK_LINKS.map((link) => (
              <button
                key={link.id}
                type="button"
                onClick={() => {
                  navigator.clipboard.writeText(link.url);
                  toast.success(`"${link.label}" link copied — paste in chat`);
                }}
                className="group flex w-full items-center gap-2 rounded-lg p-1.5 text-left transition-colors hover:bg-slate-50"
              >
                <div
                  className={cn(
                    "flex size-7 shrink-0 items-center justify-center rounded-lg",
                    link.color,
                  )}
                >
                  <link.icon className="size-3.5" />
                </div>
                <span className="flex-1 text-xs font-medium text-slate-600">
                  {link.label}
                </span>
                <Copy className="size-3 text-slate-300 opacity-0 transition-opacity group-hover:opacity-100" />
              </button>
            ))}
          </div>
        </Section>

        {/* ── Shared Photos ── */}
        <Section title="Shared Photos" icon={ImageIcon} defaultOpen={false}>
          <div className="grid grid-cols-3 gap-[2px] overflow-hidden rounded-lg">
            {DEMO_MEDIA.map((item) => (
              <button
                key={item.id}
                className="group relative aspect-square overflow-hidden bg-slate-100"
                onClick={() => setSelectedImage(item.url)}
              >
                <img
                  src={item.thumbnail ?? item.url}
                  alt=""
                  className="size-full object-cover transition-transform group-hover:scale-110"
                />
                <div className="absolute inset-0 flex items-center justify-center bg-black/0 transition-colors group-hover:bg-black/30">
                  <Eye className="size-4 text-white opacity-0 transition-opacity group-hover:opacity-100" />
                </div>
              </button>
            ))}
          </div>
        </Section>
      </div>

      {/* Lightbox */}
      {selectedImage && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/80"
          onClick={() => setSelectedImage(null)}
        >
          <Button
            variant="ghost"
            size="icon"
            className="absolute top-4 right-4 size-10 rounded-full text-white hover:bg-white/20"
            onClick={() => setSelectedImage(null)}
          >
            <X className="size-5" />
          </Button>
          <img
            src={selectedImage}
            alt=""
            className="max-h-[80vh] max-w-[80vw] rounded-lg object-contain shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          />
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useMemo } from "react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import {
  Search,
  Plus,
  MessageSquare,
  X,
  AlertCircle,
  Smartphone,
  ChevronRight,
  RefreshCw,
} from "lucide-react";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import type { Message } from "@/types/communications";
import { clients } from "@/data/clients";
import { facilities } from "@/data/facilities";
import { useFacilityRole } from "@/hooks/use-facility-role";

// SMS credits
const facility = facilities.find((f) => f.id === 11);
const credits = (facility as Record<string, unknown>)?.smsCredits as
  | {
      monthlyAllowance: number;
      used: number;
      purchased: number;
      autoReload: boolean;
      autoReloadThreshold: number;
      autoReloadAmount: number;
    }
  | undefined;
const smsTotal = credits
  ? credits.monthlyAllowance + (credits.purchased ?? 0)
  : 0;
const smsRemaining = credits ? smsTotal - credits.used : 0;

const SMS_PACKAGES = [
  { amount: 100, price: 5 },
  { amount: 500, price: 20 },
  { amount: 1000, price: 35 },
  { amount: 5000, price: 150 },
];

export interface Thread {
  threadId: string;
  clientId: number;
  clientName: string;
  clientImage?: string;
  lastMessage: Message;
  unreadCount: number;
  channels: string[];
}

const COLORS = [
  "bg-rose-500",
  "bg-blue-500",
  "bg-emerald-500",
  "bg-violet-500",
  "bg-amber-500",
  "bg-sky-500",
  "bg-pink-500",
  "bg-teal-500",
];

function avatarColor(name: string) {
  return COLORS[name.charCodeAt(0) % COLORS.length];
}

function initials(name: string) {
  return name
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);
}

function relTime(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  const m = Math.floor(diff / 60000);
  if (m < 1) return "now";
  if (m < 60) return `${m}m`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h`;
  const d = Math.floor(h / 24);
  if (d < 7) return `${d}d`;
  return new Date(iso).toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
  });
}

type Filter = "all" | "unread" | "sms" | "email" | "chat";

export function ContactList({
  messages,
  selectedThreadId,
  onSelectThread,
}: {
  messages: Message[];
  selectedThreadId: string | null;
  onSelectThread: (threadId: string) => void;
}) {
  const { role } = useFacilityRole();
  const canPurchase = role === "owner" || role === "manager";
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState<Filter>("all");
  const [compose, setCompose] = useState(false);
  const [clientSearch, setClientSearch] = useState("");

  const clientResults = useMemo(() => {
    if (!clientSearch.trim()) return clients.slice(0, 10);
    const q = clientSearch.toLowerCase();
    return clients
      .filter(
        (c) =>
          c.name.toLowerCase().includes(q) || c.email.toLowerCase().includes(q),
      )
      .slice(0, 10);
  }, [clientSearch]);

  const threads = useMemo(() => {
    const map = new Map<string, Thread>();
    for (const msg of messages) {
      const tid = msg.threadId ?? msg.id;
      const existing = map.get(tid);
      if (
        !existing ||
        new Date(msg.timestamp) > new Date(existing.lastMessage.timestamp)
      ) {
        const client = msg.clientId
          ? clients.find((c) => c.id === msg.clientId)
          : null;
        const ch = new Set(existing?.channels ?? []);
        ch.add(msg.type);
        map.set(tid, {
          threadId: tid,
          clientId: msg.clientId ?? 0,
          clientName: client?.name ?? msg.from,
          clientImage: (client as Record<string, unknown>)?.imageUrl as
            | string
            | undefined,
          lastMessage: msg,
          unreadCount: (existing?.unreadCount ?? 0) + (!msg.hasRead ? 1 : 0),
          channels: [...ch],
        });
      } else {
        existing.channels = [...new Set([...existing.channels, msg.type])];
        if (!msg.hasRead) existing.unreadCount++;
      }
    }
    return [...map.values()].sort(
      (a, b) =>
        new Date(b.lastMessage.timestamp).getTime() -
        new Date(a.lastMessage.timestamp).getTime(),
    );
  }, [messages]);

  const filtered = useMemo(() => {
    let list = threads;
    if (filter === "unread") list = list.filter((t) => t.unreadCount > 0);
    if (filter === "sms") list = list.filter((t) => t.channels.includes("sms"));
    if (filter === "email")
      list = list.filter((t) => t.channels.includes("email"));
    if (filter === "chat")
      list = list.filter((t) => t.channels.includes("in-app"));
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(
        (t) =>
          t.clientName.toLowerCase().includes(q) ||
          t.lastMessage.body.toLowerCase().includes(q),
      );
    }
    return list;
  }, [threads, filter, search]);

  return (
    <div className="flex h-full w-80 shrink-0 flex-col bg-white">
      {/* Header */}
      <div className="flex items-center justify-between px-5 pt-4 pb-2">
        <h1 className="text-xl font-bold text-slate-900">Messages</h1>
        <Button
          size="icon"
          variant={compose ? "secondary" : "default"}
          className="size-9 rounded-full"
          onClick={() => {
            setCompose(!compose);
            setClientSearch("");
          }}
        >
          {compose ? <X className="size-4" /> : <Plus className="size-4" />}
        </Button>
      </div>

      {/* SMS credits strip */}
      {credits && !compose && (
        <Popover>
          <PopoverTrigger asChild>
            <button
              type="button"
              className="mx-4 mb-1 flex w-[calc(100%-2rem)] items-center gap-2 rounded-lg bg-slate-50 px-3 py-2 text-left transition-colors hover:bg-slate-100"
            >
              <Smartphone className="size-3.5 text-slate-400" />
              <div className="flex-1">
                <div className="flex items-center justify-between">
                  <span className="text-[10px] font-medium text-slate-500">
                    SMS Credits
                  </span>
                  <span
                    className={cn(
                      "text-[10px] font-bold tabular-nums",
                      smsRemaining > 500
                        ? "text-blue-600"
                        : smsRemaining > 100
                          ? "text-amber-600"
                          : "text-red-500",
                    )}
                  >
                    {smsRemaining.toLocaleString()} left
                  </span>
                </div>
                <div className="mt-1 h-1 overflow-hidden rounded-full bg-blue-100">
                  <div
                    className={cn(
                      "h-full rounded-full transition-all",
                      smsRemaining > 500
                        ? "bg-blue-500"
                        : smsRemaining > 100
                          ? "bg-amber-500"
                          : "bg-red-500",
                    )}
                    style={{
                      width: `${Math.min(100, (smsRemaining / smsTotal) * 100)}%`,
                    }}
                  />
                </div>
              </div>
              <ChevronRight className="size-3 text-slate-300" />
            </button>
          </PopoverTrigger>
          <PopoverContent
            align="start"
            className="w-64 rounded-xl border-slate-200 p-0 shadow-lg"
          >
            {/* Balance */}
            <div className="px-4 pt-3.5 pb-3">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-slate-500">
                  SMS Balance
                </span>
                <span
                  className={cn(
                    "text-lg leading-none font-bold tabular-nums",
                    smsRemaining > 500
                      ? "text-blue-600"
                      : smsRemaining > 100
                        ? "text-amber-600"
                        : "text-red-500",
                  )}
                >
                  {smsRemaining.toLocaleString()}
                </span>
              </div>
              <div className="mt-2 h-1.5 overflow-hidden rounded-full bg-blue-100">
                <div
                  className={cn(
                    "h-full rounded-full",
                    smsRemaining > 500
                      ? "bg-blue-500"
                      : smsRemaining > 100
                        ? "bg-amber-500"
                        : "bg-red-500",
                  )}
                  style={{
                    width: `${Math.min(100, (smsRemaining / smsTotal) * 100)}%`,
                  }}
                />
              </div>
              <div className="mt-1.5 flex gap-3 text-[10px] text-slate-400">
                <span>{credits.monthlyAllowance.toLocaleString()} plan</span>
                <span className="text-slate-300">·</span>
                <span>{credits.purchased.toLocaleString()} extra</span>
                <span className="text-slate-300">·</span>
                <span>{credits.used.toLocaleString()} used</span>
              </div>
              {credits.autoReload && (
                <div className="mt-2 flex items-center gap-1.5">
                  <RefreshCw className="size-2.5 text-blue-400" />
                  <span className="text-[10px] text-blue-500">
                    Auto-reload on
                  </span>
                </div>
              )}
            </div>

            {/* Packages — owner/manager only */}
            {canPurchase && (
              <div className="border-t border-slate-100 px-4 pt-2.5 pb-3">
                <p className="mb-2 text-[11px] font-semibold text-slate-500">
                  Buy More Credits
                </p>
                <div className="grid grid-cols-2 gap-1.5">
                  {SMS_PACKAGES.map((pkg) => {
                    const perSms = ((pkg.price / pkg.amount) * 100).toFixed(1);
                    return (
                      <button
                        key={pkg.amount}
                        type="button"
                        onClick={() =>
                          toast.success(
                            `${pkg.amount.toLocaleString()} credits purchased — $${pkg.price}`,
                          )
                        }
                        className="group flex flex-col items-center rounded-lg border border-slate-100 bg-slate-50/50 px-2 py-2 transition-all hover:border-blue-200 hover:bg-blue-50"
                      >
                        <span className="text-sm font-bold text-slate-700 group-hover:text-blue-600">
                          {pkg.amount >= 1000
                            ? `${pkg.amount / 1000}K`
                            : pkg.amount}
                        </span>
                        <span className="text-[9px] text-slate-400">
                          credits
                        </span>
                        <span className="mt-1 rounded-full bg-blue-50 px-2 py-px text-[10px] font-semibold text-blue-600 group-hover:bg-blue-100">
                          ${pkg.price}
                        </span>
                        <span className="mt-0.5 text-[9px] text-slate-400">
                          {perSms}¢/sms
                        </span>
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
          </PopoverContent>
        </Popover>
      )}

      {/* Search */}
      <div className="px-4 py-2">
        <div className="relative">
          <Search className="text-muted-foreground absolute top-1/2 left-3 size-4 -translate-y-1/2" />
          <Input
            placeholder={compose ? "Search clients..." : "Search messages..."}
            value={compose ? clientSearch : search}
            onChange={(e) =>
              compose
                ? setClientSearch(e.target.value)
                : setSearch(e.target.value)
            }
            className="h-9 rounded-full border-slate-200 bg-slate-50 pl-9 text-sm"
            autoFocus={compose}
          />
        </div>
      </div>

      {/* Filters */}
      {!compose && (
        <div className="flex gap-1 px-4 pb-2">
          {(
            [
              { key: "all" as Filter, label: "All" },
              { key: "chat" as Filter, label: "Chat" },
              { key: "email" as Filter, label: "Email" },
              { key: "sms" as Filter, label: "SMS" },
              { key: "unread" as Filter, label: "Unread" },
            ] as const
          ).map((f) => (
            <button
              key={f.key}
              onClick={() => setFilter(f.key)}
              className={cn(
                "rounded-full px-3 py-1 text-[11px] font-semibold transition-all",
                filter === f.key
                  ? "bg-slate-900 text-white"
                  : "bg-slate-100 text-slate-500 hover:bg-slate-200",
              )}
            >
              {f.label}
            </button>
          ))}
        </div>
      )}

      {/* Compose — client search */}
      {compose && (
        <div className="flex-1 overflow-y-auto">
          {clientResults.map((client) => (
            <button
              key={client.id}
              onClick={() => {
                const existing = threads.find((t) => t.clientId === client.id);
                onSelectThread(
                  existing ? existing.threadId : `new-${client.id}`,
                );
                setCompose(false);
              }}
              className="flex w-full items-center gap-3 px-5 py-2.5 text-left transition-colors hover:bg-slate-50"
            >
              <div
                className={cn(
                  "flex size-10 shrink-0 items-center justify-center rounded-full text-xs font-bold text-white",
                  avatarColor(client.name),
                )}
              >
                {initials(client.name)}
              </div>
              <div className="min-w-0 flex-1">
                <p className="text-sm font-semibold text-slate-800">
                  {client.name}
                </p>
                <p className="truncate text-xs text-slate-400">
                  {client.email}
                </p>
              </div>
            </button>
          ))}
        </div>
      )}

      {/* Thread list */}
      {!compose && (
        <div className="flex-1 overflow-y-auto">
          {filtered.length === 0 ? (
            <div className="flex flex-col items-center py-16 text-center">
              <MessageSquare className="size-10 text-slate-200" />
              <p className="mt-3 text-sm text-slate-400">No conversations</p>
            </div>
          ) : (
            filtered.map((thread) => {
              const sel = selectedThreadId === thread.threadId;
              const failed = thread.lastMessage.status === "failed";
              return (
                <button
                  key={thread.threadId}
                  onClick={() => onSelectThread(thread.threadId)}
                  className={cn(
                    "flex w-full items-center gap-3 px-5 py-3 text-left transition-all",
                    sel ? "bg-slate-100" : "hover:bg-slate-50",
                  )}
                >
                  {/* Avatar */}
                  <div className="relative shrink-0">
                    {thread.clientImage ? (
                      <img
                        src={thread.clientImage}
                        alt=""
                        className="size-12 rounded-full object-cover"
                      />
                    ) : (
                      <div
                        className={cn(
                          "flex size-12 items-center justify-center rounded-full text-sm font-bold text-white",
                          avatarColor(thread.clientName),
                        )}
                      >
                        {initials(thread.clientName)}
                      </div>
                    )}
                    {thread.unreadCount > 0 && (
                      <div className="absolute -right-0.5 -bottom-0.5 size-3.5 rounded-full border-2 border-white bg-emerald-500" />
                    )}
                  </div>

                  {/* Content */}
                  <div className="min-w-0 flex-1">
                    <div className="flex items-center justify-between">
                      <span
                        className={cn(
                          "truncate text-sm",
                          thread.unreadCount > 0
                            ? "font-bold text-slate-900"
                            : "font-medium text-slate-700",
                        )}
                      >
                        {thread.clientName}
                      </span>
                      <span
                        className={cn(
                          "shrink-0 text-[10px]",
                          thread.unreadCount > 0
                            ? "font-semibold text-slate-900"
                            : "text-slate-400",
                        )}
                      >
                        {relTime(thread.lastMessage.timestamp)}
                      </span>
                    </div>
                    <div className="mt-0.5 flex items-center justify-between gap-2">
                      {failed ? (
                        <span className="flex items-center gap-1 text-xs text-red-500">
                          <AlertCircle className="size-3" />
                          Failed
                        </span>
                      ) : (
                        <span
                          className={cn(
                            "truncate text-xs",
                            thread.unreadCount > 0
                              ? "text-slate-600"
                              : "text-slate-400",
                          )}
                        >
                          {thread.lastMessage.direction === "outbound" &&
                            "You: "}
                          {thread.lastMessage.body}
                        </span>
                      )}
                      {thread.unreadCount > 0 && (
                        <span className="flex size-5 shrink-0 items-center justify-center rounded-full bg-emerald-500 text-[10px] font-bold text-white">
                          {thread.unreadCount}
                        </span>
                      )}
                    </div>
                  </div>
                </button>
              );
            })
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { useRef, useEffect, useMemo } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Phone,
  MoreHorizontal,
  MessageSquare,
  PanelRightClose,
  Info,
  Search,
  Star,
} from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";
import { MessageBubble, DateSeparator } from "./MessageBubble";
import { ComposeBar } from "./ComposeBar";
import type { Message } from "@/types/communications";
import { clients } from "@/data/clients";

const COLORS = [
  "bg-rose-500",
  "bg-blue-500",
  "bg-emerald-500",
  "bg-violet-500",
  "bg-amber-500",
  "bg-sky-500",
];

function avatarColor(name: string) {
  return COLORS[name.charCodeAt(0) % COLORS.length];
}

function initials(name: string) {
  return name
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);
}

export function ConversationThread({
  threadId,
  messages,
  detailOpen,
  onToggleDetail,
}: {
  threadId: string | null;
  messages: Message[];
  detailOpen: boolean;
  onToggleDetail: () => void;
}) {
  const scrollRef = useRef<HTMLDivElement>(null);

  const threadMessages = useMemo(() => {
    if (!threadId) return [];
    return messages
      .filter((m) => (m.threadId ?? m.id) === threadId)
      .sort(
        (a, b) =>
          new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime(),
      );
  }, [threadId, messages]);

  const clientId = threadMessages[0]?.clientId;
  const client = clientId ? clients.find((c) => c.id === clientId) : null;
  const clientName = client?.name ?? threadMessages[0]?.from ?? "Unknown";
  const channels = [...new Set(threadMessages.map((m) => m.type))];

  useEffect(() => {
    scrollRef.current?.scrollTo({
      top: scrollRef.current.scrollHeight,
      behavior: "smooth",
    });
  }, [threadMessages.length]);

  // Empty state
  if (!threadId) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center bg-slate-50/30">
        <div className="relative">
          <div className="flex size-24 items-center justify-center rounded-3xl bg-blue-50">
            <MessageSquare className="size-10 text-blue-300" />
          </div>
          <div className="absolute -right-2 -bottom-2 flex size-10 items-center justify-center rounded-2xl bg-emerald-50">
            <Star className="size-5 text-emerald-300" />
          </div>
        </div>
        <h3 className="mt-6 text-xl font-bold text-slate-700">Your Messages</h3>
        <p className="mt-2 max-w-xs text-center text-sm/relaxed text-slate-400">
          Select a client from the left panel or create a new message
        </p>
      </div>
    );
  }

  // Group messages by date
  const grouped: Array<
    { type: "date"; date: string } | { type: "msg"; msg: Message }
  > = [];
  let lastDate = "";
  for (const msg of threadMessages) {
    const date = new Date(msg.timestamp).toLocaleDateString("en-US", {
      weekday: "long",
      month: "long",
      day: "numeric",
    });
    if (date !== lastDate) {
      grouped.push({ type: "date", date });
      lastDate = date;
    }
    grouped.push({ type: "msg", msg });
  }

  const channelLabel =
    channels.length === 1
      ? channels[0] === "sms"
        ? "SMS"
        : channels[0] === "email"
          ? "Email"
          : "Chat"
      : `${channels.length} channels`;

  return (
    <div className="flex flex-1 flex-col">
      {/* Header */}
      <div className="flex items-center justify-between border-b bg-white px-5 py-3">
        <div className="flex items-center gap-3">
          {/* Avatar */}
          {(client as Record<string, unknown>)?.imageUrl ? (
            <img
              src={(client as Record<string, unknown>).imageUrl as string}
              alt=""
              className="size-11 rounded-full object-cover ring-2 ring-slate-100"
            />
          ) : (
            <div
              className={cn(
                "flex size-11 items-center justify-center rounded-full text-sm font-bold text-white shadow-sm",
                avatarColor(clientName),
              )}
            >
              {initials(clientName)}
            </div>
          )}
          <div>
            <div className="flex items-center gap-2">
              <h3 className="text-sm font-bold text-slate-800">{clientName}</h3>
              <Badge
                variant="outline"
                className="border-slate-200 text-[9px] text-slate-400"
              >
                {channelLabel}
              </Badge>
            </div>
            <p className="text-[11px] text-slate-400">
              {client?.phone ?? client?.email ?? "Active now"}
            </p>
          </div>
        </div>

        {/* Actions */}
        <div className="flex items-center gap-1">
          <Button
            variant="ghost"
            size="icon"
            className="size-9 rounded-full text-slate-400 hover:bg-blue-50 hover:text-blue-600"
          >
            <Phone className="size-[18px]" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="size-9 rounded-full text-slate-400 hover:bg-blue-50 hover:text-blue-600"
          >
            <Search className="size-[18px]" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className={cn(
              "size-9 rounded-full",
              detailOpen
                ? "bg-blue-50 text-blue-600"
                : "text-slate-400 hover:bg-blue-50 hover:text-blue-600",
            )}
            onClick={onToggleDetail}
          >
            {detailOpen ? (
              <PanelRightClose className="size-[18px]" />
            ) : (
              <Info className="size-[18px]" />
            )}
          </Button>

          <div className="mx-1 h-5 border-l border-slate-200" />

          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button
                variant="ghost"
                size="icon"
                className="size-9 rounded-full text-slate-400 hover:bg-slate-100"
              >
                <MoreHorizontal className="size-[18px]" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-48">
              <DropdownMenuItem>View client profile</DropdownMenuItem>
              <DropdownMenuItem>Booking history</DropdownMenuItem>
              <DropdownMenuSeparator />
              <DropdownMenuItem>Pin conversation</DropdownMenuItem>
              <DropdownMenuItem>Mark as unread</DropdownMenuItem>
              <DropdownMenuItem className="text-red-500">
                Archive
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>

      {/* Messages area */}
      <div
        ref={scrollRef}
        className="flex-1 overflow-y-auto"
        style={{
          background:
            "linear-gradient(180deg, rgb(248 250 252 / 0.5) 0%, rgb(241 245 249 / 0.3) 100%)",
        }}
      >
        <div className="mx-auto max-w-2xl px-6 py-5">
          {/* Conversation start indicator */}
          <div className="mb-4 flex flex-col items-center py-4 text-center">
            {(client as Record<string, unknown>)?.imageUrl ? (
              <img
                src={(client as Record<string, unknown>).imageUrl as string}
                alt=""
                className="size-16 rounded-full object-cover shadow-md ring-4 ring-white"
              />
            ) : (
              <div
                className={cn(
                  "flex size-16 items-center justify-center rounded-full text-xl font-bold text-white shadow-md ring-4 ring-white",
                  avatarColor(clientName),
                )}
              >
                {initials(clientName)}
              </div>
            )}
            <p className="mt-2 text-sm font-semibold text-slate-700">
              {clientName}
            </p>
            <p className="text-[11px] text-slate-400">
              {client?.email ?? ""} {client?.phone ? `· ${client.phone}` : ""}
            </p>
            <p className="mt-1 text-[10px] text-slate-300">
              Conversation started{" "}
              {threadMessages[0]
                ? new Date(threadMessages[0].timestamp).toLocaleDateString(
                    "en-US",
                    {
                      month: "long",
                      day: "numeric",
                      year: "numeric",
                    },
                  )
                : ""}
            </p>
          </div>

          {/* Messages */}
          <div className="space-y-0.5">
            {grouped.map((item, i) =>
              item.type === "date" ? (
                <DateSeparator key={`d-${i}`} date={item.date} />
              ) : (
                <MessageBubble
                  key={item.msg.id}
                  message={item.msg}
                  clientName={clientName}
                  clientImage={
                    (client as Record<string, unknown>)?.imageUrl as
                      | string
                      | undefined
                  }
                />
              ),
            )}
          </div>
        </div>
      </div>

      {/* Compose */}
      <ComposeBar
        clientName={clientName}
        lastMessage={threadMessages[threadMessages.length - 1]?.body}
      />
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import {
  Check,
  CheckCheck,
  AlertCircle,
  Mail,
  Smartphone,
  MessageSquare,
} from "lucide-react";
import type { Message } from "@/types/communications";

function formatTime(iso: string): string {
  return new Date(iso).toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
  });
}

function StatusIcon({ status }: { status: Message["status"] }) {
  if (status === "sent") return <Check className="size-3 text-white/40" />;
  if (status === "delivered")
    return <CheckCheck className="size-3 text-white/40" />;
  if (status === "read") return <CheckCheck className="size-3 text-sky-200" />;
  if (status === "failed")
    return <AlertCircle className="size-3 text-red-300" />;
  return null;
}

function ChannelIcon({ type }: { type: string }) {
  if (type === "email") return <Mail className="size-2.5 text-slate-300" />;
  if (type === "sms") return <Smartphone className="size-2.5 text-slate-300" />;
  return <MessageSquare className="size-2.5 text-slate-300" />;
}

const AVATAR_COLORS = [
  "bg-rose-500",
  "bg-blue-500",
  "bg-emerald-500",
  "bg-violet-500",
  "bg-amber-500",
  "bg-sky-500",
];

export function MessageBubble({
  message,
  clientName,
  clientImage,
  showAvatar = true,
}: {
  message: Message;
  clientName?: string;
  clientImage?: string;
  showAvatar?: boolean;
}) {
  const out = message.direction === "outbound";
  const failed = message.status === "failed";
  const color =
    AVATAR_COLORS[(clientName?.charCodeAt(0) ?? 0) % AVATAR_COLORS.length];

  return (
    <div
      className={cn(
        "group flex gap-2 py-[3px]",
        out ? "flex-row-reverse" : "flex-row",
      )}
    >
      {/* Avatar — only for inbound */}
      {!out && showAvatar ? (
        clientImage ? (
          <img
            src={clientImage}
            alt=""
            className="mt-auto size-8 shrink-0 rounded-full object-cover shadow-sm"
          />
        ) : (
          <div
            className={cn(
              "mt-auto flex size-8 shrink-0 items-center justify-center rounded-full text-[11px] font-bold text-white shadow-sm",
              color,
            )}
          >
            {clientName?.charAt(0).toUpperCase() ?? "?"}
          </div>
        )
      ) : !out ? (
        <div className="w-8 shrink-0" />
      ) : null}

      <div className={cn("max-w-[60%]")}>
        {/* Bubble */}
        <div
          className={cn(
            "relative px-4 py-2.5",
            out
              ? "rounded-[20px] rounded-br-[6px] bg-blue-500 text-white shadow-sm"
              : "rounded-[20px] rounded-bl-[6px] border border-slate-100 bg-white text-slate-800 shadow-sm",
            failed && "ring-2 ring-red-400/40",
          )}
        >
          {/* Email subject line */}
          {message.subject && (
            <p
              className={cn(
                "mb-1 text-[11px] font-semibold",
                out ? "text-white/80" : "text-slate-500",
              )}
            >
              {message.subject}
            </p>
          )}

          <p className="text-[13.5px] leading-[1.55] whitespace-pre-wrap">
            {message.body}
          </p>

          {/* Time + status row inside bubble */}
          <div
            className={cn(
              "mt-1.5 flex items-center gap-1.5",
              out ? "justify-end" : "justify-start",
            )}
          >
            {!out && <ChannelIcon type={message.type} />}
            <span
              className={cn(
                "text-[10px]",
                out ? "text-white/50" : "text-slate-400",
              )}
            >
              {formatTime(message.timestamp)}
            </span>
            {out && <StatusIcon status={message.status} />}
          </div>
        </div>

        {/* Failed retry */}
        {failed && (
          <p
            className={cn(
              "mt-1 text-[10px] text-red-500",
              out ? "text-right" : "text-left",
            )}
          >
            Not delivered ·{" "}
            <button type="button" className="font-semibold underline">
              Retry
            </button>
          </p>
        )}
      </div>
    </div>
  );
}

export function DateSeparator({ date }: { date: string }) {
  return (
    <div className="flex items-center gap-4 py-4">
      <div className="h-px flex-1 bg-slate-200/70" />
      <span className="text-[11px] font-medium text-slate-400">{date}</span>
      <div className="h-px flex-1 bg-slate-200/70" />
    </div>
  );
}

export function SystemMessage({ text }: { text: string }) {
  return (
    <div className="flex justify-center py-2">
      <span className="rounded-full bg-slate-100 px-4 py-1.5 text-[11px] text-slate-400">
        {text}
      </span>
    </div>
  );
}

