  onSign,
  onClear,
  agreementText,
  label = "Signature",
  witnessMode = false,
  disabled = false,
  initialSignature,
  readOnly = false,
  compact = false,
  className,
}: SignaturePadProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const padRef = useRef<SignaturePadLib | null>(null);
  const [isEmpty, setIsEmpty] = useState(true);
  const [agreed, setAgreed] = useState(!agreementText);
  const [witnessName, setWitnessName] = useState("");
  const [mode, setMode] = useState<"draw" | "type">("draw");
  const [typedName, setTypedName] = useState("");
  const [signing, setSigning] = useState(false);
  const [signedMeta, setSignedMeta] = useState<{
    date: string;
    ip: string;
  } | null>(null);

  // Initialize signature pad
  useEffect(() => {
    if (!canvasRef.current || readOnly) return;
    const canvas = canvasRef.current;
    const ratio = Math.max(window.devicePixelRatio || 1, 1);
    canvas.width = canvas.offsetWidth * ratio;
    canvas.height = canvas.offsetHeight * ratio;
    const ctx = canvas.getContext("2d");
    if (ctx) ctx.scale(ratio, ratio);

    const pad = new SignaturePadLib(canvas, {
      penColor: "#1e293b",
      minWidth: 1.5,
      maxWidth: 3,
    });

    pad.addEventListener("beginStroke", () => setIsEmpty(false));

    if (disabled || !agreed) {
      pad.off();
    }

    padRef.current = pad;

    return () => {
      pad.off();
    };
  }, [readOnly, disabled, agreed]);

  // Enable/disable based on agreement
  useEffect(() => {
    if (!padRef.current) return;
    if (agreed && !disabled) {
      padRef.current.on();
    } else {
      padRef.current.off();
    }
  }, [agreed, disabled]);

  const handleClear = useCallback(() => {
    padRef.current?.clear();
    setIsEmpty(true);
    setTypedName("");
    onClear?.();
  }, [onClear]);

  const handleConfirm = useCallback(async () => {
    setSigning(true);

    let signatureData: string;

    if (mode === "type" && typedName.trim()) {
      // Render typed name to canvas
      const tempCanvas = document.createElement("canvas");
      tempCanvas.width = 600;
      tempCanvas.height = 150;
      const ctx = tempCanvas.getContext("2d");
      if (ctx) {
        ctx.fillStyle = "white";
        ctx.fillRect(0, 0, 600, 150);
        ctx.fillStyle = "#1e293b";
        ctx.font = "italic 48px Georgia, serif";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.fillText(typedName.trim(), 300, 75);
      }
      signatureData = tempCanvas.toDataURL("image/png");
    } else if (padRef.current && !padRef.current.isEmpty()) {
      signatureData = padRef.current.toDataURL("image/png");
    } else {
      setSigning(false);
      return;
    }

    const ip = await getIpAddress();
    const result: SignatureResult = {
      signatureData,
      signedAt: new Date().toISOString(),
      ipAddress: ip,
      userAgent: navigator.userAgent,
      deviceId: generateDeviceId(),
      timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
      agreementText: agreementText ?? undefined,
      witnessName: witnessMode ? witnessName : undefined,
    };

    setSignedMeta({ date: result.signedAt, ip });
    setSigning(false);
    onSign(result);
  }, [mode, typedName, agreementText, witnessMode, witnessName, onSign]);

  const canConfirm =
    agreed &&
    !disabled &&
    ((mode === "draw" && !isEmpty) ||
      (mode === "type" && typedName.trim().length > 1));

  // ── Read-only view ─────────────────────────────────────────────────

  if (readOnly && initialSignature) {
    return (
      <div className={cn("space-y-2", className)}>
        <Label className="text-xs font-semibold tracking-wider text-slate-400 uppercase">
          {label}
        </Label>
        <div className="rounded-xl border-2 border-slate-200 bg-white p-3">
          <img
            src={initialSignature}
            alt="Signature"
            className={cn("w-full object-contain", compact ? "h-20" : "h-32")}
          />
        </div>
        {signedMeta && (
          <p className="text-[11px] text-slate-400">
            Signed on{" "}
            {new Date(signedMeta.date).toLocaleDateString("en-US", {
              month: "short",
              day: "numeric",
              year: "numeric",
              hour: "numeric",
              minute: "2-digit",
            })}
            {signedMeta.ip !== "unavailable" && ` · IP: ${signedMeta.ip}`}
          </p>
        )}
        <Button
          variant="outline"
          size="sm"
          className="gap-1.5"
          onClick={() => {
            const link = document.createElement("a");
            link.download = "signature.png";
            link.href = initialSignature;
            link.click();
          }}
        >
          <Download className="size-3.5" />
          Download
        </Button>
      </div>
    );
  }

  // ── Interactive view ───────────────────────────────────────────────

  return (
    <div className={cn("space-y-3", className)}>
      {/* Agreement text */}
      {agreementText && (
        <div className="space-y-2">
          <ScrollArea className="max-h-[200px] rounded-lg border bg-slate-50/50 p-4">
            <div className="prose prose-sm max-w-none text-sm/relaxed text-slate-600">
              {agreementText}
            </div>
          </ScrollArea>
          <label className="flex items-center gap-2">
            <Checkbox
              checked={agreed}
              onCheckedChange={(c) => setAgreed(c === true)}
            />
            <span className="text-xs font-medium text-slate-600">
              I have read and agree to the terms above
            </span>
          </label>
        </div>
      )}

      {/* Mode tabs */}
      <div className="flex items-center gap-1 rounded-lg bg-slate-100 p-0.5">
        <button
          type="button"
          onClick={() => setMode("draw")}
          className={cn(
            "flex flex-1 items-center justify-center gap-1.5 rounded-md py-1.5 text-xs font-semibold transition-all",
            mode === "draw"
              ? "bg-white text-slate-800 shadow-sm"
              : "text-slate-400 hover:text-slate-600",
          )}
        >
          <Pen className="size-3.5" />
          Draw
        </button>
        <button
          type="button"
          onClick={() => setMode("type")}
          className={cn(
            "flex flex-1 items-center justify-center gap-1.5 rounded-md py-1.5 text-xs font-semibold transition-all",
            mode === "type"
              ? "bg-white text-slate-800 shadow-sm"
              : "text-slate-400 hover:text-slate-600",
          )}
        >
          <Type className="size-3.5" />
          Type
        </button>
      </div>

      {/* Canvas / Type input */}
      {mode === "draw" ? (
        <div
          className={cn(
            "relative overflow-hidden rounded-xl border-2 border-dashed border-slate-200 bg-white",
            !agreed && "opacity-50",
            compact ? "h-28" : "h-40",
          )}
        >
          <canvas
            ref={canvasRef}
            className="absolute inset-0 size-full"
            style={{ touchAction: "none" }}
          />
          {isEmpty && (
            <div className="pointer-events-none absolute inset-0 flex flex-col items-center justify-center gap-1">
              <Pen className="size-5 text-slate-300" />
              <span className="text-sm text-slate-300">Sign here</span>
            </div>
          )}
        </div>
      ) : (
        <div className="space-y-2">
          <Input
            value={typedName}
            onChange={(e) => setTypedName(e.target.value)}
            placeholder="Type your full name"
            disabled={!agreed}
            className="text-center"
          />
          <div
            className={cn(
              "flex items-center justify-center rounded-xl border-2 border-slate-200 bg-white",
              compact ? "h-28" : "h-40",
            )}
          >
            {typedName.trim() ? (
              <span
                className="text-3xl text-slate-700"
                style={{ fontFamily: "Georgia, serif", fontStyle: "italic" }}
              >
                {typedName}
              </span>
            ) : (
              <span className="text-sm text-slate-300">
                Your signature will appear here
              </span>
            )}
          </div>
        </div>
      )}

      {/* Controls */}
      <div className="flex items-center justify-between">
        <span className="text-xs font-medium tracking-wider text-slate-400 uppercase">
          {label}
        </span>
        {mode === "draw" && (
          <Button
            variant="ghost"
            size="sm"
            className="h-7 gap-1.5 text-xs text-slate-400"
            onClick={handleClear}
          >
            <Eraser className="size-3.5" />
            Clear
          </Button>
        )}
      </div>

      {/* Witness */}
      {witnessMode && (
        <div className="space-y-1.5">
          <Label className="text-xs">Witness Name</Label>
          <Input
            value={witnessName}
            onChange={(e) => setWitnessName(e.target.value)}
            placeholder="Full name of witness"
          />
        </div>
      )}

      {/* Confirm */}
      <Button
        className="w-full gap-1.5"
        disabled={!canConfirm || signing}
        onClick={handleConfirm}
      >
        {signing ? (
          "Capturing signature..."
        ) : (
          <>
            <Check className="size-4" />
            Confirm Signature
          </>
        )}
      </Button>

      {/* Legal text */}
      <p className="text-[10px] leading-relaxed text-slate-400">
        By signing above, you acknowledge that this electronic signature has the
        same legal validity as a handwritten signature. Your signature,
        timestamp, IP address, and device information are recorded for
        verification purposes.
      </p>
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Phone,
  Video,
  MoreVertical,
  Send,
  Smile,
  Paperclip,
  ArrowLeft,
  Search,
  MessageSquare,
} from "lucide-react";
import { ChatConversation } from "@/data/chats";
import { cn } from "@/lib/utils";
import { VariableInsertDropdown } from "@/components/shared/VariableInsertDropdown";
import { useInsertAtCursor } from "@/hooks/use-insert-at-cursor";

interface ChatPanelProps {
  conversations: ChatConversation[];
  selectedChat: ChatConversation | null;
  onSelectChat: (chat: ChatConversation | null) => void;
  onSendMessage: (message: string) => void;
}

export function ChatPanel({
  conversations,
  selectedChat,
  onSelectChat,
  onSendMessage,
}: ChatPanelProps) {
  const [newMessage, setNewMessage] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const chatInputRef = useRef<HTMLInputElement>(null);
  const insertVariable = useInsertAtCursor(
    chatInputRef,
    newMessage,
    setNewMessage,
  );

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [selectedChat?.messages]);

  const handleSend = () => {
    if (newMessage.trim()) {
      onSendMessage(newMessage);
      setNewMessage("");
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const getInitials = (name: string) => {
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .toUpperCase()
      .slice(0, 2);
  };

  const getParticipantName = (chat: ChatConversation) => {
    const participant = chat.participants.find(
      (p) => !p.includes("Support") && !p.includes("Agent"),
    );
    return participant?.replace(/\s*\(.*?\)\s*/g, "") || "Unknown";
  };

  const filteredConversations = conversations.filter((chat) => {
    const participantName = getParticipantName(chat).toLowerCase();
    const facility = (chat.facility || "").toLowerCase();
    const query = searchQuery.toLowerCase();
    return participantName.includes(query) || facility.includes(query);
  });

  // List view when no chat is selected
  if (!selectedChat) {
    return (
      <Card className="flex h-full flex-col rounded-none border-t-0 border-r-0 border-b-0 border-l shadow-none">
        {/* Header */}
        <CardHeader className="border-b px-4 py-4">
          <div className="mb-3 flex items-center gap-2">
            <div className="bg-primary/10 flex size-8 items-center justify-center rounded-lg">
              <MessageSquare className="text-primary size-4" />
            </div>
            <CardTitle className="text-lg">Live Chat Support</CardTitle>
          </div>
          <div className="relative">
            <Search className="text-muted-foreground absolute top-1/2 left-3 size-4 -translate-y-1/2" />
            <Input
              placeholder="Search conversations..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="bg-muted/50 border-0 pl-9 focus-visible:ring-1"
            />
          </div>
        </CardHeader>

        {/* Conversations List */}
        <CardContent className="flex-1 overflow-hidden p-0">
          <ScrollArea className="h-full">
            <div className="p-2">
              {filteredConversations.length === 0 ? (
                <div className="text-muted-foreground py-8 text-center">
                  <MessageSquare className="mx-auto mb-2 size-10 opacity-50" />
                  <p className="text-sm">No conversations found</p>
                </div>
              ) : (
                filteredConversations.map((chat) => {
                  const participantName = getParticipantName(chat);
                  const lastMessage = chat.messages[chat.messages.length - 1];
                  const isActive = chat.status === "Active";

                  return (
                    <button
                      key={chat.id}
                      onClick={() => onSelectChat(chat)}
                      className="group hover:bg-muted/50 mb-1 flex w-full items-start gap-3 rounded-xl p-3 text-left transition-all"
                    >
                      <div className="relative">
                        <Avatar className="border-background size-10 border-2 shadow-sm">
                          <AvatarImage src="" />
                          <AvatarFallback className="bg-gradient-primary text-primary-foreground text-sm font-medium">
                            {getInitials(participantName)}
                          </AvatarFallback>
                        </Avatar>
                        {isActive && (
                          <span className="status-online border-background bg-success absolute -right-0.5 -bottom-0.5 size-3 rounded-full border-2" />
                        )}
                      </div>
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center justify-between gap-2">
                          <span className="text-foreground truncate text-sm font-medium">
                            {participantName}
                          </span>
                          <span className="text-muted-foreground text-xs whitespace-nowrap">
                            {new Date(chat.updatedAt).toLocaleTimeString([], {
                              hour: "2-digit",
                              minute: "2-digit",
                            })}
                          </span>
                        </div>
                        <p className="text-muted-foreground mt-0.5 truncate text-xs">
                          {chat.facility}
                        </p>
                        <p className="text-muted-foreground group-hover:text-foreground/70 mt-1 truncate text-sm transition-colors">
                          {lastMessage?.message || "No messages yet"}
                        </p>
                      </div>
                      {isActive && (
                        <Badge className="bg-success/10 text-success hover:bg-success/20 shrink-0 border-0 text-xs">
                          Active
                        </Badge>
                      )}
                    </button>
                  );
                })
              )}
            </div>
          </ScrollArea>
        </CardContent>
      </Card>
    );
  }

  // Chat detail view
  const participantName = getParticipantName(selectedChat);
  const isActive = selectedChat.status === "Active";

  return (
    <Card className="flex h-full flex-col rounded-none border-t-0 border-r-0 border-b-0 border-l shadow-none">
      {/* Chat Header */}
      <CardHeader className="border-b px-4 py-4">
        <div className="flex items-center gap-3">
          <Button
            variant="ghost"
            size="icon"
            className="hover:bg-muted size-8 shrink-0"
            onClick={() => onSelectChat(null)}
          >
            <ArrowLeft className="size-4" />
          </Button>
          <div className="relative">
            <Avatar className="border-background h-11 w-11 border-2 shadow-sm">
              <AvatarImage src="" />
              <AvatarFallback className="bg-gradient-primary text-primary-foreground font-medium">
                {getInitials(participantName)}
              </AvatarFallback>
            </Avatar>
            {isActive && (
              <span className="status-online border-background bg-success absolute -right-0.5 -bottom-0.5 size-3.5 rounded-full border-2" />
            )}
          </div>
          <div className="min-w-0 flex-1">
            <h3 className="text-foreground truncate font-semibold">
              {participantName}
            </h3>
            <p className="text-muted-foreground truncate text-sm">
              {selectedChat.facility}
            </p>
          </div>
        </div>

        {/* Action buttons */}
        <div className="mt-4 flex items-center justify-center gap-2">
          <Button
            variant="outline"
            size="icon"
            className="hover:border-primary/50 hover:bg-primary/10 hover:text-primary size-9 rounded-full transition-colors"
          >
            <Phone className="size-4" />
          </Button>
          <Button
            variant="outline"
            size="icon"
            className="hover:border-primary/50 hover:bg-primary/10 hover:text-primary size-9 rounded-full transition-colors"
          >
            <Video className="size-4" />
          </Button>
          <Button
            variant="outline"
            size="icon"
            className="hover:bg-muted size-9 rounded-full transition-colors"
          >
            <MoreVertical className="size-4" />
          </Button>
        </div>
      </CardHeader>

      {/* Activity Label */}
      <div className="bg-muted/30 border-b px-4 py-2">
        <p className="text-muted-foreground text-center text-xs font-medium tracking-wider uppercase">
          Activity
        </p>
      </div>

      {/* Messages */}
      <CardContent className="flex-1 overflow-hidden p-0">
        <ScrollArea className="h-full">
          <div className="space-y-4 p-4">
            {selectedChat.messages.map((msg) => {
              const isSupport =
                msg.sender.includes("Support") || msg.sender.includes("Agent");
              const senderName = msg.sender.replace(/\s*\(.*?\)\s*/g, "");

              return (
                <div
                  key={msg.id}
                  className={cn(
                    "animate-fade-in flex gap-3",
                    isSupport ? "flex-row-reverse" : "flex-row",
                  )}
                >
                  {!isSupport && (
                    <Avatar className="border-border size-8 shrink-0 border shadow-sm">
                      <AvatarImage src="" />
                      <AvatarFallback className="bg-muted text-muted-foreground text-xs">
                        {getInitials(senderName)}
                      </AvatarFallback>
                    </Avatar>
                  )}
                  <div
                    className={cn(
                      "flex max-w-[80%] flex-col",
                      isSupport ? "items-end" : "items-start",
                    )}
                  >
                    {!isSupport && (
                      <div className="mb-1 flex items-center gap-2">
                        <span className="text-foreground text-xs font-medium">
                          {senderName}
                        </span>
                        <span className="text-muted-foreground text-xs">
                          {new Date(msg.timestamp).toLocaleTimeString([], {
                            hour: "2-digit",
                            minute: "2-digit",
                          })}
                        </span>
                      </div>
                    )}
                    <div
                      className={cn(
                        "rounded-2xl px-4 py-2.5 text-sm shadow-sm",
                        isSupport
                          ? "bg-primary text-primary-foreground rounded-br-md"
                          : `border-border/50 bg-muted text-foreground rounded-bl-md border`,
                      )}
                    >
                      {msg.message}
                    </div>
                    {isSupport && (
                      <span className="text-muted-foreground mt-1 text-xs">
                        {new Date(msg.timestamp).toLocaleTimeString([], {
                          hour: "2-digit",
                          minute: "2-digit",
                        })}
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
            <div ref={messagesEndRef} />
          </div>
        </ScrollArea>
      </CardContent>

      {/* Message Input */}
      <div className="bg-card border-t p-4">
        <div className="flex items-center gap-2">
          <Button
            variant="ghost"
            size="icon"
            className="text-muted-foreground hover:bg-muted hover:text-foreground size-9 shrink-0"
          >
            <Paperclip className="size-4" />
          </Button>
          <div className="relative flex-1">
            <Input
              ref={chatInputRef}
              placeholder="Write a message..."
              value={newMessage}
              onChange={(e) => setNewMessage(e.target.value)}
              onKeyDown={handleKeyPress}
              className="bg-muted/50 focus-visible:ring-primary border-0 pr-10 focus-visible:ring-1"
            />
          </div>
          <VariableInsertDropdown context="general" onInsert={insertVariable} />
          <Button
            variant="ghost"
            size="icon"
            className="text-muted-foreground hover:bg-muted hover:text-foreground size-9 shrink-0"
          >
            <Smile className="size-4" />
          </Button>
          <Button
            size="icon"
            className="bg-primary hover:bg-primary/90 size-9 shrink-0 shadow-sm"
            onClick={handleSend}
            disabled={!newMessage.trim()}
          >
            <Send className="size-4" />
          </Button>
        </div>
      </div>
    </Card>
  );
}

import { Card, CardContent } from "@/components/ui/card";
import { LucideIcon, TrendingUp, TrendingDown } from "lucide-react";
import { cn } from "@/lib/utils";

interface StatCardProps {
  title: string;
  value: string | number;
  subtitle?: string;
  change?: string;
  changeType?: "up" | "down" | "neutral";
  icon: LucideIcon;
  variant?:
    | "default"
    | "primary"
    | "success"
    | "warning"
    | "info"
    | "secondary";
}

const variantStyles = {
  default: {
    iconBg: "bg-muted",
    iconColor: "text-muted-foreground",
  },
  primary: {
    iconBg: "bg-gradient-to-br from-primary to-primary/80",
    iconColor: "text-primary-foreground",
  },
  success: {
    iconBg: "bg-gradient-to-br from-success to-success/80",
    iconColor: "text-success-foreground",
  },
  warning: {
    iconBg: "bg-gradient-to-br from-warning to-warning/80",
    iconColor: "text-warning-foreground",
  },
  info: {
    iconBg: "bg-gradient-to-br from-info to-info/80",
    iconColor: "text-info-foreground",
  },
  secondary: {
    iconBg: "bg-gradient-to-br from-secondary to-secondary/80",
    iconColor: "text-secondary-foreground",
  },
};

export function StatCard({
  title,
  value,
  subtitle,
  change,
  changeType = "neutral",
  icon: Icon,
  variant = "primary",
}: StatCardProps) {
  const styles = variantStyles[variant];

  return (
    <Card className="hover:shadow-elevated group shadow-card relative overflow-hidden border-0 transition-all duration-300">
      <CardContent className="p-5">
        <div className="flex items-start justify-between">
          <div className="flex-1 space-y-1">
            <p className="text-muted-foreground text-sm font-medium">{title}</p>
            <div className="flex items-baseline gap-2">
              <h3 className="text-2xl font-bold tracking-tight">{value}</h3>
              {change && (
                <span
                  className={cn(
                    "inline-flex items-center text-xs font-medium",
                    changeType === "up" && "text-success",
                    changeType === "down" && "text-destructive",
                    changeType === "neutral" && "text-muted-foreground",
                  )}
                >
                  {changeType === "up" && (
                    <TrendingUp className="mr-0.5 size-3" />
                  )}
                  {changeType === "down" && (
                    <TrendingDown className="mr-0.5 size-3" />
                  )}
                  {change}
                </span>
              )}
            </div>
            {subtitle && (
              <p className="text-muted-foreground text-xs">{subtitle}</p>
            )}
          </div>
          <div
            className={cn(
              `flex h-11 w-11 items-center justify-center rounded-xl shadow-sm transition-transform duration-300 group-hover:scale-110`,
              styles.iconBg,
            )}
          >
            <Icon className={cn("size-5", styles.iconColor)} />
          </div>
        </div>
      </CardContent>

      {/* Decorative gradient overlay */}
      <div
        className="pointer-events-none absolute top-0 right-0 size-24 opacity-5"
        style={{
          background: `radial-gradient(circle at top right, currentColor 0%, transparent 70%)`,
        }}
      />
    </Card>
  );
}

